import pg from 'pg';
const { Pool } = pg;

const shadowConfig = {
  host: process.env.SHADOW_HOST,
  user: 'postgres',
  password: process.env.SHADOW_PASS,
  database: 'ship_main',
  port: 5432,
  ssl: { rejectUnauthorized: false }
};

const devConfig = {
  host: process.env.DEV_HOST,
  user: 'postgres',
  password: process.env.DEV_PASS,
  database: 'ship_main',
  port: 5432,
  ssl: { rejectUnauthorized: false }
};

async function checkUser(config: pg.PoolConfig, name: string) {
  const pool = new Pool(config);
  try {
    console.log(`\n=== ${name} DB ===`);
    console.log('Host:', config.host);

    // Check users table (used by login)
    const result = await pool.query(
      'SELECT id, email, password_hash, name FROM users WHERE LOWER(email) = LOWER($1)',
      ['shawn.jones@treasury.gov']
    );

    if (result.rows.length === 0) {
      console.log('USER NOT FOUND in users table!');
    } else {
      const user = result.rows[0];
      console.log('User found in users table:');
      console.log('  ID:', user.id);
      console.log('  Email:', user.email);
      console.log('  Name:', user.name);
      console.log('  Hash:', user.password_hash);
    }

    const countResult = await pool.query('SELECT COUNT(*) FROM users');
    console.log('Total users:', countResult.rows[0].count);

    // List all users
    const allUsers = await pool.query('SELECT id, email FROM users LIMIT 5');
    console.log('Sample users:', allUsers.rows.map(u => u.email).join(', '));

  } catch (err: any) {
    console.error('Error:', err.message);
  } finally {
    await pool.end();
  }
}

async function main() {
  await checkUser(shadowConfig, 'Shadow');
  await checkUser(devConfig, 'Dev');
}

main();

/**
 * Shadow Database Migration Script
 *
 * Runs migrations on the shadow database without SSM loading.
 * Designed to work with port-forwarded connections.
 *
 * Usage:
 *   DATABASE_URL="..." npx tsx api/scripts/migrate-shadow.ts
 */

import { readdirSync, readFileSync } from 'fs';
import { dirname, join } from 'path';
import { fileURLToPath } from 'url';
import pg from 'pg';
const { Pool } = pg;

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

async function migrate() {
  const databaseUrl = process.env.DATABASE_URL;
  if (!databaseUrl) {
    console.error('ERROR: DATABASE_URL environment variable is required');
    process.exit(1);
  }

  console.log('Connecting to shadow database...');
  console.log('Host from URL:', databaseUrl.split('@')[1]?.split(':')[0]);

  const pool = new Pool({
    connectionString: databaseUrl,
    ssl: { rejectUnauthorized: false },
  });

  try {
    console.log('Running database migrations...');

    // Step 1: Run schema.sql for initial setup
    const schemaPath = join(__dirname, '../src/db/schema.sql');
    const schema = readFileSync(schemaPath, 'utf-8');

    try {
      await pool.query(schema);
      console.log('✅ Schema applied');
    } catch (err: any) {
      if (err.message?.includes('already exists')) {
        console.log('ℹ️  Schema already exists, continuing...');
      } else {
        throw err;
      }
    }

    // Step 2: Create migrations tracking table
    await pool.query(`
      CREATE TABLE IF NOT EXISTS schema_migrations (
        version TEXT PRIMARY KEY,
        applied_at TIMESTAMPTZ DEFAULT now()
      )
    `);

    // Step 3: Get list of already-applied migrations
    const appliedResult = await pool.query('SELECT version FROM schema_migrations ORDER BY version');
    const appliedMigrations = new Set(appliedResult.rows.map(r => r.version));

    console.log(`Already applied: ${appliedMigrations.size} migrations`);

    // Step 4: Find and run pending migrations
    const migrationsDir = join(__dirname, '../src/db/migrations');
    let migrationFiles: string[] = [];

    try {
      migrationFiles = readdirSync(migrationsDir)
        .filter(f => f.endsWith('.sql'))
        .sort();
    } catch {
      console.log('ℹ️  No migrations directory found');
    }

    console.log(`Found ${migrationFiles.length} migration files`);

    let migrationsRun = 0;
    for (const file of migrationFiles) {
      const version = file.replace('.sql', '');

      if (appliedMigrations.has(version)) {
        continue;
      }

      console.log(`  Running migration: ${file}`);
      const migrationPath = join(migrationsDir, file);
      const migrationSql = readFileSync(migrationPath, 'utf-8');

      const client = await pool.connect();
      try {
        await client.query('BEGIN');
        await client.query(migrationSql);
        await client.query('INSERT INTO schema_migrations (version) VALUES ($1)', [version]);
        await client.query('COMMIT');
        console.log(`  ✅ ${file} applied`);
        migrationsRun++;
      } catch (err) {
        await client.query('ROLLBACK');
        console.error(`  ❌ ${file} failed:`, err);
        throw err;
      } finally {
        client.release();
      }
    }

    if (migrationsRun === 0) {
      console.log('✅ All migrations already applied');
    } else {
      console.log(`✅ ${migrationsRun} migration(s) applied successfully`);
    }

    // Verify test user
    const userResult = await pool.query(
      `SELECT id, email, name,
              CASE WHEN password_hash IS NOT NULL THEN 'SET' ELSE 'NULL' END as password_status
       FROM users WHERE LOWER(email) = LOWER('shawn.jones@treasury.gov')`
    );

    if (userResult.rows.length > 0) {
      console.log('\n✅ Test user verified:', userResult.rows[0]);
    } else {
      console.log('\n⚠️  Test user not found');
    }

  } catch (error) {
    console.error('Database migration failed:', error);
    process.exit(1);
  } finally {
    await pool.end();
  }
}

migrate();

import { describe, it, expect, beforeEach, vi } from 'vitest';
import request from 'supertest';
import express from 'express';

// Mock pool before importing routes
vi.mock('../db/client.js', () => ({
  pool: {
    query: vi.fn(),
  },
}));

// Mock auth middleware to inject test session data
vi.mock('../middleware/auth.js', () => ({
  authMiddleware: (req: any, res: any, next: any) => {
    req.workspaceId = 'test-workspace-id';
    req.userId = 'test-user-id';
    next();
  },
}));

import activityRouter from '../routes/activity.js';
import { pool } from '../db/client.js';

// Create test Express app
function createTestApp() {
  const app = express();
  app.use(express.json());
  app.use('/activity', activityRouter);
  return app;
}

describe('Activity API', () => {
  let app: express.Application;

  beforeEach(() => {
    vi.clearAllMocks();
    app = createTestApp();
  });

  describe('GET /activity/:entityType/:entityId', () => {
    describe('successful activity retrieval', () => {
      it('returns 30 days of activity for a program', async () => {
        const programId = 'program-123';
        const workspaceId = 'test-workspace-id';

        // Mock entity exists check
        vi.mocked(pool.query)
          .mockResolvedValueOnce({
            rows: [{ id: programId }],
            rowCount: 1,
          } as any)
          // Mock activity query
          .mockResolvedValueOnce({
            rows: [
              { date: '2024-01-01', count: 5 },
              { date: '2024-01-02', count: 3 },
              { date: '2024-01-03', count: 0 },
            ],
          } as any);

        const response = await request(app)
          .get(`/activity/program/${programId}`)
          .expect(200);

        expect(response.body).toEqual({
          days: [
            { date: '2024-01-01', count: 5 },
            { date: '2024-01-02', count: 3 },
            { date: '2024-01-03', count: 0 },
          ],
        });

        // Verify entity check query
        expect(pool.query).toHaveBeenCalledWith(
          expect.stringContaining('SELECT id FROM documents'),
          [programId, workspaceId, 'program']
        );
      });

      it('returns 30 days of activity for a project', async () => {
        const projectId = 'project-456';
        const workspaceId = 'test-workspace-id';

        vi.mocked(pool.query)
          .mockResolvedValueOnce({
            rows: [{ id: projectId }],
            rowCount: 1,
          } as any)
          .mockResolvedValueOnce({
            rows: [
              { date: '2024-01-10', count: 12 },
              { date: '2024-01-11', count: 8 },
            ],
          } as any);

        const response = await request(app)
          .get(`/activity/project/${projectId}`)
          .expect(200);

        expect(response.body).toEqual({
          days: [
            { date: '2024-01-10', count: 12 },
            { date: '2024-01-11', count: 8 },
          ],
        });

        expect(pool.query).toHaveBeenCalledWith(
          expect.stringContaining('SELECT id FROM documents'),
          [projectId, workspaceId, 'project']
        );
      });

      it('returns 30 days of activity for a sprint', async () => {
        const sprintId = 'sprint-789';
        const workspaceId = 'test-workspace-id';

        vi.mocked(pool.query)
          .mockResolvedValueOnce({
            rows: [{ id: sprintId }],
            rowCount: 1,
          } as any)
          .mockResolvedValueOnce({
            rows: [
              { date: '2024-01-20', count: 15 },
            ],
          } as any);

        const response = await request(app)
          .get(`/activity/sprint/${sprintId}`)
          .expect(200);

        expect(response.body).toEqual({
          days: [
            { date: '2024-01-20', count: 15 },
          ],
        });

        expect(pool.query).toHaveBeenCalledWith(
          expect.stringContaining('SELECT id FROM documents'),
          [sprintId, workspaceId, 'sprint']
        );
      });

      it('returns empty array for entity with no activity', async () => {
        const programId = 'empty-program';

        vi.mocked(pool.query)
          .mockResolvedValueOnce({
            rows: [{ id: programId }],
            rowCount: 1,
          } as any)
          .mockResolvedValueOnce({
            rows: [],
          } as any);

        const response = await request(app)
          .get(`/activity/program/${programId}`)
          .expect(200);

        expect(response.body).toEqual({
          days: [],
        });
      });
    });

    describe('error handling', () => {
      it('returns 400 for invalid entity type', async () => {
        const response = await request(app)
          .get('/activity/invalid-type/some-id')
          .expect(400);

        expect(response.body).toEqual({
          error: 'Invalid entity type. Must be program, project, or week.',
        });

        // Should not query database for invalid type
        expect(pool.query).not.toHaveBeenCalled();
      });

      it('returns 404 when entity does not exist', async () => {
        const nonExistentId = 'non-existent-id';

        vi.mocked(pool.query).mockResolvedValueOnce({
          rows: [],
          rowCount: 0,
        } as any);

        const response = await request(app)
          .get(`/activity/program/${nonExistentId}`)
          .expect(404);

        expect(response.body).toEqual({
          error: 'Entity not found',
        });
      });

      it('returns 404 when entity belongs to different workspace', async () => {
        const programId = 'other-workspace-program';

        // Entity exists but not in user's workspace
        vi.mocked(pool.query).mockResolvedValueOnce({
          rows: [],
          rowCount: 0,
        } as any);

        const response = await request(app)
          .get(`/activity/program/${programId}`)
          .expect(404);

        expect(response.body).toEqual({
          error: 'Entity not found',
        });
      });

      it('returns 500 on database error', async () => {
        const programId = 'program-error';

        vi.mocked(pool.query).mockRejectedValueOnce(
          new Error('Database connection failed')
        );

        const response = await request(app)
          .get(`/activity/program/${programId}`)
          .expect(500);

        expect(response.body).toEqual({
          error: 'Failed to fetch activity data',
        });
      });
    });

    describe('workspace isolation', () => {
      it('only queries entities in the authenticated workspace', async () => {
        const programId = 'program-123';
        const workspaceId = 'test-workspace-id';

        vi.mocked(pool.query)
          .mockResolvedValueOnce({
            rows: [{ id: programId }],
            rowCount: 1,
          } as any)
          .mockResolvedValueOnce({
            rows: [],
          } as any);

        await request(app)
          .get(`/activity/program/${programId}`)
          .expect(200);

        // Verify workspace_id is included in entity check
        expect(pool.query).toHaveBeenCalledWith(
          expect.stringContaining('workspace_id = $2'),
          [programId, workspaceId, 'program']
        );

        // Verify workspace_id is included in activity query
        expect(pool.query).toHaveBeenCalledWith(
          expect.stringContaining('WHERE workspace_id = $2'),
          [programId, workspaceId]
        );
      });
    });

    describe('date range validation', () => {
      it('queries exactly 30 days of activity', async () => {
        const programId = 'program-123';

        vi.mocked(pool.query)
          .mockResolvedValueOnce({
            rows: [{ id: programId }],
            rowCount: 1,
          } as any)
          .mockResolvedValueOnce({
            rows: Array.from({ length: 30 }, (_, i) => ({
              date: `2024-01-${String(i + 1).padStart(2, '0')}`,
              count: i % 3,
            })),
          } as any);

        const response = await request(app)
          .get(`/activity/program/${programId}`)
          .expect(200);

        // Should return exactly 30 days
        expect(response.body.days).toHaveLength(30);

        // Verify query uses 29 days interval (today + 29 previous days = 30 total)
        expect(pool.query).toHaveBeenCalledWith(
          expect.stringContaining("INTERVAL '29 days'"),
          [programId, 'test-workspace-id']
        );
      });
    });

    describe('entity type specific queries', () => {
      it('program query includes direct documents, projects, and sprints', async () => {
        const programId = 'program-123';

        vi.mocked(pool.query)
          .mockResolvedValueOnce({
            rows: [{ id: programId }],
            rowCount: 1,
          } as any)
          .mockResolvedValueOnce({
            rows: [],
          } as any);

        await request(app)
          .get(`/activity/program/${programId}`)
          .expect(200);

        const activityQuery = vi.mocked(pool.query).mock.calls[1]![0] as string;

        // Verify query structure includes all relevant associations via document_associations
        expect(activityQuery).toContain('program_projects');
        expect(activityQuery).toContain('program_sprints');
        expect(activityQuery).toContain('document_associations');
        expect(activityQuery).toContain("relationship_type = 'program'");
        expect(activityQuery).toContain("relationship_type = 'project'");
        expect(activityQuery).toContain("relationship_type = 'sprint'");
      });

      it('project query includes direct documents and sprints', async () => {
        const projectId = 'project-456';

        vi.mocked(pool.query)
          .mockResolvedValueOnce({
            rows: [{ id: projectId }],
            rowCount: 1,
          } as any)
          .mockResolvedValueOnce({
            rows: [],
          } as any);

        await request(app)
          .get(`/activity/project/${projectId}`)
          .expect(200);

        const activityQuery = vi.mocked(pool.query).mock.calls[1]![0] as string;

        expect(activityQuery).toContain('project_sprints');
        // Project and sprint associations use document_associations junction table
        expect(activityQuery).toContain('document_associations');
        expect(activityQuery).toContain("relationship_type = 'sprint'");
        expect(activityQuery).toContain("relationship_type = 'project'");
      });

      it('sprint query includes direct documents only', async () => {
        const sprintId = 'sprint-789';

        vi.mocked(pool.query)
          .mockResolvedValueOnce({
            rows: [{ id: sprintId }],
            rowCount: 1,
          } as any)
          .mockResolvedValueOnce({
            rows: [],
          } as any);

        await request(app)
          .get(`/activity/sprint/${sprintId}`)
          .expect(200);

        const activityQuery = vi.mocked(pool.query).mock.calls[1]![0] as string;

        // Issues linked via junction table
        expect(activityQuery).toContain('document_associations');
        expect(activityQuery).toContain("relationship_type = 'sprint'");
        expect(activityQuery).toContain('OR id = $1'); // Sprint document itself
        expect(activityQuery).not.toContain('project_sprints');
      });
    });
  });
});

import { describe, it, expect, beforeEach, vi } from 'vitest';

// Mock pool before importing auth middleware
vi.mock('../db/client.js', () => ({
  pool: {
    query: vi.fn(),
  },
}));

import { authMiddleware } from '../middleware/auth.js';
import { pool } from '../db/client.js';
import { Request, Response, NextFunction } from 'express';
import { SESSION_TIMEOUT_MS, ABSOLUTE_SESSION_TIMEOUT_MS } from '@ship/shared';

// Helper to create mock request/response
function createMockReqRes(cookies: Record<string, string> = {}) {
  const req = { cookies } as unknown as Request;
  const res = {
    status: vi.fn().mockReturnThis(),
    json: vi.fn().mockReturnThis(),
    cookie: vi.fn().mockReturnThis(),
  } as unknown as Response;
  const next = vi.fn() as NextFunction;
  return { req, res, next };
}

describe('authMiddleware', () => {
  beforeEach(() => {
    vi.mocked(pool.query).mockReset();
  });

  describe('session validation', () => {
    it('returns 401 when no session cookie is present', async () => {
      const { req, res, next } = createMockReqRes({});
      await authMiddleware(req, res, next);
      expect(res.status).toHaveBeenCalledWith(401);
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          success: false,
          error: expect.objectContaining({ message: 'No session found' }),
        })
      );
      expect(next).not.toHaveBeenCalled();
    });

    it('returns 401 when session does not exist in database', async () => {
      const { req, res, next } = createMockReqRes({ session_id: 'invalid-session' });
      vi.mocked(pool.query).mockResolvedValueOnce({ rows: [], rowCount: 0 } as any);
      await authMiddleware(req, res, next);
      expect(res.status).toHaveBeenCalledWith(401);
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          error: expect.objectContaining({ message: 'Invalid session' }),
        })
      );
      expect(next).not.toHaveBeenCalled();
    });

    it('attaches session info to request for valid session', async () => {
      const { req, res, next } = createMockReqRes({ session_id: 'valid-session' });
      const now = new Date();
      vi.mocked(pool.query)
        .mockResolvedValueOnce({
          rows: [{
            id: 'valid-session',
            user_id: 'user-123',
            workspace_id: 'ws-123',
            last_activity: now,
            created_at: now,
            is_super_admin: false,
          }],
        } as any)
        .mockResolvedValueOnce({ rows: [{ id: 'membership-1' }] } as any)
        .mockResolvedValueOnce({ rows: [] } as any);

      await authMiddleware(req, res, next);
      expect(req.sessionId).toBe('valid-session');
      expect(req.userId).toBe('user-123');
      expect(req.workspaceId).toBe('ws-123');
      expect(next).toHaveBeenCalled();
    });
  });

  describe('session timeout handling', () => {
    it('returns 401 when session exceeds 15-minute inactivity timeout', async () => {
      const { req, res, next } = createMockReqRes({ session_id: 'stale-session' });
      const now = new Date();
      const staleActivity = new Date(now.getTime() - SESSION_TIMEOUT_MS - 1000);
      vi.mocked(pool.query).mockResolvedValueOnce({
        rows: [{
          id: 'stale-session',
          user_id: 'user-123',
          workspace_id: 'ws-123',
          last_activity: staleActivity,
          created_at: now,
          is_super_admin: false,
        }],
      } as any);

      await authMiddleware(req, res, next);
      expect(res.status).toHaveBeenCalledWith(401);
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          error: expect.objectContaining({
            message: expect.stringContaining('inactivity'),
          }),
        })
      );
    });

    it('returns 401 when session exceeds 12-hour absolute timeout', async () => {
      const { req, res, next } = createMockReqRes({ session_id: 'old-session' });
      const now = new Date();
      const oldCreatedAt = new Date(now.getTime() - ABSOLUTE_SESSION_TIMEOUT_MS - 1000);
      vi.mocked(pool.query).mockResolvedValueOnce({
        rows: [{
          id: 'old-session',
          user_id: 'user-123',
          workspace_id: 'ws-123',
          last_activity: now,
          created_at: oldCreatedAt,
          is_super_admin: false,
        }],
      } as any);

      await authMiddleware(req, res, next);
      expect(res.status).toHaveBeenCalledWith(401);
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          error: expect.objectContaining({
            message: expect.stringContaining('expired'),
          }),
        })
      );
    });

    it('deletes expired session from database', async () => {
      const { req, res, next } = createMockReqRes({ session_id: 'expired-session' });
      const now = new Date();
      const staleActivity = new Date(now.getTime() - SESSION_TIMEOUT_MS - 1000);
      vi.mocked(pool.query)
        .mockResolvedValueOnce({
          rows: [{
            id: 'expired-session',
            user_id: 'user-123',
            workspace_id: 'ws-123',
            last_activity: staleActivity,
            created_at: now,
            is_super_admin: false,
          }],
        } as any)
        .mockResolvedValueOnce({ rows: [] } as any);

      await authMiddleware(req, res, next);
      expect(pool.query).toHaveBeenCalledWith(
        'DELETE FROM sessions WHERE id = $1',
        ['expired-session']
      );
    });
  });

  describe('workspace access verification', () => {
    it('returns 403 when user no longer has workspace access', async () => {
      const { req, res, next } = createMockReqRes({ session_id: 'valid-session' });
      const now = new Date();
      vi.mocked(pool.query)
        .mockResolvedValueOnce({
          rows: [{
            id: 'valid-session',
            user_id: 'user-123',
            workspace_id: 'ws-123',
            last_activity: now,
            created_at: now,
            is_super_admin: false,
          }],
        } as any)
        .mockResolvedValueOnce({ rows: [] } as any);

      await authMiddleware(req, res, next);
      expect(res.status).toHaveBeenCalledWith(403);
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          error: expect.objectContaining({
            message: expect.stringContaining('revoked'),
          }),
        })
      );
    });

    it('skips workspace check for super-admin users', async () => {
      const { req, res, next } = createMockReqRes({ session_id: 'admin-session' });
      const now = new Date();
      vi.mocked(pool.query)
        .mockResolvedValueOnce({
          rows: [{
            id: 'admin-session',
            user_id: 'admin-123',
            workspace_id: 'ws-123',
            last_activity: now,
            created_at: now,
            is_super_admin: true,
          }],
        } as any)
        .mockResolvedValueOnce({ rows: [] } as any);

      await authMiddleware(req, res, next);
      expect(req.isSuperAdmin).toBe(true);
      expect(next).toHaveBeenCalled();
    });
  });

  describe('error handling', () => {
    it('returns 500 on database error', async () => {
      const { req, res, next } = createMockReqRes({ session_id: 'some-session' });
      vi.mocked(pool.query).mockRejectedValueOnce(new Error('DB connection failed'));
      await authMiddleware(req, res, next);
      expect(res.status).toHaveBeenCalledWith(500);
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          error: expect.objectContaining({ message: 'Authentication failed' }),
        })
      );
    });
  });

  describe('sliding cookie expiration', () => {
    it('refreshes cookie when activity is beyond 60s threshold', async () => {
      const { req, res, next } = createMockReqRes({ session_id: 'valid-session' });
      const now = new Date();
      // Last activity was 90 seconds ago (beyond 60s threshold)
      const lastActivity = new Date(now.getTime() - 90 * 1000);
      vi.mocked(pool.query)
        .mockResolvedValueOnce({
          rows: [{
            id: 'valid-session',
            user_id: 'user-123',
            workspace_id: 'ws-123',
            last_activity: lastActivity,
            created_at: now,
            is_super_admin: false,
          }],
        } as any)
        .mockResolvedValueOnce({ rows: [{ id: 'membership-1' }] } as any)
        .mockResolvedValueOnce({ rows: [] } as any);

      await authMiddleware(req, res, next);
      expect(pool.query).toHaveBeenCalledWith(
        'UPDATE sessions SET last_activity = $1 WHERE id = $2',
        [expect.any(Date), 'valid-session']
      );
      expect(res.cookie).toHaveBeenCalledWith('session_id', 'valid-session', {
        httpOnly: true,
        secure: false, // NODE_ENV is 'test', not 'production'
        sameSite: 'strict',
        maxAge: SESSION_TIMEOUT_MS,
        path: '/',
      });
      expect(next).toHaveBeenCalled();
    });

    it('does NOT refresh cookie when activity is within 60s threshold', async () => {
      const { req, res, next } = createMockReqRes({ session_id: 'valid-session' });
      const now = new Date();
      // Last activity was 30 seconds ago (within 60s threshold)
      const lastActivity = new Date(now.getTime() - 30 * 1000);
      vi.mocked(pool.query)
        .mockResolvedValueOnce({
          rows: [{
            id: 'valid-session',
            user_id: 'user-123',
            workspace_id: 'ws-123',
            last_activity: lastActivity,
            created_at: now,
            is_super_admin: false,
          }],
        } as any)
        .mockResolvedValueOnce({ rows: [{ id: 'membership-1' }] } as any)
        .mockResolvedValueOnce({ rows: [] } as any);

      await authMiddleware(req, res, next);
      expect(pool.query).not.toHaveBeenCalledWith(
        'UPDATE sessions SET last_activity = $1 WHERE id = $2',
        expect.any(Array)
      );
      expect(res.cookie).not.toHaveBeenCalled();
      expect(next).toHaveBeenCalled();
    });
  });

  describe('bearer token authentication', () => {
    function createMockReqResWithAuth(authHeader: string | undefined) {
      const req = {
        cookies: {},
        headers: { authorization: authHeader },
        get: vi.fn((name: string) => name.toLowerCase() === 'authorization' ? authHeader : undefined),
      } as unknown as Request;
      const res = {
        status: vi.fn().mockReturnThis(),
        json: vi.fn().mockReturnThis(),
      } as unknown as Response;
      const next = vi.fn() as NextFunction;
      return { req, res, next };
    }

    it('authenticates with valid bearer token', async () => {
      const { req, res, next } = createMockReqResWithAuth('Bearer ship_validtoken123');

      // Mock token validation query
      vi.mocked(pool.query)
        .mockResolvedValueOnce({
          rows: [{
            id: 'token-1',
            user_id: 'user-123',
            workspace_id: 'ws-123',
            is_super_admin: false,
          }],
        } as any)
        // Mock update last_used_at
        .mockResolvedValueOnce({ rows: [] } as any);

      await authMiddleware(req, res, next);
      expect(req.userId).toBe('user-123');
      expect(req.workspaceId).toBe('ws-123');
      expect(req.isApiToken).toBe(true);
      expect(next).toHaveBeenCalled();
    });

    it('returns 401 for invalid bearer token', async () => {
      const { req, res, next } = createMockReqResWithAuth('Bearer invalid_token');

      // Mock token not found
      vi.mocked(pool.query).mockResolvedValueOnce({ rows: [] } as any);

      await authMiddleware(req, res, next);
      expect(res.status).toHaveBeenCalledWith(401);
      expect(res.json).toHaveBeenCalledWith(
        expect.objectContaining({
          error: expect.objectContaining({ message: 'Invalid or expired API token' }),
        })
      );
      expect(next).not.toHaveBeenCalled();
    });

    it('returns 401 for revoked bearer token', async () => {
      const { req, res, next } = createMockReqResWithAuth('Bearer ship_revokedtoken');

      // Mock token found but revoked (revoked_at is set)
      vi.mocked(pool.query).mockResolvedValueOnce({ rows: [] } as any); // No results means revoked/expired

      await authMiddleware(req, res, next);
      expect(res.status).toHaveBeenCalledWith(401);
      expect(next).not.toHaveBeenCalled();
    });

    it('prefers bearer token over session cookie when both present', async () => {
      // Create request with both session cookie and auth header
      const req = {
        cookies: { session_id: 'some-session' },
        headers: { authorization: 'Bearer ship_tokentoken' },
        get: vi.fn((name: string) => name.toLowerCase() === 'authorization' ? 'Bearer ship_tokentoken' : undefined),
      } as unknown as Request;
      const res = {
        status: vi.fn().mockReturnThis(),
        json: vi.fn().mockReturnThis(),
      } as unknown as Response;
      const next = vi.fn() as NextFunction;

      vi.mocked(pool.query)
        .mockResolvedValueOnce({
          rows: [{
            id: 'token-1',
            user_id: 'api-user',
            workspace_id: 'api-ws',
            is_super_admin: false,
          }],
        } as any)
        .mockResolvedValueOnce({ rows: [] } as any);

      await authMiddleware(req, res, next);
      // Should use token auth, not session
      expect(req.userId).toBe('api-user');
      expect(req.isApiToken).toBe(true);
      expect(next).toHaveBeenCalled();
    });
  });
});

import { describe, it, expect, beforeEach, vi } from 'vitest';

