      ['Design and build UI components', 'Implement responsive layouts', 'Cross-browser compatibility testing', 'Update design system tokens'],
      ['Deploy infrastructure updates', 'Configure staging environment', 'Set up auto-scaling policies', 'Review and update security configs'],
      ['Implement user settings page', 'Add form validation logic', 'Write E2E tests for critical flows', 'Optimize database queries'],
      ['Build data export feature', 'Implement audit logging', 'Fix memory leak in worker process', 'Update dependency versions'],
      ['Create admin dashboard widgets', 'Implement role-based access controls', 'Add rate limiting to API endpoints', 'Write technical design document'],
      ['Implement file upload handling', 'Build progress indicator components', 'Add WebSocket reconnection logic', 'Optimize image loading performance'],
    ];

    // Content pools for retros (corresponding accomplishments)
    const retroContentPools = [
      ['Completed API endpoints with full CRUD operations', 'Unit tests achieving 91% coverage on new code', 'Merged 4 PRs including critical bugfix', 'API docs updated with all new endpoints'],
      ['Search feature live with fuzzy matching support', 'Pagination fixed across all list views', 'Error handling covers 12 new edge cases', 'Database schema review completed with team'],
      ['Grafana dashboards configured for all services', 'Migrated 3 legacy endpoints successfully', 'Reviewed 8 PRs from team members', 'Deployment runbook finalized and shared'],
      ['Notification system handling email and in-app alerts', 'External API integration passing all tests', 'Fixed 2 critical performance bottlenecks', 'Integration test suite grew by 15 tests'],
      ['Data layer refactored to repository pattern', 'Redis caching reducing database load by 35%', 'Fixed 6 accessibility violations (WCAG AA)', 'CI pipeline execution time reduced by 25%'],
      ['Built 10 reusable UI components for design system', 'Responsive layouts working on all breakpoints', 'Tested on Chrome, Firefox, Safari, and Edge', 'Design tokens migrated to CSS custom properties'],
      ['Infrastructure upgraded to latest AMI versions', 'Staging environment fully mirrors production', 'Auto-scaling tested successfully under load', 'Security configs reviewed and hardened'],
      ['Settings page implemented with real-time preview', 'Form validation catching all invalid inputs', 'E2E test suite covers 5 critical user flows', 'Query optimization reduced avg response time 40%'],
      ['Data export supporting CSV and JSON formats', 'Audit logging capturing all write operations', 'Memory leak identified and patched in worker', 'Dependencies updated with zero breaking changes'],
      ['Dashboard widgets showing real-time metrics', 'RBAC implemented for admin and member roles', 'Rate limiting active on all public endpoints', 'Technical design document reviewed and approved'],
      ['File upload working with drag-and-drop support', 'Progress indicators showing accurate ETAs', 'WebSocket auto-reconnect with exponential backoff', 'Image lazy-loading reducing initial bundle by 30%'],
    ];

    function makePlanContent(items: string[]) {
      return {
        type: 'doc',
        content: [
          {
            type: 'heading',
            attrs: { level: 2 },
            content: [{ type: 'text', text: 'What I plan to accomplish this week' }],
          },
          {
            type: 'bulletList',
            content: items.map(item => ({
              type: 'listItem',
              content: [{ type: 'paragraph', content: [{ type: 'text', text: item }] }],
            })),
          },
        ],
      };
    }

    function makeRetroContent(items: string[]) {
      return {
        type: 'doc',
        content: [
          {
            type: 'heading',
            attrs: { level: 2 },
            content: [{ type: 'text', text: 'What I delivered this week' }],
          },
          {
            type: 'bulletList',
            content: items.map(item => ({
              type: 'listItem',
              content: [{ type: 'paragraph', content: [{ type: 'text', text: item }] }],
            })),
          },
        ],
      };
    }

    // Iterate through sprint assignments and create plans/retros
    for (let i = 0; i < sprintsToCreate.length; i++) {
      const sprintDef = sprintsToCreate[i]!;
      const matchingSprint = sprints.find(
        s => s.programId === sprintDef.programId && s.number === sprintDef.number
      );
      if (!matchingSprint) continue;

      const owner = allUsers[sprintDef.ownerIdx]!;
      const team = programTeams[sprintDef.programId]!;
      const otherIdx = team.find(idx => idx !== sprintDef.ownerIdx) ?? team[0]!;
      const otherUser = allUsers[otherIdx]!;
      const assignees = [
        { personDocId: owner.person_doc_id, userId: owner.id },
        { personDocId: otherUser.person_doc_id, userId: otherUser.id },
      ].filter(a => a.personDocId);

      const sprintOffset = sprintDef.number - currentSprintNumber;

      for (let p = 0; p < assignees.length; p++) {
        const assignee = assignees[p]!;
        const contentIdx = (i + p) % planContentPools.length;

        // Deterministic skip patterns for realistic gaps in past data
        // Dev User (the login user) always gets complete data so action items
        // don't conflict with the heatmap. Other users get realistic gaps.
        const isDevUser = assignee.userId === allUsers.find((u: { name: string }) => u.name === 'Dev User')?.id;
        const skipPlanForPast = !isDevUser && (i + p) % 7 === 3;     // ~14% of past plans missing
        const skipRetroForPast = !isDevUser && (i + p) % 6 === 2;    // ~17% of past retros missing
        const skipPlanForCurrent = !isDevUser && (i + p) % 3 === 0;  // ~33% of current plans not yet done

        // Past sprints: create plan + retro with content (some deliberately skipped)
        if (sprintOffset < 0) {
          if (!skipPlanForPast) {
            const existing = await pool.query(
              `SELECT id FROM documents
               WHERE workspace_id = $1 AND document_type = 'weekly_plan'
                 AND (properties->>'person_id') = $2
                 AND (properties->>'project_id') = $3
                 AND (properties->>'week_number')::int = $4`,
              [workspaceId, assignee.personDocId, sprintDef.projectId, sprintDef.number]
            );
            if (!existing.rows[0]) {
              await pool.query(
                `INSERT INTO documents (workspace_id, document_type, title, content, properties, visibility, created_by)
                 VALUES ($1, 'weekly_plan', $2, $3, $4, 'workspace', $5)`,
                [
                  workspaceId,
                  `Week ${sprintDef.number} Plan`,
                  JSON.stringify(makePlanContent(planContentPools[contentIdx]!)),
                  JSON.stringify({
                    person_id: assignee.personDocId,
                    project_id: sprintDef.projectId,
                    week_number: sprintDef.number,
                    submitted_at: new Date().toISOString(),
                  }),
                  assignee.userId,
                ]
              );
              weeklyPlansCreated++;
            }
          }

          if (!skipRetroForPast) {
            const existing = await pool.query(
              `SELECT id FROM documents
               WHERE workspace_id = $1 AND document_type = 'weekly_retro'
                 AND (properties->>'person_id') = $2
                 AND (properties->>'project_id') = $3
                 AND (properties->>'week_number')::int = $4`,
              [workspaceId, assignee.personDocId, sprintDef.projectId, sprintDef.number]
            );
            if (!existing.rows[0]) {
              await pool.query(
                `INSERT INTO documents (workspace_id, document_type, title, content, properties, visibility, created_by)
                 VALUES ($1, 'weekly_retro', $2, $3, $4, 'workspace', $5)`,
                [
                  workspaceId,
                  `Week ${sprintDef.number} Retro`,
                  JSON.stringify(makeRetroContent(retroContentPools[contentIdx]!)),
                  JSON.stringify({
                    person_id: assignee.personDocId,
                    project_id: sprintDef.projectId,
                    week_number: sprintDef.number,
                    submitted_at: new Date().toISOString(),
                  }),
                  assignee.userId,
                ]
              );
              weeklyRetrosCreated++;
            }
          }
        }

        // Current sprint: create plan for most people (no retros yet)
        if (sprintOffset === 0 && !skipPlanForCurrent) {
          const existing = await pool.query(
            `SELECT id FROM documents
             WHERE workspace_id = $1 AND document_type = 'weekly_plan'
               AND (properties->>'person_id') = $2
               AND (properties->>'project_id') = $3
               AND (properties->>'week_number')::int = $4`,
            [workspaceId, assignee.personDocId, sprintDef.projectId, sprintDef.number]
          );
          if (!existing.rows[0]) {
            await pool.query(
              `INSERT INTO documents (workspace_id, document_type, title, content, properties, visibility, created_by)
               VALUES ($1, 'weekly_plan', $2, $3, $4, 'workspace', $5)`,
              [
                workspaceId,
                `Week ${sprintDef.number} Plan`,
                JSON.stringify(makePlanContent(planContentPools[contentIdx]!)),
                JSON.stringify({
                  person_id: assignee.personDocId,
                  project_id: sprintDef.projectId,
                  week_number: sprintDef.number,
                  submitted_at: new Date().toISOString(),
                }),
                assignee.userId,
              ]
            );
            weeklyPlansCreated++;
          }
        }
      }
    }

    if (weeklyPlansCreated > 0) {
      console.log(`✅ Created ${weeklyPlansCreated} weekly plans`);
    }
    if (weeklyRetrosCreated > 0) {
      console.log(`✅ Created ${weeklyRetrosCreated} weekly retros`);
    }

    console.log('');
    console.log('🎉 Seed complete!');
    console.log('');
    console.log('Login credentials:');
    console.log('  Email: dev@ship.local');
    console.log('  Password: admin123');
  } catch (error) {
    console.error('❌ Seed failed:', error);
    process.exit(1);
  } finally {
    await pool.end();
  }
}

seed();

import { Request, Response, NextFunction } from 'express';
import crypto from 'crypto';
import { pool } from '../db/client.js';
import { SESSION_TIMEOUT_MS, ABSOLUTE_SESSION_TIMEOUT_MS, ERROR_CODES, HTTP_STATUS } from '@ship/shared';

// Extend Express Request to include session info
declare global {
  namespace Express {
    interface Request {
      sessionId?: string;
      userId?: string;
      workspaceId?: string;
      workspaceRole?: string;
      isSuperAdmin?: boolean;
      isApiToken?: boolean; // True when authenticated via API token
    }
  }
}

// Hash a token for comparison
function hashToken(token: string): string {
  return crypto.createHash('sha256').update(token).digest('hex');
}

// Validate API token and return user info if valid
async function validateApiToken(token: string): Promise<{
  userId: string;
  workspaceId: string;
  isSuperAdmin: boolean;
  tokenId: string;
} | null> {
  const tokenHash = hashToken(token);

  const result = await pool.query(
    `SELECT t.id, t.user_id, t.workspace_id, t.expires_at, t.revoked_at, u.is_super_admin
     FROM api_tokens t
     JOIN users u ON t.user_id = u.id
     WHERE t.token_hash = $1`,
    [tokenHash]
  );

  const tokenRow = result.rows[0];

  if (!tokenRow) return null;

  // Check if revoked
  if (tokenRow.revoked_at) return null;

  // Check if expired
  if (tokenRow.expires_at && new Date(tokenRow.expires_at) < new Date()) return null;

  // Update last_used_at
  await pool.query(
    'UPDATE api_tokens SET last_used_at = NOW() WHERE id = $1',
    [tokenRow.id]
  );

  return {
    userId: tokenRow.user_id,
    workspaceId: tokenRow.workspace_id,
    isSuperAdmin: tokenRow.is_super_admin,
    tokenId: tokenRow.id,
  };
}

export async function authMiddleware(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  // Check for Bearer token first (API token auth)
  const authHeader = req.headers?.authorization;
  if (authHeader && authHeader.startsWith('Bearer ')) {
    const token = authHeader.slice(7);

    try {
      const tokenData = await validateApiToken(token);

      if (!tokenData) {
        res.status(HTTP_STATUS.UNAUTHORIZED).json({
          success: false,
          error: {
            code: ERROR_CODES.UNAUTHORIZED,
            message: 'Invalid or expired API token',
          },
        });
        return;
      }

      // Attach token info to request
      req.userId = tokenData.userId;
      req.workspaceId = tokenData.workspaceId;
      req.isSuperAdmin = tokenData.isSuperAdmin;
      req.isApiToken = true;

      next();
      return;
    } catch (error) {
      console.error('API token auth error:', error);
      res.status(HTTP_STATUS.INTERNAL_SERVER_ERROR).json({
        success: false,
        error: {
          code: ERROR_CODES.INTERNAL_ERROR,
          message: 'Authentication failed',
        },
      });
      return;
    }
  }

  // Fall back to session cookie auth
  const sessionId = req.cookies?.session_id;

  if (!sessionId) {
    res.status(HTTP_STATUS.UNAUTHORIZED).json({
      success: false,
      error: {
        code: ERROR_CODES.UNAUTHORIZED,
        message: 'No session found',
      },
    });
    return;
  }

  try {
    // Get session and check if it's valid
    const result = await pool.query(
      `SELECT s.id, s.user_id, s.workspace_id, s.expires_at, s.last_activity, s.created_at,
              u.is_super_admin
       FROM sessions s
       JOIN users u ON s.user_id = u.id
       WHERE s.id = $1`,
      [sessionId]
    );

    const session = result.rows[0];

    if (!session) {
      res.status(HTTP_STATUS.UNAUTHORIZED).json({
        success: false,
        error: {
          code: ERROR_CODES.UNAUTHORIZED,
          message: 'Invalid session',
        },
      });
      return;
    }

    const now = new Date();
    const lastActivity = new Date(session.last_activity);
    const createdAt = new Date(session.created_at);
    const inactivityMs = now.getTime() - lastActivity.getTime();
    const sessionAgeMs = now.getTime() - createdAt.getTime();

    // Check 12-hour absolute session timeout (NIST SP 800-63B-4 AAL2)
    if (sessionAgeMs > ABSOLUTE_SESSION_TIMEOUT_MS) {
      await pool.query('DELETE FROM sessions WHERE id = $1', [sessionId]);

      res.status(HTTP_STATUS.UNAUTHORIZED).json({
        success: false,
        error: {
          code: ERROR_CODES.SESSION_EXPIRED,
          message: 'Session expired. Please log in again.',
        },
      });
      return;
    }

    // Check 15-minute inactivity timeout
    if (inactivityMs > SESSION_TIMEOUT_MS) {
      await pool.query('DELETE FROM sessions WHERE id = $1', [sessionId]);

      res.status(HTTP_STATUS.UNAUTHORIZED).json({
        success: false,
        error: {
          code: ERROR_CODES.SESSION_EXPIRED,
          message: 'Session expired due to inactivity',
        },
      });
      return;
    }

    // Verify user still has access to the workspace (unless super-admin)
    let workspaceRole: string | undefined;
    if (session.workspace_id && !session.is_super_admin) {
      const membershipResult = await pool.query(
        'SELECT id, role FROM workspace_memberships WHERE workspace_id = $1 AND user_id = $2',
        [session.workspace_id, session.user_id]
      );

      const membership = membershipResult.rows[0];
      if (!membership) {
        // User no longer has access - delete session
        await pool.query('DELETE FROM sessions WHERE id = $1', [sessionId]);

        res.status(HTTP_STATUS.FORBIDDEN).json({
          success: false,
          error: {
            code: ERROR_CODES.FORBIDDEN,
            message: 'Access to this workspace has been revoked',
          },
        });
        return;
      }

      workspaceRole = membership.role;
    }

    // Refresh cookie with sliding expiration (throttled to avoid overhead)
    // Only refresh if more than 60 seconds since last activity
    const COOKIE_REFRESH_THRESHOLD_MS = 60 * 1000;
    if (inactivityMs > COOKIE_REFRESH_THRESHOLD_MS) {
      await pool.query(
        'UPDATE sessions SET last_activity = $1 WHERE id = $2',
        [now, sessionId]
      );

      res.cookie('session_id', sessionId, {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'strict',
        maxAge: SESSION_TIMEOUT_MS,
        path: '/',
      });
    }

    // Attach session info to request
    req.sessionId = session.id;
    req.userId = session.user_id;
    req.workspaceId = session.workspace_id;
    req.workspaceRole = workspaceRole;
    req.isSuperAdmin = session.is_super_admin;

    next();
  } catch (error) {
    console.error('Auth middleware error:', error);
    res.status(HTTP_STATUS.INTERNAL_SERVER_ERROR).json({
      success: false,
      error: {
        code: ERROR_CODES.INTERNAL_ERROR,
        message: 'Authentication failed',
      },
    });
  }
}

// Middleware that requires super-admin access
export async function superAdminMiddleware(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  if (!req.isSuperAdmin) {
    res.status(HTTP_STATUS.FORBIDDEN).json({
      success: false,
      error: {
        code: ERROR_CODES.FORBIDDEN,
        message: 'Super-admin access required',
      },
    });
    return;
  }

  next();
}

// Middleware that requires workspace admin access (or super-admin)
export async function workspaceAdminMiddleware(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  // Super-admins always have access
  if (req.isSuperAdmin) {
    next();
    return;
  }

  const workspaceId = req.params.id || req.workspaceId;

  if (!workspaceId) {
    res.status(HTTP_STATUS.BAD_REQUEST).json({
      success: false,
      error: {
        code: ERROR_CODES.VALIDATION_ERROR,
        message: 'Workspace ID required',
      },
    });
    return;
  }

  try {
    const result = await pool.query(
      'SELECT role FROM workspace_memberships WHERE workspace_id = $1 AND user_id = $2',
      [workspaceId, req.userId]
    );

    const membership = result.rows[0];

    if (!membership || membership.role !== 'admin') {
      res.status(HTTP_STATUS.FORBIDDEN).json({
        success: false,
        error: {
          code: ERROR_CODES.FORBIDDEN,
          message: 'Workspace admin access required',
        },
      });
      return;
    }

    next();
  } catch (error) {
    console.error('Workspace admin middleware error:', error);
    res.status(HTTP_STATUS.INTERNAL_SERVER_ERROR).json({
      success: false,
      error: {
        code: ERROR_CODES.INTERNAL_ERROR,
        message: 'Authorization check failed',
      },
    });
  }
}

// Middleware that verifies access to a specific workspace
export async function workspaceAccessMiddleware(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  // Super-admins always have access
  if (req.isSuperAdmin) {
    next();
    return;
  }

  const workspaceId = req.params.workspaceId || req.workspaceId;

  if (!workspaceId) {
    res.status(HTTP_STATUS.BAD_REQUEST).json({
      success: false,
      error: {
        code: ERROR_CODES.VALIDATION_ERROR,
        message: 'Workspace ID required',
      },
    });
    return;
  }

  try {
    const result = await pool.query(
      'SELECT id FROM workspace_memberships WHERE workspace_id = $1 AND user_id = $2',
      [workspaceId, req.userId]
    );

    if (!result.rows[0]) {
      res.status(HTTP_STATUS.FORBIDDEN).json({
        success: false,
        error: {
          code: ERROR_CODES.FORBIDDEN,
          message: 'Access denied to this workspace',
        },
      });
      return;
    }

    next();
  } catch (error) {
    console.error('Workspace access middleware error:', error);
    res.status(HTTP_STATUS.INTERNAL_SERVER_ERROR).json({
      success: false,
      error: {
        code: ERROR_CODES.INTERNAL_ERROR,
        message: 'Authorization check failed',
      },
    });
  }
}

import type { Request, Response, NextFunction } from 'express';
import { captureError } from '@ship/shared';

export function asyncHandler(
  fn: (req: Request, res: Response, next: NextFunction) => Promise<void>,
) {
  return (req: Request, res: Response, next: NextFunction): void => {
    Promise.resolve(fn(req, res, next)).catch(next);
  };
}

export function errorHandler(
  err: unknown,
  req: Request,
  res: Response,
  _next: NextFunction,
): void {
  const captured = captureError(err, 'express', {
    method: req.method,
    path: req.path,
  });
  console.error(`[error-capture:${captured.source}]`, captured.message, captured.context ?? '');

  if (res.headersSent) {
    return;
  }

  const status =
    typeof err === 'object' &&
    err !== null &&
    'status' in err &&
    typeof (err as { status: unknown }).status === 'number'
      ? (err as { status: number }).status
      : 500;

  const message =
    err instanceof Error ? err.message : 'Internal server error';

  res.status(status >= 400 && status < 600 ? status : 500).json({
    error: {
      code: status === 500 ? 'INTERNAL_ERROR' : 'REQUEST_ERROR',
      message: status === 500 ? 'Internal server error' : message,
    },
  });
}

/**
 * Backlinks and Associations schemas - Document relationships
 */

import { z, registry } from '../registry.js';
import { UuidSchema, DateTimeSchema, BelongsToTypeSchema, AssociationRelationshipTypeSchema } from './common.js';
import { DocumentTypeSchema } from './documents.js';

// ============== Backlink ==============

export const BacklinkSchema = z.object({
  id: UuidSchema,
  document_type: DocumentTypeSchema,
  title: z.string(),
  display_id: z.string().optional().openapi({
    description: 'Display ID for issues (e.g., "#42")',
  }),
}).openapi('Backlink');

registry.register('Backlink', BacklinkSchema);

// ============== Association ==============

export const AssociationSchema = z.object({
  id: UuidSchema,
  document_id: UuidSchema,
  related_id: UuidSchema,
  relationship_type: AssociationRelationshipTypeSchema,
  created_at: DateTimeSchema,
  // Related document info
  related_title: z.string().optional(),
  related_document_type: DocumentTypeSchema.optional(),
  related_color: z.string().optional(),
}).openapi('Association');

registry.register('Association', AssociationSchema);

// ============== Register Backlink Endpoints ==============

registry.registerPath({
  method: 'get',
  path: '/documents/{id}/backlinks',
  tags: ['Documents'],
  summary: 'Get document backlinks',
  description: 'Get all documents that link to this document.',
  request: {
    params: z.object({
      id: UuidSchema,
    }),
  },
  responses: {
    200: {
      description: 'List of backlinks',
      content: {
        'application/json': {
          schema: z.array(BacklinkSchema),
        },
      },
    },
    404: {
      description: 'Document not found',
    },
  },
});

registry.registerPath({
  method: 'post',
  path: '/documents/{id}/links',
  tags: ['Documents'],
  summary: 'Update document links',
  description: 'Update the links from this document to other documents.',
  request: {
    params: z.object({
      id: UuidSchema,
    }),
    body: {
      content: {
        'application/json': {
          schema: z.object({
            target_ids: z.array(UuidSchema),
          }),
        },
      },
    },
  },
  responses: {
    200: {
      description: 'Links updated',
      content: {
        'application/json': {
          schema: z.object({
            added: z.number().int(),
            removed: z.number().int(),
          }),
        },
      },
    },
    404: {
      description: 'Document not found',
    },
  },
});

registry.registerPath({
  method: 'get',
  path: '/documents/{id}/associations',
  tags: ['Documents'],
  summary: 'Get document associations',
  description: 'Get associations (belongs_to relationships) for this document.',
  request: {
    params: z.object({
      id: UuidSchema,
    }),
  },
  responses: {
    200: {
      description: 'List of associations',
      content: {
        'application/json': {
          schema: z.array(AssociationSchema),
        },
      },
    },
    404: {
      description: 'Document not found',
    },
  },
});

registry.registerPath({
  method: 'post',
  path: '/documents/{id}/associations',
  tags: ['Documents'],
  summary: 'Add document association',
  description: 'Add an association to a program, project, sprint, parent document, or dependency predecessor.',
  request: {
    params: z.object({
      id: UuidSchema,
    }),
    body: {
      content: {
        'application/json': {
          schema: z.object({
            related_id: UuidSchema,
            relationship_type: AssociationRelationshipTypeSchema,
          }),
        },
      },
    },
  },
  responses: {
    201: {
      description: 'Association created',
      content: {
        'application/json': {
          schema: AssociationSchema,
        },
      },
    },
    400: {
      description: 'Invalid association',
    },
    404: {
      description: 'Document not found',
    },
    409: {
      description: 'Association already exists',
    },
  },
});

registry.registerPath({
  method: 'delete',
  path: '/documents/{id}/associations/{relatedId}',
  tags: ['Documents'],
  summary: 'Remove document association',
  request: {
    params: z.object({
      id: UuidSchema,
      relatedId: UuidSchema,
    }),
  },
  responses: {
    204: {
      description: 'Association removed',
    },
    404: {
      description: 'Document or association not found',
    },
  },
});

registry.registerPath({
  method: 'get',
  path: '/documents/{id}/reverse-associations',
