      await pool.query('DELETE FROM documents WHERE id = $1', [testIssueId])
    })

    it('standup context returns issues via junction table', async () => {
      const response = await request(app)
        .get(`/api/claude/context?context_type=standup&sprint_id=${testSprint1Id}`)
        .set('Cookie', sessionCookie)

      expect(response.status).toBe(200)
      expect(response.body.issues).toBeDefined()

      // Should include our test issue
      const issueList = response.body.issues.items || response.body.issues
      const testIssue = issueList.find((i: any) => i.id === testIssueId)
      expect(testIssue).toBeDefined()
    })

    it('review context returns issues via junction table', async () => {
      const response = await request(app)
        .get(`/api/claude/context?context_type=review&sprint_id=${testSprint1Id}`)
        .set('Cookie', sessionCookie)

      expect(response.status).toBe(200)
      expect(response.body.issues).toBeDefined()
    })
  })

  describe('Status cascade warning for parent issues', () => {
    let parentIssueId: string
    let childIssueId: string

    beforeEach(async () => {
      // Create parent issue
      const parentResult = await pool.query(
        `INSERT INTO documents (workspace_id, document_type, title, ticket_number, created_by, properties)
         VALUES ($1, 'issue', 'Parent Issue', 9010, $2, '{"state": "in_progress", "priority": "medium"}')
         RETURNING id`,
        [testWorkspaceId, testUserId]
      )
      parentIssueId = parentResult.rows[0].id

      // Create child issue
      const childResult = await pool.query(
        `INSERT INTO documents (workspace_id, document_type, title, ticket_number, created_by, properties)
         VALUES ($1, 'issue', 'Child Issue', 9011, $2, '{"state": "todo", "priority": "medium"}')
         RETURNING id`,
        [testWorkspaceId, testUserId]
      )
      childIssueId = childResult.rows[0].id

      // Create parent-child association
      await pool.query(
        `INSERT INTO document_associations (document_id, related_id, relationship_type)
         VALUES ($1, $2, 'parent')`,
        [childIssueId, parentIssueId]
      )
    })

    afterEach(async () => {
      await pool.query('DELETE FROM document_associations WHERE document_id IN ($1, $2)', [parentIssueId, childIssueId])
      await pool.query('DELETE FROM documents WHERE id IN ($1, $2)', [parentIssueId, childIssueId])
    })

    it('returns 409 warning when closing parent with incomplete children', async () => {
      const response = await request(app)
        .patch(`/api/issues/${parentIssueId}`)
        .set('Cookie', sessionCookie)
        .set('x-csrf-token', csrfToken)
        .send({ state: 'done' })

      expect(response.status).toBe(409)
      expect(response.body.error).toBe('incomplete_children')
      expect(response.body.incomplete_children).toBeDefined()
      expect(response.body.incomplete_children.length).toBe(1)
      expect(response.body.incomplete_children[0].id).toBe(childIssueId)
    })

    it('allows closing parent with confirm_orphan_children flag', async () => {
      const response = await request(app)
        .patch(`/api/issues/${parentIssueId}`)
        .set('Cookie', sessionCookie)
        .set('x-csrf-token', csrfToken)
        .send({ state: 'done', confirm_orphan_children: true })

      expect(response.status).toBe(200)
      expect(response.body.state).toBe('done')

      // Verify child is orphaned (parent association removed)
      const assocResult = await pool.query(
        `SELECT * FROM document_associations WHERE document_id = $1 AND relationship_type = 'parent'`,
        [childIssueId]
      )
      expect(assocResult.rows.length).toBe(0)
    })

    it('closes parent without warning if all children are done', async () => {
      // Mark child as done first
      await pool.query(
        `UPDATE documents SET properties = properties || '{"state": "done"}' WHERE id = $1`,
        [childIssueId]
      )

      const response = await request(app)
        .patch(`/api/issues/${parentIssueId}`)
        .set('Cookie', sessionCookie)
        .set('x-csrf-token', csrfToken)
        .send({ state: 'done' })

      expect(response.status).toBe(200)
      expect(response.body.state).toBe('done')
    })
  })
})

import { describe, it, expect, beforeAll, afterAll } from 'vitest'
import request from 'supertest'
import crypto from 'crypto'
import bcrypt from 'bcryptjs'
import { createApp } from '../app.js'
import { pool } from '../db/client.js'

// Helper to normalize set-cookie header (can be string or string[])
function getCookiesArray(setCookie: string | string[] | undefined): string[] {
  if (!setCookie) return []
  return Array.isArray(setCookie) ? setCookie : [setCookie]
}

describe('Auth API', () => {
  const app = createApp()
  const testRunId = Date.now().toString(36) + Math.random().toString(36).slice(2, 6)
  const testEmail = `auth-test-${testRunId}@ship.local`
  const testPassword = 'TestPassword123!'
  const testWorkspaceName = `Auth Test ${testRunId}`

  let testWorkspaceId: string
  let testUserId: string
  let passwordHash: string

  // Helper to get CSRF token and session cookie for requests
  async function getCsrfTokenAndCookie(): Promise<{ csrfToken: string; cookie: string }> {
    const csrfRes = await request(app).get('/api/csrf-token')
    const csrfToken = csrfRes.body.token
    const cookie = csrfRes.headers['set-cookie']?.[0]?.split(';')[0] || ''
    return { csrfToken, cookie }
  }

  // Helper to login with CSRF token
  async function loginWithCsrf(email: string, password: string, extraCookie?: string) {
    const { csrfToken, cookie } = await getCsrfTokenAndCookie()
    const fullCookie = extraCookie ? `${cookie}; ${extraCookie}` : cookie
    return request(app)
      .post('/api/auth/login')
      .set('Cookie', fullCookie)
      .set('x-csrf-token', csrfToken)
      .send({ email, password })
  }

  beforeAll(async () => {
    // Create test workspace
    const workspaceResult = await pool.query(
      `INSERT INTO workspaces (name) VALUES ($1) RETURNING id`,
      [testWorkspaceName]
    )
    testWorkspaceId = workspaceResult.rows[0].id

    // Create password hash
    passwordHash = await bcrypt.hash(testPassword, 10)

    // Create test user with password
    const userResult = await pool.query(
      `INSERT INTO users (email, password_hash, name)
       VALUES ($1, $2, 'Auth Test User')
       RETURNING id`,
      [testEmail, passwordHash]
    )
    testUserId = userResult.rows[0].id

    // Create workspace membership
    await pool.query(
      `INSERT INTO workspace_memberships (workspace_id, user_id, role)
       VALUES ($1, $2, 'member')`,
      [testWorkspaceId, testUserId]
    )
  })

  afterAll(async () => {
    // Clean up in correct order (foreign key constraints)
    await pool.query('DELETE FROM sessions WHERE user_id = $1', [testUserId])
    await pool.query('DELETE FROM workspace_memberships WHERE user_id = $1', [testUserId])
    await pool.query('DELETE FROM users WHERE id = $1', [testUserId])
    await pool.query('DELETE FROM workspaces WHERE id = $1', [testWorkspaceId])
  })

  describe('POST /api/auth/login', () => {
    it('should reject login without email', async () => {
      const { csrfToken, cookie } = await getCsrfTokenAndCookie()
      const res = await request(app)
        .post('/api/auth/login')
        .set('Cookie', cookie)
        .set('x-csrf-token', csrfToken)
        .send({ password: testPassword })

      expect(res.status).toBe(400)
      expect(res.body.success).toBe(false)
      expect(res.body.error.message).toContain('Email and password are required')
    })

    it('should reject login without password', async () => {
      const { csrfToken, cookie } = await getCsrfTokenAndCookie()
      const res = await request(app)
        .post('/api/auth/login')
        .set('Cookie', cookie)
        .set('x-csrf-token', csrfToken)
        .send({ email: testEmail })

      expect(res.status).toBe(400)
      expect(res.body.success).toBe(false)
      expect(res.body.error.message).toContain('Email and password are required')
    })

    it('should reject login with non-existent email', async () => {
      const { csrfToken, cookie } = await getCsrfTokenAndCookie()
      const res = await request(app)
        .post('/api/auth/login')
        .set('Cookie', cookie)
        .set('x-csrf-token', csrfToken)
        .send({ email: 'nonexistent@ship.local', password: testPassword })

      expect(res.status).toBe(401)
      expect(res.body.success).toBe(false)
      expect(res.body.error.message).toBe('Invalid email or password')
    })

    it('should reject login with wrong password', async () => {
      const { csrfToken, cookie } = await getCsrfTokenAndCookie()
      const res = await request(app)
        .post('/api/auth/login')
        .set('Cookie', cookie)
        .set('x-csrf-token', csrfToken)
        .send({ email: testEmail, password: 'WrongPassword123!' })

      expect(res.status).toBe(401)
      expect(res.body.success).toBe(false)
      expect(res.body.error.message).toBe('Invalid email or password')
    })

    it('should accept valid credentials and set session cookie', async () => {
      const res = await loginWithCsrf(testEmail, testPassword)

      expect(res.status).toBe(200)
      expect(res.body.success).toBe(true)
      expect(res.body.data.user).toBeDefined()
      expect(res.body.data.user.email).toBe(testEmail)
      expect(res.body.data.user.id).toBe(testUserId)
      expect(res.body.data.currentWorkspace).toBeDefined()
      expect(res.body.data.workspaces).toBeInstanceOf(Array)

      // Check cookie is set
      const cookies = getCookiesArray(res.headers['set-cookie'])
      expect(cookies.length).toBeGreaterThan(0)
      const sessionCookie = cookies.find((c: string) => c.startsWith('session_id='))
      expect(sessionCookie).toBeDefined()
      expect(sessionCookie).toContain('HttpOnly')
    })

    it('should handle case-insensitive email lookup', async () => {
      const res = await loginWithCsrf(testEmail.toUpperCase(), testPassword)

      expect(res.status).toBe(200)
      expect(res.body.success).toBe(true)
    })

    it('should reject PIV-only user attempting password login', async () => {
      // Create PIV-only user (no password_hash)
      const pivEmail = `piv-user-${testRunId}@ship.local`
      const pivUserResult = await pool.query(
        `INSERT INTO users (email, password_hash, name)
         VALUES ($1, NULL, 'PIV User')
         RETURNING id`,
        [pivEmail]
      )
      const pivUserId = pivUserResult.rows[0].id

      // Add to workspace
      await pool.query(
        `INSERT INTO workspace_memberships (workspace_id, user_id, role)
         VALUES ($1, $2, 'member')`,
        [testWorkspaceId, pivUserId]
      )

      const res = await loginWithCsrf(pivEmail, 'anypassword')

      expect(res.status).toBe(401)
      expect(res.body.error.message).toContain('PIV authentication only')

      // Cleanup
      await pool.query('DELETE FROM workspace_memberships WHERE user_id = $1', [pivUserId])
      await pool.query('DELETE FROM users WHERE id = $1', [pivUserId])
    })
  })

  describe('POST /api/auth/logout', () => {
    it('should reject logout without session', async () => {
      const { csrfToken, cookie } = await getCsrfTokenAndCookie()
      const res = await request(app)
        .post('/api/auth/logout')
        .set('Cookie', cookie)
        .set('x-csrf-token', csrfToken)

      expect(res.status).toBe(401)
    })

    it('should successfully logout with valid session', async () => {
      // First login to get a session
      const loginRes = await loginWithCsrf(testEmail, testPassword)

      expect(loginRes.status).toBe(200)
      const cookies = getCookiesArray(loginRes.headers['set-cookie'])
      const sessionCookie = cookies.find((c: string) => c.startsWith('session_id='))?.split(';')[0]

      // Get CSRF token with session
      const csrfRes = await request(app)
        .get('/api/csrf-token')
        .set('Cookie', sessionCookie || '')

      const csrfToken = csrfRes.body.token
      const connectSidCookie = csrfRes.headers['set-cookie']?.[0]?.split(';')[0] || ''
      const fullCookie = connectSidCookie ? `${sessionCookie}; ${connectSidCookie}` : sessionCookie

      // Now logout
      const logoutRes = await request(app)
        .post('/api/auth/logout')
        .set('Cookie', fullCookie || '')
        .set('x-csrf-token', csrfToken || '')

      expect(logoutRes.status).toBe(200)
      expect(logoutRes.body.success).toBe(true)

      // Verify session is invalidated - subsequent requests should fail
      const meRes = await request(app)
        .get('/api/auth/me')
        .set('Cookie', fullCookie || '')

      expect(meRes.status).toBe(401)
    })
  })

  describe('GET /api/auth/me', () => {
    let sessionCookie: string
    let csrfToken: string

    beforeAll(async () => {
      // Login to get a session
      const loginRes = await loginWithCsrf(testEmail, testPassword)

      const cookies = getCookiesArray(loginRes.headers['set-cookie'])
      sessionCookie = cookies.find((c: string) => c.startsWith('session_id='))?.split(';')[0] || ''

      // Get CSRF token with session
      const csrfRes = await request(app)
        .get('/api/csrf-token')
        .set('Cookie', sessionCookie)

      csrfToken = csrfRes.body.token
      const connectSidCookie = csrfRes.headers['set-cookie']?.[0]?.split(';')[0] || ''
      if (connectSidCookie) {
        sessionCookie = `${sessionCookie}; ${connectSidCookie}`
      }
    })

    it('should reject request without session', async () => {
      const res = await request(app)
        .get('/api/auth/me')

      expect(res.status).toBe(401)
    })

    it('should return user info for valid session', async () => {
      const res = await request(app)
        .get('/api/auth/me')
        .set('Cookie', sessionCookie)

      expect(res.status).toBe(200)
      expect(res.body.success).toBe(true)
      expect(res.body.data.user).toBeDefined()
      expect(res.body.data.user.email).toBe(testEmail)
      expect(res.body.data.user.id).toBe(testUserId)
      expect(res.body.data.currentWorkspace).toBeDefined()
      expect(res.body.data.workspaces).toBeInstanceOf(Array)
    })

    it('should reject expired session', async () => {
      // Create a session that expired due to inactivity (last_activity > 15 minutes ago)
      // Auth middleware checks last_activity against 15-minute timeout, not expires_at
      const expiredSessionId = crypto.randomBytes(32).toString('hex')
      await pool.query(
        `INSERT INTO sessions (id, user_id, workspace_id, expires_at, last_activity)
         VALUES ($1, $2, $3, now() + interval '1 hour', now() - interval '20 minutes')`,
        [expiredSessionId, testUserId, testWorkspaceId]
      )

      const res = await request(app)
        .get('/api/auth/me')
        .set('Cookie', `session_id=${expiredSessionId}`)

      expect(res.status).toBe(401)

      // Session should be auto-deleted by middleware, but cleanup anyway
      await pool.query('DELETE FROM sessions WHERE id = $1', [expiredSessionId])
    })
  })

  describe('POST /api/auth/extend-session', () => {
    it('should extend session expiry', async () => {
      // Login to get a session
      const loginRes = await loginWithCsrf(testEmail, testPassword)

      const cookies = getCookiesArray(loginRes.headers['set-cookie'])
      let sessionCookie = cookies.find((c: string) => c.startsWith('session_id='))?.split(';')[0] || ''

      // Get CSRF token with session
      const csrfRes = await request(app)
        .get('/api/csrf-token')
        .set('Cookie', sessionCookie)

      const csrfToken = csrfRes.body.token
      const connectSidCookie = csrfRes.headers['set-cookie']?.[0]?.split(';')[0] || ''
      if (connectSidCookie) {
        sessionCookie = `${sessionCookie}; ${connectSidCookie}`
      }

      // Extend session
      const res = await request(app)
        .post('/api/auth/extend-session')
        .set('Cookie', sessionCookie)
        .set('x-csrf-token', csrfToken || '')

      expect(res.status).toBe(200)
      expect(res.body.success).toBe(true)
      expect(res.body.data.expiresAt).toBeDefined()
      expect(res.body.data.lastActivity).toBeDefined()

      // Verify expiry is in the future
      const expiresAt = new Date(res.body.data.expiresAt)
      expect(expiresAt.getTime()).toBeGreaterThan(Date.now())
    })
  })

  describe('GET /api/auth/session', () => {
    it('should return session info', async () => {
      // Login to get a session
      const loginRes = await loginWithCsrf(testEmail, testPassword)

      const cookies = getCookiesArray(loginRes.headers['set-cookie'])
      let sessionCookie = cookies.find((c: string) => c.startsWith('session_id='))?.split(';')[0] || ''

      // Get CSRF token with session
      const csrfRes = await request(app)
        .get('/api/csrf-token')
        .set('Cookie', sessionCookie)

      const connectSidCookie = csrfRes.headers['set-cookie']?.[0]?.split(';')[0] || ''
      if (connectSidCookie) {
        sessionCookie = `${sessionCookie}; ${connectSidCookie}`
      }

      // Get session info
      const res = await request(app)
        .get('/api/auth/session')
        .set('Cookie', sessionCookie)

      expect(res.status).toBe(200)
      expect(res.body.success).toBe(true)
      expect(res.body.data.createdAt).toBeDefined()
      expect(res.body.data.expiresAt).toBeDefined()
      expect(res.body.data.absoluteExpiresAt).toBeDefined()
      expect(res.body.data.lastActivity).toBeDefined()
    })
  })

  describe('Session Security', () => {
    it('should generate unique session IDs for each login', async () => {
      // Login twice and verify different session IDs
      const login1 = await loginWithCsrf(testEmail, testPassword)

      const cookies1 = getCookiesArray(login1.headers['set-cookie'])
      const session1 = cookies1.find((c: string) => c.startsWith('session_id='))?.split(';')[0]?.split('=')[1]

      const login2 = await loginWithCsrf(testEmail, testPassword)

      const cookies2 = getCookiesArray(login2.headers['set-cookie'])
      const session2 = cookies2.find((c: string) => c.startsWith('session_id='))?.split(';')[0]?.split('=')[1]

      expect(session1).not.toBe(session2)
    })

    it('should invalidate old session on re-login (session fixation prevention)', async () => {
      // Login to get first session
      const login1 = await loginWithCsrf(testEmail, testPassword)

      const cookies1 = getCookiesArray(login1.headers['set-cookie'])
      let session1Cookie = cookies1.find((c: string) => c.startsWith('session_id='))?.split(';')[0] || ''

      // Get CSRF for first session
      const csrfRes = await request(app)
        .get('/api/csrf-token')
        .set('Cookie', session1Cookie)

      const csrfToken = csrfRes.body.token
      const connectSidCookie = csrfRes.headers['set-cookie']?.[0]?.split(';')[0] || ''
      if (connectSidCookie) {
        session1Cookie = `${session1Cookie}; ${connectSidCookie}`
      }

      // Re-login with the old session cookie (simulates session fixation attempt)
      const login2 = await request(app)
        .post('/api/auth/login')
        .set('Cookie', session1Cookie)
        .set('x-csrf-token', csrfToken)
        .send({ email: testEmail, password: testPassword })

      expect(login2.status).toBe(200)

      // Old session should be invalid
      const meRes = await request(app)
        .get('/api/auth/me')
        .set('Cookie', session1Cookie)

      expect(meRes.status).toBe(401)
    })
  })
})

import { Router, Request, Response } from 'express';
import type { Router as RouterType } from 'express';
import bcrypt from 'bcryptjs';
import crypto from 'crypto';
import { pool } from '../db/client.js';
import { authMiddleware } from '../middleware/auth.js';
import { ERROR_CODES, HTTP_STATUS, SESSION_TIMEOUT_MS, ABSOLUTE_SESSION_TIMEOUT_MS } from '@ship/shared';
import { logAuditEvent } from '../services/audit.js';

const router: RouterType = Router();

// Generate cryptographically secure session ID (256 bits of entropy)
function generateSecureSessionId(): string {
  return crypto.randomBytes(32).toString('hex');
}

// POST /api/auth/login
router.post('/login', async (req: Request, res: Response): Promise<void> => {
  const { email, password } = req.body;

  if (!email || !password) {
    res.status(HTTP_STATUS.BAD_REQUEST).json({
      success: false,
      error: {
        code: ERROR_CODES.VALIDATION_ERROR,
        message: 'Email and password are required',
      },
    });
    return;
  }

  try {
    // Find user with their workspace memberships (case-insensitive email lookup)
    const userResult = await pool.query(
      `SELECT u.id, u.email, u.password_hash, u.name, u.is_super_admin, u.last_workspace_id
       FROM users u
       WHERE LOWER(u.email) = LOWER($1)`,
      [email]
    );

    const user = userResult.rows[0];

    if (!user) {
      await logAuditEvent({
        action: 'auth.login_failed',
        details: { email, reason: 'user_not_found' },
        req,
      });
      res.status(HTTP_STATUS.UNAUTHORIZED).json({
        success: false,
        error: {
          code: ERROR_CODES.INVALID_CREDENTIALS,
          message: 'Invalid email or password',
        },
      });
      return;
    }

    // Verify password (PIV-only users have null password_hash)
    if (!user.password_hash) {
      await logAuditEvent({
        action: 'auth.login_failed',
        details: { email, reason: 'piv_only_user' },
        req,
      });
      res.status(HTTP_STATUS.UNAUTHORIZED).json({
        success: false,
        error: {
          code: ERROR_CODES.INVALID_CREDENTIALS,
          message: 'This account uses PIV authentication only',
        },
      });
      return;
    }

    const validPassword = await bcrypt.compare(password, user.password_hash);

    if (!validPassword) {
      await logAuditEvent({
        action: 'auth.login_failed',
        details: { email, reason: 'invalid_password' },
        req,
      });
      res.status(HTTP_STATUS.UNAUTHORIZED).json({
        success: false,
        error: {
          code: ERROR_CODES.INVALID_CREDENTIALS,
          message: 'Invalid email or password',
        },
      });
      return;
    }

    // Get user's workspaces
    const workspacesResult = await pool.query(
      `SELECT w.id, w.name, wm.role
       FROM workspaces w
       JOIN workspace_memberships wm ON w.id = wm.workspace_id
       WHERE wm.user_id = $1 AND w.archived_at IS NULL
       ORDER BY w.name`,
      [user.id]
    );

    const workspaces = workspacesResult.rows;

    // Determine which workspace to log into
    let workspaceId: string | null = null;

    if (user.last_workspace_id) {
      // Check if last workspace is still accessible
      const lastWorkspaceValid = workspaces.some(w => w.id === user.last_workspace_id);
      if (lastWorkspaceValid) {
        workspaceId = user.last_workspace_id;
      }
    }

    // If no valid last workspace, use first available
    if (!workspaceId && workspaces.length > 0) {
      workspaceId = workspaces[0].id;
    }

    // Super-admins can log in even without workspace membership
    // They'll need to select a workspace after login
    if (!workspaceId && !user.is_super_admin && workspaces.length === 0) {
      await logAuditEvent({
        actorUserId: user.id,
        action: 'auth.login_failed',
        details: { email, reason: 'no_workspace_access' },
        req,
      });
      res.status(HTTP_STATUS.FORBIDDEN).json({
        success: false,
        error: {
          code: ERROR_CODES.FORBIDDEN,
          message: 'You do not have access to any workspaces',
        },
      });
      return;
    }

    // Session fixation prevention: Delete any existing session from this request
    const oldSessionId = req.cookies.session_id;
    if (oldSessionId) {
      await pool.query('DELETE FROM sessions WHERE id = $1', [oldSessionId]);
    }

    // Create NEW session with cryptographically secure ID
    const sessionId = generateSecureSessionId();
    const expiresAt = new Date(Date.now() + SESSION_TIMEOUT_MS);

    // Store session with binding data (user_agent, ip_address for audit)
    await pool.query(
      `INSERT INTO sessions (id, user_id, workspace_id, expires_at, last_activity, user_agent, ip_address)
       VALUES ($1, $2, $3, $4, $5, $6, $7)`,
      [
        sessionId,
        user.id,
        workspaceId,
        expiresAt,
        new Date(),
        req.headers['user-agent'] || 'unknown',
        req.ip || req.socket.remoteAddress || 'unknown',
      ]
    );

    // Update last_workspace_id
    if (workspaceId) {
      await pool.query(
        'UPDATE users SET last_workspace_id = $1, updated_at = NOW() WHERE id = $2',
        [workspaceId, user.id]
      );
    }

    await logAuditEvent({
      workspaceId: workspaceId || undefined,
      actorUserId: user.id,
      action: 'auth.login',
      req,
    });

    // Pending accountability items will be fetched via /api/accountability/action-items
    const pendingAccountabilityItems: any[] = [];

    // Set cookie with hardened security options
    res.cookie('session_id', sessionId, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict', // Strict for government applications
      maxAge: SESSION_TIMEOUT_MS,
      path: '/',
    });

    res.json({
      success: true,
      data: {
        user: {
          id: user.id,
          email: user.email,
          name: user.name,
          isSuperAdmin: user.is_super_admin,
        },
        currentWorkspace: workspaceId ? {
          id: workspaceId,
          name: workspaces.find(w => w.id === workspaceId)?.name,
          role: workspaces.find(w => w.id === workspaceId)?.role,
        } : null,
        workspaces: workspaces.map(w => ({
          id: w.id,
          name: w.name,
          role: w.role,
        })),
        pendingAccountabilityItems,
      },
    });
  } catch (error) {
    console.error('Login error:', error);
    res.status(HTTP_STATUS.INTERNAL_SERVER_ERROR).json({
      success: false,
      error: {
        code: ERROR_CODES.INTERNAL_ERROR,
        message: 'Login failed',
      },
    });
  }
});

