// autoCompleteAccountabilityIssue have been removed. Accountability is now
// computed via inference using checkMissingAccountability() - no issues are
// created or completed.

/**
 * Business Day Calculator
 *
 * Calculates business days excluding weekends and federal holidays.
 * Uses OPM-defined federal holiday schedules for 2025 and 2026.
 */

// Federal holidays follow OPM rules:
// - If holiday falls on Saturday, observed on Friday
// - If holiday falls on Sunday, observed on Monday

const FEDERAL_HOLIDAYS_2025: string[] = [
  '2025-01-01', // New Year's Day
  '2025-01-20', // Martin Luther King Jr. Day
  '2025-02-17', // Presidents' Day
  '2025-05-26', // Memorial Day
  '2025-06-19', // Juneteenth
  '2025-07-04', // Independence Day
  '2025-09-01', // Labor Day
  '2025-10-13', // Columbus Day
  '2025-11-11', // Veterans Day
  '2025-11-27', // Thanksgiving Day
  '2025-12-25', // Christmas Day
];

const FEDERAL_HOLIDAYS_2026: string[] = [
  '2026-01-01', // New Year's Day
  '2026-01-19', // Martin Luther King Jr. Day
  '2026-02-16', // Presidents' Day
  '2026-05-25', // Memorial Day
  '2026-06-19', // Juneteenth
  '2026-07-03', // Independence Day (observed - July 4 is Saturday)
  '2026-09-07', // Labor Day
  '2026-10-12', // Columbus Day
  '2026-11-11', // Veterans Day
  '2026-11-26', // Thanksgiving Day
  '2026-12-25', // Christmas Day
];

// Combined set for quick lookup
const FEDERAL_HOLIDAYS = new Set([
  ...FEDERAL_HOLIDAYS_2025,
  ...FEDERAL_HOLIDAYS_2026,
]);

/**
 * Parse an ISO date string to a Date object in UTC
 */
function parseDate(dateStr: string): Date {
  const parts = dateStr.split('-');
  const year = Number(parts[0]);
  const month = Number(parts[1]);
  const day = Number(parts[2]);
  return new Date(Date.UTC(year, month - 1, day));
}

/**
 * Format a Date object to ISO date string (YYYY-MM-DD)
 */
function formatDate(date: Date): string {
  const year = date.getUTCFullYear();
  const month = String(date.getUTCMonth() + 1).padStart(2, '0');
  const day = String(date.getUTCDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
}

/**
 * Check if a date is a weekend (Saturday or Sunday)
 */
function isWeekend(date: Date): boolean {
  const day = date.getUTCDay();
  return day === 0 || day === 6; // Sunday = 0, Saturday = 6
}

/**
 * Check if a date is a federal holiday
 */
function isFederalHoliday(dateStr: string): boolean {
  return FEDERAL_HOLIDAYS.has(dateStr);
}

/**
 * Check if a date is a business day (not weekend, not federal holiday)
 *
 * @param dateStr - ISO date string (YYYY-MM-DD)
 * @returns true if the date is a business day
 */
export function isBusinessDay(dateStr: string): boolean {
  const date = parseDate(dateStr);

  if (isWeekend(date)) {
    return false;
  }

  if (isFederalHoliday(dateStr)) {
    return false;
  }

  return true;
}

/**
 * Get the next business day from a given date
 * If the given date is a business day, returns the next business day after it
 *
 * @param dateStr - ISO date string (YYYY-MM-DD)
 * @returns ISO date string of the next business day
 */
export function getNextBusinessDay(dateStr: string): string {
  let date = parseDate(dateStr);

  // Move to the next day
  date.setUTCDate(date.getUTCDate() + 1);
  let currentDateStr = formatDate(date);

  // Keep moving forward until we find a business day
  while (!isBusinessDay(currentDateStr)) {
    date.setUTCDate(date.getUTCDate() + 1);
    currentDateStr = formatDate(date);
  }

  return currentDateStr;
}

/**
 * Add a number of business days to a date
 *
 * @param dateStr - ISO date string (YYYY-MM-DD) starting date
 * @param days - Number of business days to add (positive or negative)
 * @returns ISO date string of the resulting date
 */
export function addBusinessDays(dateStr: string, days: number): string {
  if (days === 0) {
    return dateStr;
  }

  let date = parseDate(dateStr);
  const direction = days > 0 ? 1 : -1;
  let remaining = Math.abs(days);

  while (remaining > 0) {
    date.setUTCDate(date.getUTCDate() + direction);
    const currentDateStr = formatDate(date);

    if (isBusinessDay(currentDateStr)) {
      remaining--;
    }
  }

  return formatDate(date);
}

/**
 * Count business days between two dates (exclusive of start, inclusive of end)
 *
 * @param startDateStr - ISO date string (YYYY-MM-DD) start date
 * @param endDateStr - ISO date string (YYYY-MM-DD) end date
 * @returns Number of business days between the dates
 */
export function businessDaysBetween(startDateStr: string, endDateStr: string): number {
  const startDate = parseDate(startDateStr);
  const endDate = parseDate(endDateStr);

  // Determine direction
  const forward = endDate >= startDate;
  const direction = forward ? 1 : -1;

  let count = 0;
  let current = new Date(startDate);

  while (true) {
    current.setUTCDate(current.getUTCDate() + direction);
    const currentDateStr = formatDate(current);

    if (forward) {
      if (current > endDate) break;
    } else {
      if (current < endDate) break;
    }

    if (isBusinessDay(currentDateStr)) {
      count++;
    }
  }

  return forward ? count : -count;
}

/**
 * Get the list of federal holidays for a given year
 *
 * @param year - The year to get holidays for
 * @returns Array of ISO date strings for federal holidays
 */
export function getFederalHolidays(year: number): string[] {
  if (year === 2025) {
    return [...FEDERAL_HOLIDAYS_2025];
  }
  if (year === 2026) {
    return [...FEDERAL_HOLIDAYS_2026];
  }
  // Return empty for unsupported years - caller should handle gracefully
  return [];
}

import { spawnSync } from 'node:child_process';
import { readFileSync } from 'node:fs';
import { createRequire } from 'node:module';
import { dirname, resolve } from 'node:path';

const require = createRequire(import.meta.url);

function packageBin(packageName, binName) {
  const packageJsonPath = require.resolve(`${packageName}/package.json`);
  const packageJson = JSON.parse(readFileSync(packageJsonPath, 'utf-8'));
  const bin = typeof packageJson.bin === 'string'
    ? packageJson.bin
    : packageJson.bin?.[binName];

  if (!bin) {
    throw new Error(`Could not find ${binName} binary in ${packageName}`);
  }

  return resolve(dirname(packageJsonPath), bin);
}

function run(command, args, options = {}) {
  const result = spawnSync(command, args, {
    stdio: 'inherit',
    ...options,
  });

  if (result.error) {
    console.error(result.error);
    process.exit(1);
  }

  if (result.status !== 0) {
    process.exit(result.status ?? 1);
  }
}

run(process.execPath, [packageBin('typescript', 'tsc')]);
run(process.execPath, [packageBin('vite', 'vite'), 'build'], {
  env: {
    ...process.env,
    VITE_API_URL: '',
  },
});

import { useState, useEffect, useRef, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { cn } from '@/lib/cn';
import { formatDateRange } from '@/lib/date-utils';

const API_URL = import.meta.env.VITE_API_URL ?? '';

interface Sprint {
  number: number;
  name: string;
  startDate: string;
  endDate: string;
  isCurrent: boolean;
}

interface ApprovalState {
  state: 'approved' | 'changed_since_approved' | null;
}

interface SprintAccountability {
  id: string;
  title: string;
  hasPlan: boolean;
  planApproval: ApprovalState | null;
  hasReview: boolean;
  reviewApproval: ApprovalState | null;
}

interface ProjectData {
  id: string;
  title: string;
  color: string;
  emoji?: string | null;
  programId?: string | null;
  programName?: string | null;
  programColor?: string | null;
  programEmoji?: string | null;
  hasPlan: boolean;
  planApproval: ApprovalState | null;
  hasRetro: boolean;
  retroApproval: ApprovalState | null;
  allocations: Record<number, number>; // sprintNumber -> personCount
}

interface AccountabilityGridData {
  weeks: Sprint[];
  currentSprintNumber: number;
  sprintAccountability: Record<number, SprintAccountability>;
  projects: ProjectData[];
}

// Group projects by program
interface ProgramGroup {
  programId: string | null;
  programName: string;
  programColor: string | null;
  programEmoji: string | null;
  projects: ProjectData[];
}

interface AccountabilityGridProps {
  showArchived?: boolean;
}

export function AccountabilityGrid({ showArchived = false }: AccountabilityGridProps) {
  const navigate = useNavigate();
  const [data, setData] = useState<AccountabilityGridData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [expandedProjectId, setExpandedProjectId] = useState<string | null>(null);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const hasScrolledToCurrentRef = useRef(false);

  useEffect(() => {
    async function fetchData() {
      try {
        const params = new URLSearchParams();
        if (showArchived) params.set('includeArchived', 'true');
        const url = `${API_URL}/api/team/accountability-grid${params.toString() ? `?${params}` : ''}`;
        const res = await fetch(url, { credentials: 'include' });
        if (!res.ok) {
          if (res.status === 403) {
            setError('Admin access required to view accountability grid');
          } else {
            setError('Failed to load accountability data');
          }
          return;
        }
        const json = await res.json();
        setData(json);
      } catch (err) {
        setError('Failed to load accountability data');
      } finally {
        setLoading(false);
      }
    }

    fetchData();
  }, [showArchived]);

  // Scroll to current sprint on initial load
  useEffect(() => {
    if (data && scrollContainerRef.current && !hasScrolledToCurrentRef.current) {
      const currentSprintIndex = data.weeks.findIndex(s => s.isCurrent);
      if (currentSprintIndex >= 0) {
        requestAnimationFrame(() => {
          if (scrollContainerRef.current) {
            const columnWidth = 140;
            const scrollPosition = Math.max(0, (currentSprintIndex - 1) * columnWidth);
            scrollContainerRef.current.scrollLeft = scrollPosition;
            hasScrolledToCurrentRef.current = true;
          }
        });
      }
    }
  }, [data]);

  // Group projects by program
  const programGroups = useMemo((): ProgramGroup[] => {
    if (!data) return [];

    const groups: Map<string, ProgramGroup> = new Map();
    const UNASSIGNED_KEY = '__unassigned__';

    for (const project of data.projects) {
      const groupKey = project.programId || UNASSIGNED_KEY;

      if (!groups.has(groupKey)) {
        groups.set(groupKey, {
          programId: project.programId || null,
          programName: project.programName || 'No Program',
          programColor: project.programColor || null,
          programEmoji: project.programEmoji || null,
          projects: [],
        });
      }

      groups.get(groupKey)!.projects.push(project);
    }

    // Sort groups alphabetically, with "No Program" last
    return Array.from(groups.values()).sort((a, b) => {
      if (a.programId === null) return 1;
      if (b.programId === null) return -1;
      return a.programName.localeCompare(b.programName);
    });
  }, [data]);

  if (loading) {
    return (
      <div className="flex flex-1 items-center justify-center">
        <span className="text-sm text-muted">Loading accountability grid...</span>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-1 items-center justify-center">
        <span className="text-sm text-red-500">{error}</span>
      </div>
    );
  }

  if (!data) return null;

  return (
    <div
      ref={scrollContainerRef}
      className="flex-1 overflow-auto pb-20"
    >
      <div className="inline-flex min-w-full">
        {/* Sticky left column - Sprint info */}
        <div className="flex flex-col sticky left-0 z-20 bg-background border-r border-border">
          {/* Header cell */}
          <div className="flex h-10 w-[180px] items-center justify-center border-b border-border px-3 sticky top-0 z-30 bg-background">
            <span className="text-xs font-medium text-muted">Week Accountability</span>
          </div>

          {/* Legend row */}
          <div className="flex h-10 w-[180px] items-center gap-2 border-b border-border px-3 bg-border/20">
            <div className="flex items-center gap-1">
              <span className="text-[10px] text-muted">P</span>
              <span className="text-[10px] text-muted">=</span>
              <span className="text-[10px] text-muted">Plan</span>
            </div>
            <div className="flex items-center gap-1">
              <span className="text-[10px] text-muted">R</span>
              <span className="text-[10px] text-muted">=</span>
              <span className="text-[10px] text-muted">Review</span>
            </div>
          </div>

          {/* Program group headers with projects */}
          {programGroups.map((group) => (
            <div key={group.programId || '__unassigned__'}>
              {/* Program header */}
              <div className="flex h-8 w-[180px] items-center gap-2 border-b border-border bg-border/30 px-3">
                {group.programId ? (
                  <span
                    className="shrink-0 rounded px-1.5 py-0.5 text-[10px] font-bold text-white"
                    style={{ backgroundColor: group.programColor || '#6b7280' }}
                  >
                    {group.programEmoji || group.programName[0]}
                  </span>
                ) : (
                  <span className="shrink-0 rounded px-1.5 py-0.5 text-[10px] font-bold text-white bg-gray-500">
                    ?
                  </span>
                )}
                <span className="truncate text-xs font-medium text-foreground">
                  {group.programName}
                </span>
                <span className="ml-auto text-[10px] text-muted">
                  {group.projects.length}
                </span>
              </div>

              {/* Project timeline lines (thin collapsed state) */}
              {group.projects.map((project) => {
                const isExpanded = expandedProjectId === project.id;
                return (
                  <div
                    key={project.id}
                    className={cn(
                      "flex w-[180px] items-center border-b border-border px-3 cursor-pointer transition-all duration-200",
                      isExpanded ? "h-10 bg-background" : "h-2"
                    )}
                    style={{
                      backgroundColor: isExpanded ? undefined : project.color,
                      opacity: isExpanded ? 1 : 0.6,
                    }}
                    onMouseEnter={() => setExpandedProjectId(project.id)}
                    onMouseLeave={() => setExpandedProjectId(null)}
                    onClick={() => navigate(`/documents/${project.id}`)}
                    title={project.title}
                  >
                    {isExpanded && (
                      <div className="flex items-center gap-2 overflow-hidden w-full">
                        <div
                          className="h-3 w-3 rounded-sm flex-shrink-0"
                          style={{ backgroundColor: project.color }}
                        />
                        <span className="truncate text-xs font-medium text-foreground">
                          {project.title}
                        </span>
                        <div className="ml-auto flex items-center gap-1">
                          {/* Plan status */}
                          <StatusIndicator
                            hasContent={project.hasPlan}
                            approvalState={project.planApproval?.state}
                            label="P"
                          />
                          {/* Retro status */}
                          <StatusIndicator
                            hasContent={project.hasRetro}
                            approvalState={project.retroApproval?.state}
                            label="R"
                          />
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          ))}
        </div>

        {/* Sprint columns */}
        <div className="flex">
          {data.weeks.map((sprint) => {
            const accountability = data.sprintAccountability[sprint.number];

            return (
              <div key={sprint.number} className="flex flex-col">
                {/* Sprint header */}
                <div
                  className={cn(
                    'flex h-10 w-[140px] flex-col items-center justify-center border-b border-r border-border px-2 sticky top-0 z-10 bg-background',
                    sprint.isCurrent && 'ring-1 ring-inset ring-accent/30'
                  )}
                >
                  <span className={cn(
                    'text-xs font-medium',
                    sprint.isCurrent ? 'text-accent' : 'text-foreground'
                  )}>
                    {sprint.name}
                  </span>
                  <span className="text-[10px] text-muted">
                    {formatDateRange(sprint.startDate, sprint.endDate)}
                  </span>
                </div>

                {/* Sprint accountability cell - LEFT half hypothesis, RIGHT half review */}
                <SprintAccountabilityCell
                  accountability={accountability}
                  isCurrent={sprint.isCurrent}
                  onNavigate={(id) => navigate(`/documents/${id}`)}
                />

                {/* Program groups with project allocation cells */}
                {programGroups.map((group) => (
                  <div key={group.programId || '__unassigned__'}>
                    {/* Program header spacer */}
                    <div
                      className={cn(
                        "h-8 w-[140px] border-b border-r border-border bg-border/30",
                        sprint.isCurrent && "bg-accent/5"
                      )}
                    />

                    {/* Project allocation cells */}
                    {group.projects.map((project) => {
                      const isExpanded = expandedProjectId === project.id;
                      const allocationCount = project.allocations[sprint.number] || 0;
                      const hasAllocation = allocationCount > 0;

                      return (
                        <div
                          key={project.id}
                          className={cn(
                            "w-[140px] border-b border-r border-border cursor-pointer transition-all duration-200",
                            isExpanded ? "h-10" : "h-2",
                            sprint.isCurrent && "bg-accent/5"
                          )}
                          style={{
                            backgroundColor: isExpanded
                              ? undefined
                              : hasAllocation
                              ? project.color
                              : 'transparent',
                            opacity: isExpanded ? 1 : hasAllocation ? 0.6 : 1,
                          }}
                          onMouseEnter={() => setExpandedProjectId(project.id)}
                          onMouseLeave={() => setExpandedProjectId(null)}
                          onClick={() => navigate(`/documents/${project.id}`)}
                        >
                          {isExpanded && (
                            <div className="flex items-center justify-center h-full px-2">
                              {hasAllocation ? (
                                <span
                                  className="text-xs font-medium px-2 py-0.5 rounded"
                                  style={{ backgroundColor: project.color, color: 'white' }}
                                >
                                  {allocationCount} {allocationCount === 1 ? 'person' : 'people'}
                                </span>
                              ) : (
                                <span className="text-[10px] text-muted">-</span>
                              )}
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                ))}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

// Sprint accountability cell with left/right split for plan/review
function SprintAccountabilityCell({
  accountability,
  isCurrent,
  onNavigate,
}: {
  accountability?: SprintAccountability;
  isCurrent: boolean;
  onNavigate: (id: string) => void;
}) {
  if (!accountability) {
    // No week document for this week number yet
    return (
      <div
        className={cn(
          "flex h-10 w-[140px] items-center justify-center border-b border-r border-border",
          isCurrent && "bg-accent/5"
        )}
      >
        <span className="text-[10px] text-muted">No week</span>
      </div>
    );
  }

  // Determine border color based on approval states
  const planApprovalState = accountability.planApproval?.state;
  const reviewApprovalState = accountability.reviewApproval?.state;

  // Border priority: yellow (changed) > green (approved) > none
  let borderClass = '';
  if (planApprovalState === 'changed_since_approved' || reviewApprovalState === 'changed_since_approved') {
    borderClass = 'ring-2 ring-yellow-500';
  } else if (planApprovalState === 'approved' && reviewApprovalState === 'approved') {
    borderClass = 'ring-2 ring-green-500';
  } else if (planApprovalState === 'approved' || reviewApprovalState === 'approved') {
    borderClass = 'ring-1 ring-green-500/50';
  }

  return (
    <div
      className={cn(
        "flex h-10 w-[140px] items-stretch border-b border-r border-border cursor-pointer hover:bg-border/20",
        isCurrent && "bg-accent/5",
        borderClass
      )}
      onClick={() => onNavigate(accountability.id)}
      title={`${accountability.title}\nClick to open week`}
    >
      {/* Left half - Plan */}
      <div className="flex-1 flex flex-col items-center justify-center border-r border-border/50">
        <span className="text-[9px] text-muted mb-0.5">P</span>
        <StatusIcon
          hasContent={accountability.hasPlan}
          approvalState={planApprovalState}
        />
      </div>

      {/* Right half - Review */}
      <div className="flex-1 flex flex-col items-center justify-center">
        <span className="text-[9px] text-muted mb-0.5">R</span>
        <StatusIcon
          hasContent={accountability.hasReview}
          approvalState={reviewApprovalState}
        />
      </div>
    </div>
  );
}

// Status indicator for expanded project rows
function StatusIndicator({
  hasContent,
  approvalState,
  label,
}: {
  hasContent: boolean;
  approvalState?: 'approved' | 'changed_since_approved' | null;
  label: string;
}) {
  const bgColor = hasContent
    ? approvalState === 'approved'
      ? 'bg-green-500'
      : approvalState === 'changed_since_approved'
      ? 'bg-yellow-500'
      : 'bg-blue-500'
    : 'bg-gray-400';

  return (
    <div
      className={cn(
        "flex items-center justify-center h-4 w-4 rounded text-[8px] font-bold text-white",
        bgColor
      )}
      title={`${label === 'P' ? 'Plan' : label === 'R' ? 'Review/Retro' : label}: ${
        !hasContent ? 'Not written' :
        approvalState === 'approved' ? 'Approved' :
        approvalState === 'changed_since_approved' ? 'Changed since approved' :
        'Written (pending approval)'
      }`}
    >
      {hasContent ? (
        approvalState === 'approved' ? '✓' :
        approvalState === 'changed_since_approved' ? '!' :
        '●'
      ) : (
        '○'
      )}
    </div>
  );
}

// Status icon for sprint cells
function StatusIcon({
  hasContent,
  approvalState,
}: {
  hasContent: boolean;
  approvalState?: 'approved' | 'changed_since_approved' | null;
}) {
  if (!hasContent) {
    return (
      <svg className="h-4 w-4 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <circle cx="12" cy="12" r="8" strokeWidth="2" />
      </svg>
    );
  }

  if (approvalState === 'approved') {
    return (
      <svg className="h-4 w-4 text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" />
      </svg>
    );
  }

  if (approvalState === 'changed_since_approved') {
    return (
      <svg className="h-4 w-4 text-yellow-500" fill="currentColor" viewBox="0 0 24 24">
        <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z" />
      </svg>
    );
  }

  // Written but not approved
  return (
    <svg className="h-4 w-4 text-blue-500" fill="currentColor" viewBox="0 0 24 24">
      <circle cx="12" cy="12" r="8" />
    </svg>
  );
}

export default AccountabilityGrid;

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { cn } from '@/lib/cn';
import { useActionItemsQuery, ActionItem } from '@/hooks/useActionItemsQuery';
import {
  ACCOUNTABILITY_TYPE_LABELS,
  createOrGetWeeklyDocumentId,
  formatActionItemDueDate,
  getWeeklyDocumentKindForAccountabilityType,
} from '@/lib/accountability';

const ACCOUNTABILITY_TYPE_ICONS: Record<string, React.ReactNode> = {
  standup: (
    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
    </svg>
  ),
  weekly_plan: (
    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
    </svg>
  ),
  weekly_review: (
    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
    </svg>
  ),
  week_start: (
    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
    </svg>
  ),
  week_issues: (
    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
    </svg>
  ),
  project_plan: (
    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
    </svg>
  ),
  project_retro: (
    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
    </svg>
  ),
};

function ActionItemRow({ item }: { item: ActionItem }) {
  const navigate = useNavigate();
  const [navigating, setNavigating] = useState(false);
  const typeLabel = item.accountability_type
    ? ACCOUNTABILITY_TYPE_LABELS[item.accountability_type] || item.accountability_type
    : 'Action Item';
  const icon = item.accountability_type
    ? ACCOUNTABILITY_TYPE_ICONS[item.accountability_type]
    : null;
  const { text: dueText, isOverdue } = formatActionItemDueDate(item.due_date, item.days_overdue);

  const handleClick = async (e: React.MouseEvent) => {
    e.preventDefault();

    // For weekly plan/retro types, create/find the actual document before navigating
    const weeklyDocKind = getWeeklyDocumentKindForAccountabilityType(item.accountability_type);
    if (weeklyDocKind && item.person_id && item.week_number != null) {
      setNavigating(true);
      try {
        const documentId = await createOrGetWeeklyDocumentId({
          kind: weeklyDocKind,
          personId: item.person_id,
          projectId: item.project_id || undefined,
          weekNumber: item.week_number,
        });
        if (documentId) {
          navigate(`/documents/${documentId}`);
          return;
        }
      } catch { /* fall through to default */ }
      finally { setNavigating(false); }
    }

    // For standup items, use the deep link
    if (item.accountability_type === 'standup' && item.accountability_target_id) {
      navigate(`/documents/${item.accountability_target_id}?action=new-standup`);
      return;
    }

    // Default: navigate to the target document
    const targetUrl = item.accountability_target_id
      ? `/documents/${item.accountability_target_id}`
      : `/documents/${item.id}`;
    navigate(targetUrl);
  };

  return (
    <a
      href="#"
      onClick={handleClick}
      className={cn(
        "flex items-center gap-3 px-4 py-3 hover:bg-background/80 transition-colors",
        navigating && "opacity-50 pointer-events-none"
      )}
    >
      {/* Type icon */}
      <span className={cn(
        'flex items-center justify-center h-8 w-8 rounded-full flex-shrink-0',
        isOverdue ? 'bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400' : 'bg-amber-100 text-amber-600 dark:bg-amber-900/30 dark:text-amber-400'
      )}>
        {icon}
      </span>

      {/* Item info */}
      <div className="min-w-0 flex-1">
        <div className="flex items-center gap-2">
          <span className="text-xs font-medium text-muted uppercase tracking-wide">{typeLabel}</span>
          {item.target_title && (
            <>
              <span className="text-muted">&middot;</span>
              <span className="text-xs text-muted truncate">{item.target_title}</span>
            </>
          )}
        </div>
        <p className="truncate text-sm text-foreground mt-0.5">{item.title}</p>
      </div>

      {/* Due date */}
      <span className={cn(
        'text-xs whitespace-nowrap',
        isOverdue ? 'text-red-600 font-medium dark:text-red-400' : 'text-muted'
      )}>
        {dueText}
      </span>

      {/* Arrow indicator */}
      <svg className="w-4 h-4 text-muted flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
      </svg>
    </a>
  );
}

export function ActionItems() {
  const { data, isLoading, error } = useActionItemsQuery();

  if (isLoading) {
    return (
      <div className="rounded-lg border border-amber-500/30 bg-amber-500/10 p-6">
        <div className="flex items-center gap-2 text-amber-600 dark:text-amber-400">
          <svg className="w-5 h-5 animate-spin" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <span className="text-sm font-medium">Loading action items...</span>
        </div>
      </div>
    );
  }

  if (error) {
    return null; // Silently fail if action items can't be loaded
  }

  if (!data?.items || data.items.length === 0) {
    return null; // Don't show section if no action items
  }

  const overdueCount = data.items.filter(item => item.days_overdue >= 0).length;

  return (
    <div className="rounded-lg border border-amber-500/30 bg-amber-500/10 overflow-hidden">
      {/* Header */}
      <div className="flex items-center justify-between px-4 py-3 border-b border-amber-500/20 bg-amber-500/5">
        <div className="flex items-center gap-2">
          <svg className="w-5 h-5 text-amber-600 dark:text-amber-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
          </svg>
          <h2 className="text-sm font-semibold text-amber-700 dark:text-amber-300">
            Action Items
          </h2>
          <span className="px-2 py-0.5 text-xs font-medium rounded-full bg-amber-700 text-white">
            {data.items.length}
          </span>
        </div>
        {overdueCount > 0 && (
          <span className="text-xs font-medium text-red-600 dark:text-red-400">
            {overdueCount} due/overdue
          </span>
        )}
      </div>

      {/* Items list */}
      <div className="divide-y divide-amber-500/20 bg-background">
        {data.items.map((item) => (
          <ActionItemRow key={item.id} item={item} />
        ))}
      </div>
    </div>
  );
}

export default ActionItems;

