import { useState, useEffect, useCallback } from 'react';
import { useEditor, EditorContent, JSONContent } from '@tiptap/react';
import StarterKit from '@tiptap/starter-kit';
import Placeholder from '@tiptap/extension-placeholder';
import { cn } from '@/lib/cn';
import { useToast } from '@/components/ui/Toast';
import { apiPost, apiPatch, apiGet } from '@/lib/api';

interface ProjectRetroProps {
  projectId: string;
}

interface RetroData {
  is_draft: boolean;
  plan_validated: boolean | null;
  monetary_impact_expected: string | null;
  monetary_impact_actual: string | null;
  success_criteria: string[];
  next_steps: string | null;
  content: JSONContent;
  weeks: { id: string; title: string; sprint_number: string }[];
  issues_summary: {
    total: number;
    completed: number;
    cancelled: number;
    active: number;
  };
}

export function ProjectRetro({ projectId }: ProjectRetroProps) {
  const [retroData, setRetroData] = useState<RetroData | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [planValidated, setPlanValidated] = useState<boolean | null>(null);
  const [monetaryImpactActual, setMonetaryImpactActual] = useState('');
  const [successCriteria, setSuccessCriteria] = useState<string[]>([]);
  const [newCriterion, setNewCriterion] = useState('');
  const [isDirty, setIsDirty] = useState(false);
  const { showToast } = useToast();

  const editor = useEditor({
    extensions: [
      StarterKit,
      Placeholder.configure({
        placeholder: 'Write your project retrospective...',
      }),
    ],
    content: '',
    onUpdate: () => {
      setIsDirty(true);
    },
  });

  const fetchRetro = useCallback(async () => {
    try {
      const res = await apiGet(`/api/projects/${projectId}/retro`);
      if (res.ok) {
        const data: RetroData = await res.json();
        setRetroData(data);
        setPlanValidated(data.plan_validated ?? null);
        setMonetaryImpactActual(data.monetary_impact_actual || '');
        setSuccessCriteria(data.success_criteria || []);
        if (editor && data.content) {
          editor.commands.setContent(data.content);
        }
      } else {
        showToast('Failed to load project retrospective', 'error');
      }
    } catch (err) {
      console.error('Failed to fetch project retro:', err);
      showToast('Failed to load project retrospective. Please try again.', 'error');
    } finally {
      setLoading(false);
    }
  }, [projectId, editor, showToast]);

  useEffect(() => {
    if (editor) {
      fetchRetro();
    }
  }, [fetchRetro, editor]);

  const handleSave = async () => {
    if (!editor) return;

    setSaving(true);
    try {
      const content = editor.getJSON();

      if (retroData?.is_draft) {
        // POST to create new retro
        const res = await apiPost(`/api/projects/${projectId}/retro`, {
          content,
          plan_validated: planValidated,
          monetary_impact_actual: monetaryImpactActual || null,
          success_criteria: successCriteria,
        });
        if (res.ok) {
          const data = await res.json();
          setRetroData({ ...retroData, ...data, is_draft: false });
          setIsDirty(false);
          showToast('Project retrospective saved', 'success');
        } else {
          const data = await res.json().catch(() => ({}));
          showToast(data.error || 'Failed to save project retrospective', 'error');
        }
      } else {
        // PATCH to update existing retro
        const res = await apiPatch(`/api/projects/${projectId}/retro`, {
          content,
          plan_validated: planValidated,
          monetary_impact_actual: monetaryImpactActual || null,
          success_criteria: successCriteria,
        });
        if (res.ok) {
          setIsDirty(false);
          showToast('Project retrospective updated', 'success');
        } else {
          const data = await res.json().catch(() => ({}));
          showToast(data.error || 'Failed to update project retrospective', 'error');
        }
      }
    } catch (err) {
      console.error('Failed to save project retro:', err);
      showToast('Failed to save project retrospective. Please try again.', 'error');
    } finally {
      setSaving(false);
    }
  };

  const handleAddCriterion = () => {
    if (!newCriterion.trim()) return;
    setSuccessCriteria([...successCriteria, newCriterion.trim()]);
    setNewCriterion('');
    setIsDirty(true);
  };

  const handleRemoveCriterion = (index: number) => {
    setSuccessCriteria(successCriteria.filter((_, i) => i !== index));
    setIsDirty(true);
  };

  if (loading) {
    return (
      <div className="flex h-64 items-center justify-center">
        <div className="text-muted">Loading retrospective...</div>
      </div>
    );
  }

  return (
    <div className="flex h-full flex-col">
      {/* Retro content */}
      <div className="flex-1 overflow-auto">
        <div className="flex h-full">
          {/* Editor area */}
          <div className="flex-1 px-6 py-4">
            {retroData?.is_draft && (
              <div className="mb-4 rounded-md border border-yellow-500/50 bg-yellow-500/10 px-4 py-2 text-sm text-yellow-600">
                This is a pre-filled draft. Edit and save to finalize your project retrospective.
              </div>
            )}

            {/* Issues Summary */}
            {retroData?.issues_summary && (
              <div className="mb-4 grid grid-cols-4 gap-3">
                <div className="rounded-md border border-border bg-background p-3 text-center">
                  <div className="text-2xl font-bold text-foreground">{retroData.issues_summary.total}</div>
                  <div className="text-xs text-muted">Total Issues</div>
                </div>
                <div className="rounded-md border border-border bg-background p-3 text-center">
                  <div className="text-2xl font-bold text-green-600">{retroData.issues_summary.completed}</div>
                  <div className="text-xs text-muted">Completed</div>
                </div>
                <div className="rounded-md border border-border bg-background p-3 text-center">
                  <div className="text-2xl font-bold text-yellow-600">{retroData.issues_summary.active}</div>
                  <div className="text-xs text-muted">Active</div>
                </div>
                <div className="rounded-md border border-border bg-background p-3 text-center">
                  <div className="text-2xl font-bold text-red-600">{retroData.issues_summary.cancelled}</div>
                  <div className="text-xs text-muted">Cancelled</div>
                </div>
              </div>
            )}

            <div className="prose prose-sm max-w-none">
              <EditorContent
                editor={editor}
                className="min-h-[400px] rounded-lg border border-border bg-background p-4 focus-within:border-accent focus-within:ring-1 focus-within:ring-accent [&_.ProseMirror]:outline-none [&_.ProseMirror]:min-h-[350px]"
              />
            </div>
          </div>

          {/* Properties sidebar */}
          <div className="w-72 border-l border-border p-4 overflow-y-auto">
            <h3 className="text-sm font-medium text-foreground mb-4">Retrospective Properties</h3>

            {/* Plan Validation */}
            <div className="space-y-2 mb-6">
              <label className="text-xs font-medium text-muted uppercase tracking-wide">
                Plan Validation
              </label>
              <div className="flex flex-col gap-2">
                <button
                  onClick={() => {
                    setPlanValidated(true);
                    setIsDirty(true);
                  }}
                  className={cn(
                    'flex items-center gap-2 rounded-md px-3 py-2 text-sm font-medium transition-colors',
                    planValidated === true
                      ? 'bg-green-500/20 text-green-600 border border-green-500'
                      : 'bg-border/50 text-muted hover:bg-border'
                  )}
                >
                  <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                  </svg>
                  Validated
                </button>
                <button
                  onClick={() => {
                    setPlanValidated(false);
                    setIsDirty(true);
                  }}
                  className={cn(
                    'flex items-center gap-2 rounded-md px-3 py-2 text-sm font-medium transition-colors',
                    planValidated === false
                      ? 'bg-red-500/20 text-red-600 border border-red-500'
                      : 'bg-border/50 text-muted hover:bg-border'
                  )}
                >
                  <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                  Invalidated
                </button>
                {planValidated !== null && (
                  <button
                    onClick={() => {
                      setPlanValidated(null);
                      setIsDirty(true);
                    }}
                    className="text-xs text-muted hover:text-foreground transition-colors"
                  >
                    Clear selection
                  </button>
                )}
              </div>
            </div>

            {/* Monetary Impact Expected */}
            {retroData?.monetary_impact_expected && (
              <div className="space-y-2 mb-6">
                <label className="text-xs font-medium text-muted uppercase tracking-wide">
                  Expected Impact
                </label>
                <div className="text-sm text-foreground bg-border/30 rounded-md px-3 py-2">
                  {retroData.monetary_impact_expected}
                </div>
              </div>
            )}

            {/* Monetary Impact Actual */}
            <div className="space-y-2 mb-6">
              <label className="text-xs font-medium text-muted uppercase tracking-wide">
                Actual Monetary Impact
              </label>
              <input
                type="text"
                value={monetaryImpactActual}
                onChange={(e) => {
                  setMonetaryImpactActual(e.target.value);
                  setIsDirty(true);
                }}
                placeholder="e.g., Saved $50,000/year"
                className="w-full rounded-md border border-border bg-background px-3 py-2 text-sm text-foreground placeholder:text-muted focus:border-accent focus:outline-none focus:ring-1 focus:ring-accent"
              />
            </div>

            {/* Success Criteria */}
            <div className="space-y-2 mb-6">
              <label className="text-xs font-medium text-muted uppercase tracking-wide">
                Success Criteria
              </label>
              <div className="space-y-2">
                {successCriteria.map((criterion, index) => (
                  <div key={index} className="flex items-center gap-2 group">
                    <svg className="h-4 w-4 text-green-500 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                    </svg>
                    <span className="text-sm text-foreground flex-1">{criterion}</span>
                    <button
                      onClick={() => handleRemoveCriterion(index)}
                      className="opacity-0 group-hover:opacity-100 text-muted hover:text-red-500 transition-all"
                    >
                      <svg className="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                      </svg>
                    </button>
                  </div>
                ))}
                <div className="flex gap-2">
                  <input
                    type="text"
                    value={newCriterion}
                    onChange={(e) => setNewCriterion(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === 'Enter') {
                        e.preventDefault();
                        handleAddCriterion();
                      }
                    }}
                    placeholder="Add criterion..."
                    className="flex-1 rounded-md border border-border bg-background px-3 py-1.5 text-sm text-foreground placeholder:text-muted focus:border-accent focus:outline-none focus:ring-1 focus:ring-accent"
                  />
                  <button
                    onClick={handleAddCriterion}
                    disabled={!newCriterion.trim()}
                    className="rounded-md bg-accent px-2 py-1.5 text-sm text-white hover:bg-accent/90 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    Add
                  </button>
                </div>
              </div>
            </div>

            {/* Sprints */}
            {retroData?.weeks && retroData.weeks.length > 0 && (
              <div className="space-y-2 mb-6">
                <label className="text-xs font-medium text-muted uppercase tracking-wide">
                  Sprints ({retroData.weeks.length})
                </label>
                <div className="space-y-1">
                  {retroData.weeks.map((sprint) => (
                    <div key={sprint.id} className="text-sm text-foreground">
                      Sprint {sprint.sprint_number}: {sprint.title}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Status indicator */}
            <div className="pt-4 border-t border-border">
              <div className="text-xs text-muted">
                {retroData?.is_draft ? (
                  <span className="text-yellow-600">Draft - not yet saved</span>
                ) : (
                  <span className="text-green-600">Saved</span>
                )}
                {isDirty && !retroData?.is_draft && (
                  <span className="text-yellow-600"> (unsaved changes)</span>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Save button footer */}
      <div className="border-t border-border px-6 py-4 flex justify-end gap-2">
        <button
          onClick={handleSave}
          disabled={saving || (!isDirty && !retroData?.is_draft)}
          className="rounded-md bg-accent px-4 py-2 text-sm font-medium text-white hover:bg-accent/90 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {saving ? 'Saving...' : retroData?.is_draft ? 'Save Retrospective' : 'Update Retrospective'}
        </button>
      </div>
    </div>
  );
}

import { useState } from 'react';
import * as Dialog from '@radix-ui/react-dialog';
import { usePrograms, Program } from '@/contexts/ProgramsContext';

interface ProjectSetupWizardProps {
  open: boolean;
  onCancel: () => void;
  onSubmit: (data: ProjectSetupData) => void;
}

export interface ProjectSetupData {
  title: string;
  program_id: string;
  plan?: string;
  target_date?: string;
}

export function ProjectSetupWizard({
  open,
  onCancel,
  onSubmit,
}: ProjectSetupWizardProps) {
  const { programs, loading } = usePrograms();
  const [title, setTitle] = useState('');
  const [programId, setProgramId] = useState('');
  const [plan, setPlan] = useState('');
  const [targetDate, setTargetDate] = useState('');
  const [errors, setErrors] = useState<{ title?: string; program?: string }>({});

  const activePrograms = programs.filter((p: Program) => !p.archived_at);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const newErrors: { title?: string; program?: string } = {};

    if (!title.trim()) {
      newErrors.title = 'Project name is required';
    }

    if (!programId) {
      newErrors.program = 'Please select a program';
    }

    if (Object.keys(newErrors).length > 0) {
      setErrors(newErrors);
      return;
    }

    onSubmit({
      title: title.trim(),
      program_id: programId,
      plan: plan.trim() || undefined,
      target_date: targetDate || undefined,
    });

    // Reset form
    setTitle('');
    setProgramId('');
    setPlan('');
    setTargetDate('');
    setErrors({});
  };

  const handleCancel = () => {
    setTitle('');
    setProgramId('');
    setPlan('');
    setTargetDate('');
    setErrors({});
    onCancel();
  };

  return (
    <Dialog.Root open={open} onOpenChange={(isOpen) => !isOpen && handleCancel()}>
      <Dialog.Portal>
        <Dialog.Overlay className="fixed inset-0 z-[100] bg-black/60" />
        <Dialog.Content
          className="fixed left-1/2 top-1/2 z-[101] w-full max-w-lg -translate-x-1/2 -translate-y-1/2 rounded-lg border border-border bg-background p-6 shadow-xl focus:outline-none"
          onEscapeKeyDown={handleCancel}
        >
          <Dialog.Title className="text-lg font-semibold text-foreground">
            Create New Project
          </Dialog.Title>

          <Dialog.Description className="mt-2 text-sm text-muted">
            Set up your project with key details to get started.
          </Dialog.Description>

          <form onSubmit={handleSubmit} className="mt-6 space-y-4">
            {/* Project Name (required) */}
            <div>
              <label htmlFor="project-name" className="block text-sm font-medium text-foreground">
                Project Name <span className="text-red-500">*</span>
              </label>
              <input
                id="project-name"
                type="text"
                value={title}
                onChange={(e) => {
                  setTitle(e.target.value);
                  if (errors.title) setErrors((prev) => ({ ...prev, title: undefined }));
                }}
                placeholder="e.g., Q1 User Onboarding Redesign"
                className={`mt-1 w-full rounded-md border bg-background px-3 py-2 text-sm text-foreground placeholder:text-muted focus:outline-none focus:ring-2 focus:ring-accent ${
                  errors.title ? 'border-red-500' : 'border-border'
                }`}
                autoFocus
              />
              {errors.title && (
                <p className="mt-1 text-xs text-red-500">{errors.title}</p>
              )}
            </div>

            {/* Program (required) */}
            <div>
              <label htmlFor="project-program" className="block text-sm font-medium text-foreground">
                Program <span className="text-red-500">*</span>
              </label>
              <select
                id="project-program"
                value={programId}
                onChange={(e) => {
                  setProgramId(e.target.value);
                  if (errors.program) setErrors((prev) => ({ ...prev, program: undefined }));
                }}
                className={`mt-1 w-full rounded-md border bg-background px-3 py-2 text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-accent ${
                  errors.program ? 'border-red-500' : 'border-border'
                }`}
              >
                <option value="">Select a program...</option>
                {loading ? (
                  <option disabled>Loading programs...</option>
                ) : (
                  activePrograms.map((program: Program) => (
                    <option key={program.id} value={program.id}>
                      {program.emoji ? `${program.emoji} ` : ''}{program.name}
                    </option>
                  ))
                )}
              </select>
              {errors.program && (
                <p className="mt-1 text-xs text-red-500">{errors.program}</p>
              )}
              {!loading && activePrograms.length === 0 && (
                <p className="mt-1 text-xs text-muted">
                  No programs available. Create a program first.
                </p>
              )}
            </div>

            {/* Plan (optional) */}
            <div>
              <label htmlFor="project-plan" className="block text-sm font-medium text-foreground">
                Plan
                <span className="ml-1 text-xs font-normal text-muted">(optional)</span>
              </label>
              <textarea
                id="project-plan"
                value={plan}
                onChange={(e) => setPlan(e.target.value)}
                placeholder="What are we trying to achieve? e.g., Simplify onboarding to 3 steps to increase conversion by 20%"
                rows={3}
                className="mt-1 w-full rounded-md border border-border bg-background px-3 py-2 text-sm text-foreground placeholder:text-muted focus:outline-none focus:ring-2 focus:ring-accent"
              />
            </div>

            {/* Target Date (optional) */}
            <div>
              <label htmlFor="project-target-date" className="block text-sm font-medium text-foreground">
                Target Date
                <span className="ml-1 text-xs font-normal text-muted">(optional)</span>
              </label>
              <input
                id="project-target-date"
                type="date"
                value={targetDate}
                onChange={(e) => setTargetDate(e.target.value)}
                className="mt-1 w-full rounded-md border border-border bg-background px-3 py-2 text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-accent"
              />
            </div>

            {/* Actions */}
            <div className="mt-6 flex justify-end gap-3 pt-2">
              <button
                type="button"
                onClick={handleCancel}
                className="rounded-md bg-border px-4 py-2 text-sm font-medium text-foreground hover:bg-border/80 focus:outline-none focus:ring-2 focus:ring-border focus:ring-offset-2 focus:ring-offset-background"
              >
                Cancel
              </button>
              <button
                type="submit"
                disabled={loading || activePrograms.length === 0}
                className="rounded-md bg-accent px-4 py-2 text-sm font-medium text-white hover:bg-accent/90 focus:outline-none focus:ring-2 focus:ring-accent focus:ring-offset-2 focus:ring-offset-background disabled:opacity-50 disabled:cursor-not-allowed"
              >
                Create Project
              </button>
            </div>
          </form>
        </Dialog.Content>
      </Dialog.Portal>
    </Dialog.Root>
  );
}

import { useState, useCallback, useEffect, ReactNode } from 'react';
import { useSelection, UseSelectionReturn } from '@/hooks/useSelection';
import { cn } from '@/lib/cn';

export interface SelectableListProps<T extends { id: string }> {
  /** Items to display in the list */
  items: T[];

  /** Loading state - shows skeleton */
  loading?: boolean;

  /** Empty state content */
  emptyState?: ReactNode;

  /** Render function for each row's content (excluding checkbox) */
  renderRow: (item: T, props: RowRenderProps) => ReactNode;

  /** Get unique ID from item (defaults to item.id) */
  getItemId?: (item: T) => string;

  /** Enable selection features (checkboxes, multi-select) */
  selectable?: boolean;

  /** Initial selected IDs - for restoring selection after navigation */
  initialSelectedIds?: Set<string>;

  /** Callback when selection changes - receives both selectedIds and selection object */
  onSelectionChange?: (selectedIds: Set<string>, selection: UseSelectionReturn) => void;

  /** Callback when item is clicked (not checkbox) */
  onItemClick?: (item: T) => void;

  /** Callback when item is right-clicked (for context menu) */
  onContextMenu?: (e: React.MouseEvent, item: T, selection: UseSelectionReturn) => void;

  /** Table columns header */
  columns?: { key: string; label: string; className?: string }[];

  /** Aria label for the list */
  ariaLabel?: string;
}

export interface RowRenderProps {
  isSelected: boolean;
  isHovered: boolean;
  isFocused: boolean;
}

/**
 * SelectableList - Canonical component for lists with selection support
 *
 * Features:
 * - Hover-visible checkboxes
 * - Multi-select with Shift+Click (range) and Ctrl/Cmd+Click (toggle)
 * - Keyboard navigation (Arrow Up/Down, Shift+Arrow to extend)
 * - Space to toggle selection on focused row
 * - Escape to clear selection
 */
export function SelectableList<T extends { id: string }>({
  items,
  loading,
  emptyState,
  renderRow,
  getItemId = (item) => item.id,
  selectable = true,
  initialSelectedIds,
  onSelectionChange,
  onItemClick,
  onContextMenu,
  columns,
  ariaLabel = 'Selectable list',
}: SelectableListProps<T>) {
  const [hoveredId, setHoveredId] = useState<string | null>(null);

  const selection = useSelection({
    items,
    getItemId,
    hoveredId,
    initialSelectedIds,
  });

  // Notify parent of selection changes with both IDs and selection object
  // NOTE: We intentionally don't include moveFocus/extendSelection in dependencies
  // because extendSelection depends on focusedId, causing infinite loops when hover
  // changes focus. The parent receives fresh selection object on selectedIds/focusedId changes.
  useEffect(() => {
    onSelectionChange?.(selection.selectedIds, selection);
  }, [selection.selectedIds, selection.focusedId, onSelectionChange]);

  const handleContextMenu = useCallback((e: React.MouseEvent, item: T) => {
    e.preventDefault();
    const itemId = getItemId(item);

    // If right-clicked item is not selected, select only that item
    if (!selection.isSelected(itemId)) {
      selection.clearSelection();
      selection.handleClick(itemId, e);
    }

    onContextMenu?.(e, item, selection);
  }, [getItemId, selection, onContextMenu]);

  if (loading) {
    return <SelectableListSkeleton columns={columns?.length || 5} />;
  }

  if (items.length === 0 && emptyState) {
    return (
      <div className="flex h-full items-center justify-center">
        {emptyState}
      </div>
    );
  }

  return (
    <>
      <table
        className="w-full"
        role="grid"
        aria-multiselectable={selectable ? 'true' : undefined}
        aria-label={ariaLabel}
        tabIndex={0}
        onKeyDown={selectable ? selection.handleKeyDown : undefined}
        onMouseLeave={() => {
          // Clear focusedId when mouse leaves the table entirely.
          // This ensures pressing 'j' after mouse exits starts from the first row.
          setHoveredId(null);
          selection.setFocusedId(null);
        }}
      >
        {columns && (
          <thead className="sticky top-0 bg-background z-10">
            <tr className="border-b border-border text-left text-xs text-muted">
              {selectable && <th className="w-10 px-2 py-2" aria-label="Selection"></th>}
              {columns.map((col) => (
                <th key={col.key} className={cn('px-4 py-2 font-medium', col.className)}>
                  {col.label}
                </th>
              ))}
            </tr>
          </thead>
        )}
        <tbody>
          {items.map((item, index) => {
            const itemId = getItemId(item);
            const isSelected = selection.isSelected(itemId);
            const isFocused = selection.isFocused(itemId);
            const isHovered = hoveredId === itemId;

            return (
              <SelectableRow
                key={itemId}
                itemId={itemId}
                isSelected={isSelected}
                isFocused={isFocused}
                isHovered={isHovered}
                selectable={selectable}
                onCheckboxClick={(e) => {
                  // Checkbox clicks should toggle without clearing selection
                  // (unlike row clicks which replace selection on plain click)
                  if (e.shiftKey) {
                    selection.selectRange(itemId);
                  } else {
                    selection.toggleSelection(itemId);
                  }
                }}
                onRowClick={() => onItemClick?.(item)}
                onFocus={() => selection.setFocusedId(itemId)}
                onMouseEnter={() => {
                  setHoveredId(itemId);
                  // Set focusedId on hover for Superhuman-style UX.
                  // When mouse leaves the table entirely (see onMouseLeave on <table>),
                  // focusedId is cleared so 'j' starts from the first row.
                  selection.setFocusedId(itemId);
                }}
                onMouseLeave={() => setHoveredId(null)}
                onContextMenu={(e) => handleContextMenu(e, item)}
              >
                {renderRow(item, { isSelected, isHovered, isFocused })}
              </SelectableRow>
            );
          })}
        </tbody>
      </table>

      {/* Selection announcer for screen readers */}
      <div
        id="selection-announcer"
        role="status"
        aria-live="polite"
        aria-atomic="true"
        className="sr-only"
      >
        {selection.hasSelection ? `${selection.selectedCount} items selected` : ''}
      </div>
    </>
  );
}

interface SelectableRowProps {
  itemId: string;
  isSelected: boolean;
  isFocused: boolean;
  isHovered: boolean;
  selectable: boolean;
  onCheckboxClick: (e: React.MouseEvent) => void;
  onRowClick: () => void;
  onFocus: () => void;
  onMouseEnter: () => void;
  onMouseLeave: () => void;
  onContextMenu: (e: React.MouseEvent) => void;
  children: ReactNode;
}

function SelectableRow({
  itemId,
  isSelected,
  isFocused,
  isHovered,
  selectable,
  onCheckboxClick,
  onRowClick,
  onFocus,
  onMouseEnter,
  onMouseLeave,
  onContextMenu,
  children,
}: SelectableRowProps) {
  return (
    <tr
      role="row"
      aria-selected={isSelected}
      tabIndex={isFocused ? 0 : -1}
      onClick={onRowClick}
      onFocus={onFocus}
      onMouseEnter={onMouseEnter}
      onMouseLeave={onMouseLeave}
      onContextMenu={onContextMenu}
      data-selected={isSelected}
      data-focused={isFocused}
      className={cn(
        'group cursor-pointer border-b border-border/50 transition-colors',
        isSelected && 'bg-accent/10',
        isFocused && 'ring-2 ring-accent ring-inset',
        !isSelected && 'hover:bg-border/30'
      )}
    >
      {/* Checkbox cell */}
      {selectable && (
        <td className="w-10 px-2 py-3" role="gridcell">
          <div
            className={cn(
              'flex items-center justify-center transition-opacity',
              isSelected || isHovered ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'
            )}
          >
            <button
              type="button"
              role="checkbox"
              aria-checked={isSelected}
              onClick={(e) => {
                e.stopPropagation();
                onCheckboxClick(e);
              }}
              aria-label={`Select item ${itemId}`}
              className={cn(
                'h-4 w-4 rounded flex items-center justify-center transition-all',
                'border focus:outline-none focus:ring-2 focus:ring-accent/50',
                isSelected
                  ? 'bg-accent border-accent text-white'
                  : 'border-muted/50 hover:border-muted bg-transparent'
              )}
            >
              {isSelected && (
                <svg className="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={3}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                </svg>
              )}
            </button>
          </div>
        </td>
      )}
      {/* Row content - rendered by parent */}
      {children}
    </tr>
  );
}

function SelectableListSkeleton({ columns }: { columns: number }) {
  return (
    <div className="w-full animate-pulse">
      <div className="flex border-b border-border px-4 py-3">
        {Array.from({ length: columns }).map((_, i) => (
          <div key={i} className="flex-1 px-4">
            <div className="h-3 w-16 rounded bg-border/50" />
          </div>
        ))}
      </div>
      {Array.from({ length: 8 }).map((_, rowIdx) => (
        <div key={rowIdx} className="flex border-b border-border/50 px-4 py-4">
          <div className="w-10 px-2">
            <div className="h-4 w-4 rounded bg-border/30" />
          </div>
          {Array.from({ length: columns }).map((_, colIdx) => (
            <div key={colIdx} className="flex-1 px-4">
              <div
                className="h-4 rounded bg-border/30"
                style={{ width: `${60 + Math.random() * 40}%` }}
              />
            </div>
          ))}
        </div>
      ))}
    </div>
  );
}

// Re-export useSelection for convenience
export { useSelection } from '@/hooks/useSelection';
export type { UseSelectionReturn } from '@/hooks/useSelection';

