import { useState, useEffect } from 'react';
import { apiGet, apiPost } from '@/lib/api';
import { usePrograms } from '@/hooks/useProgramsQuery';
import { useToast } from '@/components/ui/Toast';
import { useNavigate } from 'react-router-dom';
import { useQueryClient } from '@tanstack/react-query';

interface MergePreview {
  source: { id: string; name: string };
  target: { id: string; name: string };
  counts: { projects: number; issues: number; sprints: number; wikis: number };
  conflicts: Array<{ type: string; message: string }>;
}

interface MergeProgramDialogProps {
  isOpen: boolean;
  onClose: () => void;
  sourceId: string;
  sourceName: string;
}

export function MergeProgramDialog({ isOpen, onClose, sourceId, sourceName }: MergeProgramDialogProps) {
  const [targetId, setTargetId] = useState<string | null>(null);
  const [preview, setPreview] = useState<MergePreview | null>(null);
  const [previewLoading, setPreviewLoading] = useState(false);
  const [confirmText, setConfirmText] = useState('');
  const [isMerging, setIsMerging] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const { programs } = usePrograms();
  const { showToast } = useToast();
  const navigate = useNavigate();
  const queryClient = useQueryClient();

  // Filter out current program and archived programs
  const availableTargets = programs.filter(
    (p) => p.id !== sourceId && !p.archived_at
  );

  // Reset state when dialog opens/closes
  useEffect(() => {
    if (!isOpen) {
      setTargetId(null);
      setPreview(null);
      setConfirmText('');
      setError(null);
      setIsMerging(false);
    }
  }, [isOpen]);

  // Fetch preview when target is selected
  useEffect(() => {
    if (!targetId) {
      setPreview(null);
      return;
    }

    let cancelled = false;
    setPreviewLoading(true);
    setError(null);

    apiGet(`/api/programs/${sourceId}/merge-preview?target_id=${targetId}`)
      .then(async (res) => {
        if (cancelled) return;
        if (!res.ok) {
          const data = await res.json();
          setError(data.error || 'Failed to load preview');
          setPreview(null);
        } else {
          const data = await res.json();
          setPreview(data);
        }
      })
      .catch(() => {
        if (!cancelled) setError('Failed to load preview');
      })
      .finally(() => {
        if (!cancelled) setPreviewLoading(false);
      });

    return () => { cancelled = true; };
  }, [targetId, sourceId]);

  // Handle escape key
  useEffect(() => {
    if (!isOpen || isMerging) return;
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [isOpen, isMerging, onClose]);

  const handleMerge = async () => {
    if (!targetId || confirmText !== sourceName) return;

    setIsMerging(true);
    setError(null);

    try {
      const res = await apiPost(`/api/programs/${sourceId}/merge`, {
        target_id: targetId,
        confirm_name: confirmText,
      });

      if (!res.ok) {
        const data = await res.json();
        setError(data.error || 'Merge failed');
        setIsMerging(false);
        return;
      }

      // Invalidate programs cache
      queryClient.invalidateQueries({ queryKey: ['programs'] });

      showToast(`Merged "${sourceName}" into "${preview?.target.name}"`, 'success');
      onClose();
      navigate(`/documents/${targetId}`);
    } catch {
      setError('Merge failed. Please try again.');
      setIsMerging(false);
    }
  };

  const handleBackdropClick = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget && !isMerging) onClose();
  };

  if (!isOpen) return null;

  const totalEntities = preview
    ? preview.counts.projects + preview.counts.issues + preview.counts.sprints + preview.counts.wikis
    : 0;

  const confirmMatch = confirmText === sourceName;

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/50"
      role="dialog"
      aria-modal="true"
      onClick={handleBackdropClick}
    >
      <div className="w-full max-w-md rounded-lg bg-background p-6 shadow-lg">
        <h2 className="mb-1 text-lg font-semibold text-foreground">Merge Program</h2>
        <p className="mb-4 text-sm text-muted">
          Move all content from <strong>{sourceName}</strong> into another program.
        </p>

        {/* Target selection */}
        <div className="mb-4">
          <label className="mb-1 block text-xs font-medium text-muted uppercase tracking-wider">
            Merge into
          </label>
          <select
            value={targetId || ''}
            onChange={(e) => setTargetId(e.target.value || null)}
            disabled={isMerging}
            className="w-full rounded border border-border bg-background px-3 py-2 text-sm text-foreground focus:border-accent focus:outline-none"
          >
            <option value="">Select target program...</option>
            {availableTargets.map((p) => (
              <option key={p.id} value={p.id}>
                {p.name}
              </option>
            ))}
          </select>
        </div>

        {/* Preview */}
        {previewLoading && (
          <div className="mb-4 rounded border border-border p-3 text-center text-sm text-muted">
            Loading preview...
          </div>
        )}

        {preview && !previewLoading && (
          <div className="mb-4 rounded border border-border p-3">
            <p className="mb-2 text-sm font-medium text-foreground">
              {totalEntities} {totalEntities === 1 ? 'item' : 'items'} will be moved:
            </p>
            <ul className="space-y-1 text-sm text-muted">
              {preview.counts.projects > 0 && (
                <li>{preview.counts.projects} {preview.counts.projects === 1 ? 'project' : 'projects'}</li>
              )}
              {preview.counts.issues > 0 && (
                <li>{preview.counts.issues} {preview.counts.issues === 1 ? 'issue' : 'issues'}</li>
              )}
              {preview.counts.sprints > 0 && (
                <li>{preview.counts.sprints} {preview.counts.sprints === 1 ? 'week' : 'weeks'}</li>
              )}
              {preview.counts.wikis > 0 && (
                <li>{preview.counts.wikis} {preview.counts.wikis === 1 ? 'wiki page' : 'wiki pages'}</li>
              )}
              {totalEntities === 0 && <li>No child entities to move</li>}
            </ul>

            {preview.conflicts.length > 0 && (
              <div className="mt-2 rounded bg-amber-500/10 border border-amber-500/30 p-2">
                {preview.conflicts.map((c, i) => (
                  <p key={i} className="text-xs text-amber-300">{c.message}</p>
                ))}
              </div>
            )}
          </div>
        )}

        {/* Type-to-confirm */}
        {preview && !previewLoading && (
          <div className="mb-4">
            <label className="mb-1 block text-xs font-medium text-muted">
              Type <strong className="text-foreground">{sourceName}</strong> to confirm
            </label>
            <input
              type="text"
              value={confirmText}
              onChange={(e) => setConfirmText(e.target.value)}
              disabled={isMerging}
              placeholder={sourceName}
              className="w-full rounded border border-border bg-background px-3 py-2 text-sm text-foreground placeholder:text-muted/50 focus:border-accent focus:outline-none"
              autoComplete="off"
            />
          </div>
        )}

        {/* Error */}
        {error && (
          <div className="mb-4 rounded bg-red-500/10 border border-red-500/30 p-2">
            <p className="text-sm text-red-400">{error}</p>
          </div>
        )}

        {/* Actions */}
        <div className="flex justify-end gap-2">
          <button
            onClick={onClose}
            disabled={isMerging}
            className="rounded px-3 py-1.5 text-sm text-muted hover:text-foreground transition-colors disabled:opacity-50"
          >
            Cancel
          </button>
          <button
            onClick={handleMerge}
            disabled={!confirmMatch || isMerging || !preview}
            className="rounded bg-red-600 px-3 py-1.5 text-sm font-medium text-white hover:bg-red-700 disabled:opacity-50 transition-colors flex items-center gap-2"
          >
            {isMerging ? (
              <>
                <svg className="w-4 h-4 animate-spin" viewBox="0 0 24 24" fill="none">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                </svg>
                Merging...
              </>
            ) : (
              'Merge Program'
            )}
          </button>
        </div>
      </div>
    </div>
  );
}

import { useNavigate } from 'react-router-dom';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { apiGet } from '@/lib/api';
import type { DocumentTabProps } from '@/lib/document-tabs';
import { useCreateProject } from '@/hooks/useProjectsQuery';
import { useToast } from '@/components/ui/Toast';

interface ProgramProject {
  id: string;
  title: string;
  color: string;
  emoji: string | null;
  ice_score: number;
  sprint_count: number;
  issue_count: number;
  owner: { id: string; name: string; email: string } | null;
}

/**
 * ProgramProjectsTab - Shows projects associated with a program
 *
 * This is the "Projects" tab content when viewing a program document.
 */
export default function ProgramProjectsTab({ documentId }: DocumentTabProps) {
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const createProjectMutation = useCreateProject();
  const { showToast } = useToast();

  const { data: projects = [], isLoading } = useQuery<ProgramProject[]>({
    queryKey: ['program-projects', documentId],
    queryFn: async () => {
      const response = await apiGet(`/api/programs/${documentId}/projects`);
      if (!response.ok) {
        throw new Error('Failed to fetch projects');
      }
      return response.json();
    },
  });

  const handleCreateProject = async () => {
    try {
      const project = await createProjectMutation.mutateAsync({
        program_id: documentId,
      });
      // Invalidate the program-projects query to refresh the list
      queryClient.invalidateQueries({ queryKey: ['program-projects', documentId] });
      showToast('Project created', 'success');
      // Navigate to the new project
      navigate(`/documents/${project.id}`);
    } catch {
      showToast('Failed to create project', 'error');
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-48">
        <div className="flex items-center gap-2 text-muted">
          <svg className="w-5 h-5 animate-spin" viewBox="0 0 24 24" fill="none">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
          </svg>
          Loading projects...
        </div>
      </div>
    );
  }

  if (projects.length === 0) {
    return (
      <div className="h-full overflow-auto p-4">
        <div className="flex justify-end mb-4">
          <button
            onClick={handleCreateProject}
            disabled={createProjectMutation.isPending}
            className="inline-flex items-center gap-1.5 rounded-md bg-accent px-3 py-1.5 text-sm font-medium text-white hover:bg-accent/90 transition-colors disabled:opacity-50"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
            </svg>
            {createProjectMutation.isPending ? 'Creating...' : 'New Project'}
          </button>
        </div>
        <div className="flex flex-col items-center justify-center h-48 text-muted">
          <svg className="w-12 h-12 mb-3 opacity-50" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
            <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 12.75V12A2.25 2.25 0 014.5 9.75h15A2.25 2.25 0 0121.75 12v.75m-8.69-6.44l-2.12-2.12a1.5 1.5 0 00-1.061-.44H4.5A2.25 2.25 0 002.25 6v12a2.25 2.25 0 002.25 2.25h15A2.25 2.25 0 0021.75 18V9a2.25 2.25 0 00-2.25-2.25h-5.379a1.5 1.5 0 01-1.06-.44z" />
          </svg>
          <p className="text-sm font-medium">No projects in this program</p>
          <p className="text-xs mt-1">Create a project to get started</p>
        </div>
      </div>
    );
  }

  return (
    <div className="h-full overflow-auto p-4 pb-20">
      <div className="flex justify-end mb-4">
        <button
          onClick={handleCreateProject}
          disabled={createProjectMutation.isPending}
          className="inline-flex items-center gap-1.5 rounded-md bg-accent px-3 py-1.5 text-sm font-medium text-white hover:bg-accent/90 transition-colors disabled:opacity-50"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
          </svg>
          {createProjectMutation.isPending ? 'Creating...' : 'New Project'}
        </button>
      </div>
      <div className="space-y-2">
        {projects.map((project) => (
          <div
            key={project.id}
            onClick={() => navigate(`/documents/${project.id}`)}
            className="flex items-center gap-4 p-3 rounded-lg border border-border hover:bg-accent/5 cursor-pointer transition-colors"
          >
            {/* Project color indicator */}
            <div
              className="flex-shrink-0 w-10 h-10 rounded-lg flex items-center justify-center text-lg"
              style={{ backgroundColor: project.color + '20' }}
            >
              {project.emoji || (
                <span style={{ color: project.color }} className="text-sm font-bold">
                  {project.title.charAt(0).toUpperCase()}
                </span>
              )}
            </div>

            {/* Project info */}
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-2">
                <h3 className="text-sm font-medium text-foreground truncate">
                  {project.title}
                </h3>
                <span className="inline-flex px-2 py-0.5 text-xs font-medium rounded bg-accent/20 text-accent">
                  ICE: {project.ice_score}
                </span>
              </div>
              <div className="flex items-center gap-3 mt-1 text-xs text-muted">
                {project.owner && <span>{project.owner.name}</span>}
                <span>{project.issue_count} issues</span>
                <span>{project.sprint_count} sprints</span>
              </div>
            </div>

            {/* Arrow */}
            <svg className="w-4 h-4 text-muted flex-shrink-0" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M7.293 14.707a1 1 0 010-1.414L10.586 10 7.293 6.707a1 1 0 011.414-1.414l4 4a1 1 0 010 1.414l-4 4a1 1 0 01-1.414 0z" clipRule="evenodd" />
            </svg>
          </div>
        ))}
      </div>
    </div>
  );
}

import { useCallback, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { UnifiedEditor } from '@/components/UnifiedEditor';
import type { UnifiedDocument, SidebarData } from '@/components/UnifiedEditor';
import { useAuth } from '@/hooks/useAuth';
import { useAssignableMembersQuery } from '@/hooks/useTeamMembersQuery';
import { useProgramsQuery } from '@/hooks/useProgramsQuery';
import { apiPatch, apiDelete, apiPost } from '@/lib/api';
import { useToast } from '@/components/ui/Toast';
import { issueKeys } from '@/hooks/useIssuesQuery';
import { projectKeys } from '@/hooks/useProjectsQuery';
import type { DocumentTabProps } from '@/lib/document-tabs';
import { computeICEScore } from '@ship/shared';

/**
 * ProjectDetailsTab - Renders the project document in the UnifiedEditor
 *
 * This is the "Details" tab content when viewing a project document.
 */
export default function ProjectDetailsTab({ documentId, document }: DocumentTabProps) {
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const { user } = useAuth();
  const { showToast } = useToast();

  // Track conversion state separately from update mutation
  const [isConverting, setIsConverting] = useState(false);
  const [isUndoing, setIsUndoing] = useState(false);

  // Fetch team members for sidebar
  const { data: teamMembersData = [] } = useAssignableMembersQuery();
  const teamMembers = useMemo(() => teamMembersData.map(m => ({
    id: m.id,
    user_id: m.user_id,
    name: m.name,
    email: m.email || '',
  })), [teamMembersData]);

  // Fetch programs for sidebar
  const { data: programsData = [] } = useProgramsQuery();
  const programs = useMemo(() => programsData.map(p => ({
    id: p.id,
    name: p.name,
    color: p.color,
    emoji: p.emoji,
  })), [programsData]);

  // Update mutation with optimistic updates
  const updateMutation = useMutation({
    mutationFn: async (updates: Partial<UnifiedDocument>) => {
      const response = await apiPatch(`/api/documents/${documentId}`, updates);
      if (!response.ok) {
        throw new Error('Failed to update document');
      }
      return response.json();
    },
    onMutate: async (updates) => {
      // Cancel any outgoing refetches
      await queryClient.cancelQueries({ queryKey: ['document', documentId] });
      await queryClient.cancelQueries({ queryKey: projectKeys.lists() });

      // Snapshot the previous value
      const previousDocument = queryClient.getQueryData<Record<string, unknown>>(['document', documentId]);

      // Optimistically update the document cache
      if (previousDocument) {
        // Cast updates to Record since we're in ProjectDetailsTab and know these fields exist
        const projectUpdates = updates as Record<string, unknown>;
        const updatedDocument = { ...previousDocument, ...projectUpdates };

        // Recompute ICE score if any ICE property changed
        if ('impact' in projectUpdates || 'confidence' in projectUpdates || 'ease' in projectUpdates) {
          const impact = (projectUpdates.impact ?? previousDocument.impact) as number | null;
          const confidence = (projectUpdates.confidence ?? previousDocument.confidence) as number | null;
          const ease = (projectUpdates.ease ?? previousDocument.ease) as number | null;
          updatedDocument.ice_score = computeICEScore(impact, confidence, ease);
        }

        queryClient.setQueryData(['document', documentId], updatedDocument);
      }

      // Return context with the previous value for rollback
      return { previousDocument };
    },
    onError: (_err, _updates, context) => {
      // Rollback to the previous value on error
      if (context?.previousDocument) {
        queryClient.setQueryData(['document', documentId], context.previousDocument);
      }
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['document', documentId] });
      queryClient.invalidateQueries({ queryKey: projectKeys.lists() });
    },
  });

  // Delete mutation
  const deleteMutation = useMutation({
    mutationFn: async () => {
      const response = await apiDelete(`/api/documents/${documentId}`);
      if (!response.ok) {
        throw new Error('Failed to delete document');
      }
    },
    onSuccess: () => {
      navigate('/projects');
    },
  });

  // Handle type change (project <-> issue conversion)
  const handleTypeChange = useCallback(async (newType: string) => {
    const isValidConversion = newType === 'issue';
    if (!isValidConversion) {
      showToast(`Converting project to ${newType} is not supported`, 'error');
      return;
    }

    try {
      const res = await apiPost(`/api/documents/${documentId}/convert`, { target_type: newType });
      if (res.ok) {
        const data = await res.json();
        await Promise.all([
          queryClient.invalidateQueries({ queryKey: issueKeys.lists() }),
          queryClient.invalidateQueries({ queryKey: projectKeys.lists() }),
          queryClient.invalidateQueries({ queryKey: ['document', documentId] }),
        ]);
        navigate(`/documents/${data.id}`, { replace: true });
      } else {
        const error = await res.json();
        showToast(error.error || 'Failed to convert document', 'error');
      }
    } catch (err) {
      showToast('Failed to convert document', 'error');
    }
  }, [documentId, navigate, queryClient, showToast]);

  // Handle conversion callbacks
  const handleConvert = useCallback(async () => {
    setIsConverting(true);
    try {
      await handleTypeChange('issue');
    } finally {
      setIsConverting(false);
    }
  }, [handleTypeChange]);

  const handleUndoConversion = useCallback(async () => {
    setIsUndoing(true);
    try {
      const res = await apiPost(`/api/documents/${documentId}/undo-conversion`, {});
      if (res.ok) {
        await Promise.all([
          queryClient.invalidateQueries({ queryKey: issueKeys.lists() }),
          queryClient.invalidateQueries({ queryKey: projectKeys.lists() }),
          queryClient.invalidateQueries({ queryKey: ['document', documentId] }),
        ]);
        showToast('Conversion undone successfully', 'success');
      } else {
        const error = await res.json();
        showToast(error.error || 'Failed to undo conversion', 'error');
      }
    } catch (err) {
      showToast('Failed to undo conversion', 'error');
    } finally {
      setIsUndoing(false);
    }
  }, [documentId, queryClient, showToast]);

  // Handle WebSocket notification
  const handleDocumentConverted = useCallback((newDocId: string) => {
    navigate(`/documents/${newDocId}`, { replace: true });
  }, [navigate]);

  // Handle back navigation
  const handleBack = useCallback(() => {
    navigate('/projects');
  }, [navigate]);

  // Handle update
  const handleUpdate = useCallback(async (updates: Partial<UnifiedDocument>) => {
    await updateMutation.mutateAsync(updates);
  }, [updateMutation]);

  // Handle delete
  const handleDelete = useCallback(async () => {
    if (!window.confirm('Are you sure you want to delete this project?')) return;
    await deleteMutation.mutateAsync();
  }, [deleteMutation]);

  // Build sidebar data
  const sidebarData: SidebarData = useMemo(() => ({
    programs,
    people: teamMembers,
    onConvert: handleConvert,
    onUndoConversion: handleUndoConversion,
    isConverting,
    isUndoing,
  }), [programs, teamMembers, handleConvert, handleUndoConversion, isConverting, isUndoing]);

  // Get program_id from belongs_to array (project's parent program via document_associations)
  const belongsTo = (document as { belongs_to?: Array<{ id: string; type: string }> }).belongs_to;
  const programId = belongsTo?.find(b => b.type === 'program')?.id;

  // Transform to UnifiedDocument format
  const unifiedDocument: UnifiedDocument = useMemo(() => ({
    id: document.id,
    title: document.title,
    document_type: 'project',
    created_at: document.created_at,
    updated_at: document.updated_at,
    created_by: document.created_by as string | undefined,
    properties: document.properties as Record<string, unknown> | undefined,
    impact: (document.impact as number | null) ?? null,
    confidence: (document.confidence as number | null) ?? null,
    ease: (document.ease as number | null) ?? null,
    color: (document.color as string) || '#3b82f6',
    emoji: null,
    program_id: programId ?? null,
    owner: document.owner as { id: string; name: string; email: string } | null,
    owner_id: document.owner_id as string | undefined,
    // RACI fields
    accountable_id: document.accountable_id as string | undefined,
    consulted_ids: (document.consulted_ids as string[]) || [],
    informed_ids: (document.informed_ids as string[]) || [],
    converted_from_id: document.converted_from_id as string | undefined,
    // Design review
    has_design_review: document.has_design_review as boolean | null | undefined,
    design_review_notes: document.design_review_notes as string | null | undefined,
  }), [document, programId]);

  if (!user) return null;

  return (
    <UnifiedEditor
      document={unifiedDocument}
      sidebarData={sidebarData}
      onUpdate={handleUpdate}
      onTypeChange={handleTypeChange}
      onDocumentConverted={handleDocumentConverted}
      onBack={handleBack}
      backLabel="projects"
      onDelete={handleDelete}
      showTypeSelector={true}
    />
  );
}

import { useState, useEffect, useRef, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { cn } from '@/lib/cn';
import { createOrGetWeeklyDocumentId } from '@/lib/accountability';
import { formatDateRange } from '@/lib/date-utils';
import type { DocumentTabProps } from '@/lib/document-tabs';

const API_URL = import.meta.env.VITE_API_URL ?? '';

type Status = 'done' | 'due' | 'late' | 'future';

interface Week {
  number: number;
  name: string;
  startDate: string;
  endDate: string;
  isCurrent: boolean;
}

interface PersonWeekData {
  isAllocated: boolean;
  planId: string | null;
  planStatus: Status;
  retroId: string | null;
  retroStatus: Status;
}

interface Person {
  id: string;
  name: string;
  weeks: Record<number, PersonWeekData>;
}

interface AllocationGridData {
  projectId: string;
  projectTitle: string;
  currentSprintNumber: number;
  weeks: Week[];
  people: Person[];
}

// Status colors
const STATUS_COLORS: Record<Status, string> = {
  done: '#22c55e',   // green
  due: '#eab308',    // yellow
  late: '#ef4444',   // red
  future: '#6b7280', // gray
};

// User-friendly status text for tooltips
const STATUS_TEXT: Record<Status, string> = {
  done: 'done',
  due: 'due this week',
  late: 'late',
  future: 'not yet due',
};

/**
 * StatusCell - Shows Plan/Retro status as two colored squares
 */
function StatusCell({
  planStatus,
  retroStatus,
  onPlanClick,
  onRetroClick,
  isNavigating,
}: {
  planStatus: Status;
  retroStatus: Status;
  onPlanClick?: () => void;
  onRetroClick?: () => void;
  isNavigating?: 'plan' | 'retro' | null;
}) {
  return (
    <div className="flex w-full h-full">
      {/* Plan status (left half) */}
      <button
        onClick={onPlanClick}
        disabled={isNavigating !== null}
        className={cn(
          'flex-1 h-full cursor-pointer transition-all hover:brightness-110 border-r border-white/20',
          isNavigating === 'plan' && 'animate-pulse'
        )}
        style={{ backgroundColor: STATUS_COLORS[planStatus] }}
        title={`Weekly Plan (${STATUS_TEXT[planStatus]})`}
      />
      {/* Retro status (right half) */}
      <button
        onClick={onRetroClick}
        disabled={isNavigating !== null}
        className={cn(
          'flex-1 h-full cursor-pointer transition-all hover:brightness-110',
          isNavigating === 'retro' && 'animate-pulse'
        )}
        style={{ backgroundColor: STATUS_COLORS[retroStatus] }}
        title={`Weekly Retro (${STATUS_TEXT[retroStatus]})`}
      />
    </div>
  );
}

/**
 * ProjectWeeksTab - Shows plan/retro status for team members allocated to this project
 *
 * Each cell shows two colored squares:
 * - Left: Weekly Plan status
 * - Right: Weekly Retro status
 *
 * Colors: green (done), yellow (due), red (late), gray (future)
 */
export default function ProjectWeeksTab({ documentId }: DocumentTabProps) {
  const navigate = useNavigate();
  const [data, setData] = useState<AllocationGridData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [navigatingCell, setNavigatingCell] = useState<{
    personId: string;
    weekNumber: number;
    type: 'plan' | 'retro';
  } | null>(null);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const hasScrolledToCurrentRef = useRef(false);

  /**
   * Navigate to a weekly plan or retro document.
   * Creates the document if it doesn't exist yet.
   */
  async function handleNavigate(
    personId: string,
    weekNumber: number,
    type: 'plan' | 'retro',
    existingDocId: string | null
  ) {
    // If document already exists, navigate directly
    if (existingDocId) {
      navigate(`/documents/${existingDocId}`);
      return;
    }

    // Create the document first
    setNavigatingCell({ personId, weekNumber, type });
    try {
      const createdDocumentId = await createOrGetWeeklyDocumentId({
        kind: type,
        personId,
        projectId: documentId || undefined,
        weekNumber,
      });
      if (createdDocumentId) {
        navigate(`/documents/${createdDocumentId}`);
      } else {
        console.error(`Failed to create weekly ${type}: request returned no document id`);
      }
    } catch (err) {
      console.error(`Failed to create weekly ${type}:`, err);
    } finally {
      setNavigatingCell(null);
    }
  }

  // Fetch data on mount
  useEffect(() => {
    async function fetchData() {
      try {
        setLoading(true);
        const res = await fetch(
          `${API_URL}/api/weekly-plans/project-allocation-grid/${documentId}`,
          { credentials: 'include' }
        );

        if (!res.ok) {
          throw new Error('Failed to load allocation data');
        }

        const gridData: AllocationGridData = await res.json();
        setData(gridData);
      } catch (err) {
        setError('Failed to load allocation data');
      } finally {
        setLoading(false);
      }
    }

    fetchData();
  }, [documentId]);

  // Filter to only show weeks where at least one person is allocated
  const visibleWeeks = useMemo(() => {
    if (!data) return [];
    return data.weeks;
  }, [data]);

  // Scroll to current week on initial load
  useEffect(() => {
    if (data && scrollContainerRef.current && !hasScrolledToCurrentRef.current && data.people.length > 0) {
      const currentWeekIndex = visibleWeeks.findIndex((w) => w.isCurrent);
      if (currentWeekIndex >= 0) {
        requestAnimationFrame(() => {
          if (scrollContainerRef.current) {
            const columnWidth = 140;
            const scrollPosition = currentWeekIndex * columnWidth;
            scrollContainerRef.current.scrollLeft = scrollPosition;
            hasScrolledToCurrentRef.current = true;
          }
        });
      }
    }
  }, [data, visibleWeeks]);

  if (loading) {
    return (
      <div className="flex h-full items-center justify-center">
        <div className="flex items-center gap-2 text-muted">
          <svg className="w-5 h-5 animate-spin" viewBox="0 0 24 24" fill="none">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
          </svg>
          Loading...
        </div>
      </div>
    );
  }

  if (error && !data) {
    return (
      <div className="flex h-full items-center justify-center">
        <div className="text-red-500">{error}</div>
      </div>
    );
  }

  // Empty state when no allocations
  if (!data || data.people.length === 0) {
    return (
      <div className="flex h-full flex-col items-center justify-center text-muted p-8">
        <svg className="w-16 h-16 mb-4 opacity-50" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5">
          <path strokeLinecap="round" strokeLinejoin="round" d="M15 19.128a9.38 9.38 0 002.625.372 9.337 9.337 0 004.121-.952 4.125 4.125 0 00-7.533-2.493M15 19.128v-.003c0-1.113-.285-2.16-.786-3.07M15 19.128v.106A12.318 12.318 0 018.624 21c-2.331 0-4.512-.645-6.374-1.766l-.001-.109a6.375 6.375 0 0111.964-3.07M12 6.375a3.375 3.375 0 11-6.75 0 3.375 3.375 0 016.75 0zm8.25 2.25a2.625 2.625 0 11-5.25 0 2.625 2.625 0 015.25 0z" />
        </svg>
        <p className="text-lg font-medium mb-2">No team allocations</p>
        <p className="text-sm text-center max-w-md">
          Assign team members to this project in Team → Allocation to see them here.
        </p>
      </div>
    );
  }

  return (
    <div className="flex h-full flex-col">
      {/* Legend */}
      <div className="flex items-center gap-4 px-4 py-2 border-b border-border text-xs">
        <span className="text-muted">Status:</span>
        <div className="flex items-center gap-1">
          <div className="w-3 h-3 rounded" style={{ backgroundColor: STATUS_COLORS.done }} />
          <span>Done</span>
        </div>
        <div className="flex items-center gap-1">
          <div className="w-3 h-3 rounded" style={{ backgroundColor: STATUS_COLORS.due }} />
          <span>Due</span>
        </div>
        <div className="flex items-center gap-1">
          <div className="w-3 h-3 rounded" style={{ backgroundColor: STATUS_COLORS.late }} />
          <span>Late</span>
        </div>
        <div className="flex items-center gap-1">
          <div className="w-3 h-3 rounded" style={{ backgroundColor: STATUS_COLORS.future }} />
          <span>Future</span>
        </div>
        <span className="text-muted ml-4">|</span>
        <span className="text-muted">Left = Plan, Right = Retro</span>
      </div>

      {/* Grid container */}
      <div ref={scrollContainerRef} className="flex-1 overflow-auto pb-20">
        <div className="inline-flex min-w-full">
          {/* Sticky left column - Team members */}
          <div className="flex flex-col sticky left-0 z-20 bg-background border-r border-border">
            {/* Header cell */}
            <div className="flex h-10 w-[180px] items-center border-b border-border px-3 sticky top-0 z-30 bg-background">
              <span className="text-xs font-medium text-muted">Team Member</span>
            </div>

            {/* Users */}
            {data.people.map((person) => (
              <div
                key={person.id}
                className="flex h-12 w-[180px] items-center border-b border-border px-3 bg-background"
              >
                <div className="flex items-center gap-2 overflow-hidden">
                  <div className="flex h-6 w-6 flex-shrink-0 items-center justify-center rounded-full text-xs font-medium text-white bg-accent/80">
                    {person.name.charAt(0).toUpperCase()}
                  </div>
                  <span className="truncate text-sm text-foreground">
                    {person.name}
                  </span>
                </div>
              </div>
            ))}
          </div>

          {/* Week columns */}
          <div className="flex">
            {visibleWeeks.map((week) => (
              <div key={week.number} className="flex flex-col">
                {/* Week header */}
                <div
                  className={cn(
                    'flex h-10 w-[140px] flex-col items-center justify-center border-b border-r border-border px-2 sticky top-0 z-10 bg-background',
                    week.isCurrent && 'ring-1 ring-inset ring-accent/30'
                  )}
                >
                  <span className={cn('text-xs font-medium', week.isCurrent ? 'text-accent' : 'text-foreground')}>
                    {week.name}
                  </span>
                  <span className="text-[10px] text-muted">
                    {formatDateRange(week.startDate, week.endDate)}
                  </span>
                </div>

                {/* User cells for this week */}
                {data.people.map((person) => {
                  const weekData = person.weeks[week.number];

                  // If not allocated to this project this week, show empty cell
                  if (!weekData?.isAllocated) {
                    return (
                      <div
                        key={person.id}
                        className={cn(
                          'flex h-12 w-[140px] items-center justify-center border-b border-r border-border',
                          week.isCurrent && 'bg-accent/5'
                        )}
                      >
                        <span className="text-xs text-muted">-</span>
                      </div>
                    );
                  }

                  return (
                    <div
                      key={person.id}
                      className={cn(
                        'flex h-12 w-[140px] border-b border-r border-border overflow-hidden',
                        week.isCurrent && 'bg-accent/5'
                      )}
                    >
                      <StatusCell
                        planStatus={weekData.planStatus}
                        retroStatus={weekData.retroStatus}
                        onPlanClick={() =>
                          handleNavigate(person.id, week.number, 'plan', weekData.planId)
                        }
                        onRetroClick={() =>
                          handleNavigate(person.id, week.number, 'retro', weekData.retroId)
                        }
                        isNavigating={
                          navigatingCell?.personId === person.id &&
                          navigatingCell?.weekNumber === week.number
                            ? navigatingCell.type
                            : null
                        }
                      />
                    </div>
                  );
                })}
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { ContextMenu, ContextMenuItem } from '@/components/ui/ContextMenu';
import { useToast } from '@/components/ui/Toast';
import { cn } from '@/lib/cn';

const API_URL = import.meta.env.VITE_API_URL ?? '';

interface Backlink {
  id: string;
  document_type: string;
  title: string;
  display_id?: string;
}

interface BacklinksPanelProps {
  documentId: string;
}

export function BacklinksPanel({ documentId }: BacklinksPanelProps) {
  const [backlinks, setBacklinks] = useState<Backlink[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [contextMenu, setContextMenu] = useState<{ x: number; y: number; backlink: Backlink } | null>(null);
  const navigate = useNavigate();
  const { showToast } = useToast();

  useEffect(() => {
    if (!documentId) return;

    let cancelled = false;

    async function fetchBacklinks() {
      try {
        // Only show loading on initial fetch, not on polls
        if (backlinks.length === 0) {
          setLoading(true);
        }
        setError(null);

        const response = await fetch(`${API_URL}/api/documents/${documentId}/backlinks`, {
          credentials: 'include',
        });

        if (!response.ok) {
          throw new Error('Failed to fetch backlinks');
        }

        const data = await response.json();

        if (!cancelled) {
          setBacklinks(data);
        }
      } catch (err) {
        if (!cancelled) {
          console.error('Error fetching backlinks:', err);
          setError('Failed to load backlinks');
        }
      } finally {
        if (!cancelled) {
          setLoading(false);
        }
      }
    }

    fetchBacklinks();

    // Poll for updates every 5 seconds (for real-time backlink updates)
    const intervalId = setInterval(fetchBacklinks, 5000);

    return () => {
      cancelled = true;
      clearInterval(intervalId);
    };
  }, [documentId]);

  const getDocumentUrl = (backlink: Backlink): string => {
    // Get the path based on document type
    switch (backlink.document_type) {
      case 'issue':
        return `/issues/${backlink.id}`;
      case 'wiki':
        return `/docs/${backlink.id}`;
      case 'program':
        return `/programs/${backlink.id}`;
      case 'sprint':
        return `/sprints/${backlink.id}`;
      case 'person':
        return `/team/${backlink.id}`;
      case 'weekly_plan':
      case 'weekly_retro':
        return `/docs/${backlink.id}`;
      default:
        return `/docs/${backlink.id}`;
    }
  };

  const handleNavigate = (backlink: Backlink) => {
    navigate(getDocumentUrl(backlink));
  };

  const handleContextMenu = useCallback((e: React.MouseEvent, backlink: Backlink) => {
    e.preventDefault();
    e.stopPropagation();
    setContextMenu({ x: e.clientX, y: e.clientY, backlink });
  }, []);

  const handleMenuClick = useCallback((e: React.MouseEvent, backlink: Backlink) => {
    e.preventDefault();
    e.stopPropagation();
    const rect = e.currentTarget.getBoundingClientRect();
    setContextMenu({ x: rect.right, y: rect.bottom, backlink });
  }, []);

  const handleOpen = useCallback(() => {
    if (contextMenu) {
      navigate(getDocumentUrl(contextMenu.backlink));
      setContextMenu(null);
    }
  }, [contextMenu, navigate]);

  const handleOpenInNewTab = useCallback(() => {
    if (contextMenu) {
      const url = window.location.origin + getDocumentUrl(contextMenu.backlink);
      window.open(url, '_blank');
      setContextMenu(null);
    }
  }, [contextMenu]);

  const handleCopyLink = useCallback(async () => {
    if (contextMenu) {
      const url = window.location.origin + getDocumentUrl(contextMenu.backlink);
      try {
        await navigator.clipboard.writeText(url);
        showToast('Link copied to clipboard', 'success');
      } catch {
        showToast('Failed to copy link', 'error');
      }
      setContextMenu(null);
    }
  }, [contextMenu, showToast]);

  const getDocumentTypeLabel = (type: string): string => {
    const labels: Record<string, string> = {
      wiki: 'Doc',
      issue: 'Issue',
      program: 'Program',
      project: 'Project',
      sprint: 'Week',
      person: 'Person',
      weekly_plan: 'Week Plan',
      weekly_retro: 'Week Retro',
    };
    return labels[type] || type;
  };

  if (loading) {
    return (
      <div className="space-y-2 p-4">
        <h3 className="text-xs font-medium text-muted">Backlinks</h3>
        <div className="text-xs text-muted">Loading...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="space-y-2 p-4">
        <h3 className="text-xs font-medium text-muted">Backlinks</h3>
        <div className="text-xs text-red-500">{error}</div>
      </div>
    );
  }

  return (
    <div className="space-y-2 p-4">
      <h3 className="text-xs font-medium text-muted">Backlinks</h3>

      {backlinks.length === 0 ? (
        <div className="text-xs text-muted">No backlinks</div>
      ) : (
        <div className="space-y-1">
          {backlinks.map((backlink) => (
            <div
              key={backlink.id}
              className="group relative"
            >
              <button
                onClick={() => handleNavigate(backlink)}
                onContextMenu={(e) => handleContextMenu(e, backlink)}
                className="w-full rounded px-2 py-1.5 text-left text-xs hover:bg-border transition-colors"
              >
                <div className="flex items-center gap-2">
                  <span className="rounded bg-border px-1.5 py-0.5 text-[10px] font-medium text-muted whitespace-nowrap">
                    {getDocumentTypeLabel(backlink.document_type)}
                  </span>
                  {backlink.display_id && (
                    <span className="font-mono text-[10px] text-muted">
                      {backlink.display_id}
                    </span>
                  )}
                </div>
                <div className="mt-0.5 truncate text-foreground">
                  {backlink.title || 'Untitled'}
                </div>
              </button>
              {/* Three-dot menu button */}
              <button
                type="button"
                onClick={(e) => handleMenuClick(e, backlink)}
                className="absolute right-1 top-1 p-0.5 rounded opacity-0 group-hover:opacity-100 hover:bg-border/50 text-muted hover:text-foreground transition-opacity"
                aria-label={`Actions for ${backlink.title || 'Untitled'}`}
              >
                <svg className="h-3 w-3" viewBox="0 0 24 24" fill="currentColor">
                  <circle cx="12" cy="5" r="2" />
                  <circle cx="12" cy="12" r="2" />
                  <circle cx="12" cy="19" r="2" />
                </svg>
              </button>
            </div>
          ))}
        </div>
      )}

      {/* Context menu */}
      {contextMenu && (
        <ContextMenu x={contextMenu.x} y={contextMenu.y} onClose={() => setContextMenu(null)}>
          <ContextMenuItem onClick={handleOpen}>
            <OpenIcon className="h-4 w-4" />
            Open
          </ContextMenuItem>
          <ContextMenuItem onClick={handleOpenInNewTab}>
            <ExternalLinkIcon className="h-4 w-4" />
            Open in new tab
          </ContextMenuItem>
          <ContextMenuItem onClick={handleCopyLink}>
            <LinkIcon className="h-4 w-4" />
            Copy link
          </ContextMenuItem>
        </ContextMenu>
      )}
    </div>
  );
}

// Icons
function OpenIcon({ className }: { className?: string }) {
  return (
    <svg className={cn('h-4 w-4', className)} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <path d="M9 5H7a2 2 0 0 0-2 2v12a2 2 0 0 0 2 2h10a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2h-2" />
      <rect x="9" y="3" width="6" height="4" rx="1" />
    </svg>
  );
}

function ExternalLinkIcon({ className }: { className?: string }) {
  return (
    <svg className={cn('h-4 w-4', className)} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6" />
      <polyline points="15 3 21 3 21 9" />
      <line x1="10" y1="14" x2="21" y2="3" />
    </svg>
  );
}

function LinkIcon({ className }: { className?: string }) {
  return (
    <svg className={cn('h-4 w-4', className)} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
      <path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71" />
      <path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71" />
    </svg>
  );
}

import { Extension } from '@tiptap/core';
import { Plugin, PluginKey } from '@tiptap/pm/state';
import type { Node } from '@tiptap/pm/model';
import { Decoration, DecorationSet } from '@tiptap/pm/view';
import { createRoot, Root } from 'react-dom/client';
import { Comment } from '@/hooks/useCommentsQuery';
import { formatRelativeTime } from '@/lib/date-utils';

/**
 * Groups comments by their comment_id (thread identifier).
 * Returns a map of commentId -> array of comments (root + replies).
 */
function groupByThread(comments: Comment[]): Map<string, Comment[]> {
  const threads = new Map<string, Comment[]>();
  for (const comment of comments) {
    const existing = threads.get(comment.comment_id) || [];
    existing.push(comment);
    threads.set(comment.comment_id, existing);
  }
  return threads;
}

/**
 * Find all comment mark positions in the document.
 * Returns a map of commentId -> end position of the containing block.
 */
function findCommentPositions(doc: Node): Map<string, number> {
  const positions = new Map<string, number>();

  doc.descendants((node: Node, pos: number) => {
    if (node.isText) {
      for (const mark of node.marks) {
        if (mark.type.name === 'commentMark' && mark.attrs.commentId) {
          const commentId = mark.attrs.commentId;
          // Always overwrite — doc.descendants iterates in document order,
          // so the last block containing the mark wins.
          const $pos = doc.resolve(pos);
          const blockEnd = $pos.end(Math.max(1, $pos.depth));
          positions.set(commentId, blockEnd);
        }
      }
    }
  });

  return positions;
}

export const commentDisplayPluginKey = new PluginKey('commentDisplay');

interface CommentDisplayStorage {
  comments: Comment[];
  onReply: ((commentId: string, content: string) => void) | null;
  onResolve: ((commentId: string, resolved: boolean) => void) | null;
  pendingCommentId: string | null;
  onSubmitComment: ((commentId: string, content: string) => void) | null;
  onCancelComment: ((commentId: string) => void) | null;
}

/**
 * InlineCommentThread component rendered inside widget decorations.
 * Displays a GitHub-style comment card that breaks the document flow.
 */
function InlineCommentThread({
  thread,
  quotedText,
  onReply,
  onResolve,
}: {
  thread: Comment[];
  quotedText: string;
  onReply: ((commentId: string, content: string) => void) | null;
  onResolve: ((commentId: string, resolved: boolean) => void) | null;
}) {
  const root = thread[0];
  const replies = thread.slice(1);
  const isResolved = root.resolved_at !== null;

  const container = document.createElement('div');

  // Create a simple DOM structure (no React inside decorations for simplicity)
  container.className = 'comment-thread-inline';
  container.setAttribute('data-comment-thread', root.comment_id);
  container.contentEditable = 'false';

  if (isResolved) {
    container.innerHTML = `
      <div class="comment-thread-resolved" data-comment-id="${escapeHtml(root.comment_id)}">
        <span class="comment-resolved-icon">✓</span>
        <span class="comment-resolved-text">Resolved by ${escapeHtml(root.author.name)} · ${formatRelativeTime(root.resolved_at!)}</span>
        <span class="comment-resolved-toggle">Show thread</span>
      </div>
    `;
  } else {
    const quotedHtml = quotedText
      ? `<div class="comment-quoted-text">"${escapeHtml(quotedText)}"</div>`
      : '';

    let repliesHtml = '';
    for (const reply of replies) {
      repliesHtml += `
        <div class="comment-reply">
          <div class="comment-header">
            <span class="comment-author">${escapeHtml(reply.author.name)}</span>
            <span class="comment-time">${formatRelativeTime(reply.created_at)}</span>
          </div>
          <div class="comment-body">${escapeHtml(reply.content)}</div>
        </div>
      `;
    }

    container.innerHTML = `
      ${quotedHtml}
      <div class="comment-root">
        <div class="comment-header">
          <span class="comment-author">${escapeHtml(root.author.name)}</span>
          <span class="comment-time">${formatRelativeTime(root.created_at)}</span>
          <button class="comment-resolve-btn" data-comment-id="${escapeHtml(root.comment_id)}" title="Resolve">✓</button>
        </div>
        <div class="comment-body">${escapeHtml(root.content)}</div>
      </div>
      ${repliesHtml}
      <div class="comment-reply-area">
        <input type="text" class="comment-reply-input" placeholder="Reply..." data-comment-id="${escapeHtml(root.comment_id)}" />
      </div>
    `;
  }

  return container;
}

function escapeHtml(str: string): string {
  const div = document.createElement('div');
  div.textContent = str;
  return div.innerHTML;
}

/**
 * CommentDisplay extension - Renders inline comment threads as widget decorations.
 *
 * Comments appear as bordered cards between content blocks, pushing content down
 * (like GitHub code review). The extension reads comment data from its storage,
 * which is updated by the parent Editor component via React Query.
 */
export const CommentDisplayExtension = Extension.create<Record<string, never>, CommentDisplayStorage>({
  name: 'commentDisplay',

  addStorage() {
    return {
      comments: [],
      onReply: null,
      onResolve: null,
      pendingCommentId: null,
      onSubmitComment: null,
      onCancelComment: null,
    };
  },

  addProseMirrorPlugins() {
    const storage = this.storage;

    return [
      new Plugin({
        key: commentDisplayPluginKey,
        props: {
          decorations: (state) => {
            const { doc } = state;
            const comments = storage.comments;
            const positions = findCommentPositions(doc);
            const decorations: Decoration[] = [];

            // Add pending comment input widget (before saved comments so it renders inline)
            const pendingId = storage.pendingCommentId;
            if (pendingId) {
              const pendingPos = positions.get(pendingId);
              if (pendingPos !== undefined) {
                const pendingWidget = Decoration.widget(pendingPos, () => {
                  const container = document.createElement('div');
                  container.className = 'comment-thread-inline comment-pending-input';
                  container.contentEditable = 'false';
                  container.innerHTML = `
                    <div class="comment-pending-label">Add your comment:</div>
                    <input type="text" class="comment-pending-field" placeholder="Write a comment..." data-pending-comment-id="${escapeHtml(pendingId)}" />
                    <div class="comment-pending-hint">Press Enter to submit, Escape to cancel</div>
                  `;
                  // Auto-focus the input after it's added to the DOM
                  requestAnimationFrame(() => {
                    const input = container.querySelector('.comment-pending-field');
                    if (input instanceof HTMLInputElement) {
                      input.focus();
                    }
                  });
                  return container;
                }, {
                  side: 1,
                  key: `pending-comment-${pendingId}`,
                });
                decorations.push(pendingWidget);
              }
            }

            if (!comments || comments.length === 0) {
              return DecorationSet.create(doc, decorations);
            }

            const threads = groupByThread(comments);

            // Sort positions by document order (ascending)
            const sortedEntries = [...positions.entries()].sort(
              (a, b) => a[1] - b[1]
            );

            // Add inline decorations to dim resolved comment highlights
            for (const [commentId, thread] of threads.entries()) {
              const isResolved = thread[0].resolved_at !== null;
              if (isResolved) {
                doc.descendants((node: Node, pos: number) => {
                  if (node.isText) {
                    for (const mark of node.marks) {
                      if (mark.type.name === 'commentMark' && mark.attrs.commentId === commentId) {
                        decorations.push(
                          Decoration.inline(pos, pos + node.nodeSize, {
                            class: 'comment-highlight-resolved',
                          })
                        );
                      }
                    }
                  }
                });
              }
            }

            for (const [commentId, blockEndPos] of sortedEntries) {
              const thread = threads.get(commentId);
              if (!thread || thread.length === 0) continue;

              // Find the quoted text for this comment
              let quotedText = '';
              doc.descendants((node: Node) => {
                if (node.isText) {
                  for (const mark of node.marks) {
                    if (
                      mark.type.name === 'commentMark' &&
                      mark.attrs.commentId === commentId
                    ) {
                      quotedText += node.text;
                    }
                  }
                }
              });

              const widget = Decoration.widget(blockEndPos, () => {
                return InlineCommentThread({
                  thread,
                  quotedText,
                  onReply: storage.onReply,
                  onResolve: storage.onResolve,
                });
              }, {
                side: 1, // Render after the position
                key: `comment-${commentId}-${thread.length}-${thread[0].resolved_at || 'open'}`,
              });

              decorations.push(widget);
            }

            return DecorationSet.create(doc, decorations);
          },

          handleDOMEvents: {
            click: (view, event) => {
              if (!(event.target instanceof HTMLElement)) return false;
              const target = event.target;

              // Handle resolve button click
              const resolveBtn = target.closest('.comment-resolve-btn');
              if (resolveBtn) {
                const commentId = resolveBtn instanceof HTMLElement ? resolveBtn.dataset.commentId : undefined;
                if (commentId && storage.onResolve) {
                  storage.onResolve(commentId, true);
                }
                event.preventDefault();
                return true;
              }

              // Handle "Show thread" click on resolved comments
              const resolvedToggle = target.closest('.comment-resolved-toggle');
              if (resolvedToggle) {
                const threadEl = resolvedToggle.closest('.comment-thread-inline');
                if (threadEl) {
                  const commentId = threadEl instanceof HTMLElement ? threadEl.dataset.commentThread : undefined;
                  if (commentId && storage.onResolve) {
                    storage.onResolve(commentId, false);
                  }
                }
                event.preventDefault();
                return true;
              }

              return false;
            },

            keydown: (view, event) => {
              if (!(event.target instanceof HTMLElement)) return false;
              const target = event.target;

              // Handle Enter/Escape on pending comment input
              if (target instanceof HTMLInputElement && target.classList.contains('comment-pending-field')) {
                const commentId = target.dataset.pendingCommentId;

                if (event.key === 'Enter' && !event.shiftKey) {
                  const content = target.value.trim();
                  if (commentId && content && storage.onSubmitComment) {
                    storage.onSubmitComment(commentId, content);
                  }
                  event.preventDefault();
                  return true;
                }

                if (event.key === 'Escape') {
                  if (commentId && storage.onCancelComment) {
                    storage.onCancelComment(commentId);
                  }
                  event.preventDefault();
                  return true;
                }

                // Prevent other keys from propagating to ProseMirror
                event.stopPropagation();
                return true;
              }

              // Handle Enter on reply input
              if (
                target instanceof HTMLInputElement &&
                target.classList.contains('comment-reply-input') &&
                event.key === 'Enter' &&
                !event.shiftKey
              ) {
                const commentId = target.dataset.commentId;
                const content = target.value.trim();

                if (commentId && content && storage.onReply) {
                  storage.onReply(commentId, content);
                  target.value = '';
                }
                event.preventDefault();
                return true;
              }

              return false;
            },
          },
        },
      }),
    ];
  },
});

