import { useState, useEffect, useCallback, useMemo } from 'react';
import { Combobox } from '@/components/ui/Combobox';
import { MultiAssociationChips } from '@/components/ui/MultiAssociationChips';
import { PropertyRow } from '@/components/ui/PropertyRow';
import { ConfirmDialog } from '@/components/ConfirmDialog';
import { isCascadeWarningError, type IncompleteChild } from '@/hooks/useIssuesQuery';
import { apiPost, apiDelete } from '@/lib/api';
import { formatDateRange } from '@/lib/date-utils';
import type { BelongsTo, BelongsToType } from '@ship/shared';

const API_URL = import.meta.env.VITE_API_URL ?? '';

interface Issue {
  id: string;
  state: string;
  priority: string;
  estimate: number | null;
  assignee_id: string | null;
  assignee_name?: string | null;
  assignee_archived?: boolean;
  source?: 'internal' | 'external';
  rejection_reason?: string | null;
  converted_from_id?: string | null;
  /** Multi-parent associations via junction table */
  belongs_to?: BelongsTo[];
}

interface TeamMember {
  id: string;
  user_id: string;
  name: string;
}

interface Program {
  id: string;
  name: string;
  color?: string;
}

interface Project {
  id: string;
  title: string;
  color?: string;
}

interface Sprint {
  id: string;
  name: string;
  status: string;
  sprint_number: number;
}

interface IssueSidebarProps {
  issue: Issue;
  teamMembers: TeamMember[];
  programs: Program[];
  /** Available projects for multi-association */
  projects?: Project[];
  onUpdate: (updates: Partial<Issue>) => Promise<void>;
  /** Called after an association is added/removed via API */
  onAssociationChange?: () => void;
  onConvert?: () => void;
  onUndoConversion?: () => void;
  onAccept?: () => Promise<void>;
  onReject?: (reason: string) => Promise<void>;
  isConverting?: boolean;
  isUndoing?: boolean;
  /** Fields to highlight as missing (e.g., after type conversion) */
  highlightedFields?: string[];
}

const STATES = [
  { value: 'triage', label: 'Needs Triage' },
  { value: 'backlog', label: 'Backlog' },
  { value: 'todo', label: 'Todo' },
  { value: 'in_progress', label: 'In Progress' },
  { value: 'in_review', label: 'In Review' },
  { value: 'done', label: 'Done' },
  { value: 'cancelled', label: 'Cancelled' },
];

const PRIORITIES = [
  { value: 'urgent', label: 'Urgent' },
  { value: 'high', label: 'High' },
  { value: 'medium', label: 'Medium' },
  { value: 'low', label: 'Low' },
  { value: 'none', label: 'No Priority' },
];

// Compute sprint dates from sprint number (1-week sprints)
function computeSprintDates(sprintNumber: number, workspaceStartDate: Date): { start: Date; end: Date } {
  const start = new Date(workspaceStartDate);
  start.setDate(start.getDate() + (sprintNumber - 1) * 7);
  start.setHours(0, 0, 0, 0);
  const end = new Date(start);
  end.setDate(end.getDate() + 6);
  end.setHours(23, 59, 59, 999);
  return { start, end };
}

export function IssueSidebar({
  issue,
  teamMembers,
  programs,
  projects = [],
  onUpdate,
  onAssociationChange,
  onConvert,
  onUndoConversion,
  onAccept,
  onReject,
  isConverting = false,
  isUndoing = false,
  highlightedFields = [],
}: IssueSidebarProps) {
  // Helper to check if a field should be highlighted
  const isHighlighted = (field: string) => highlightedFields.includes(field);
  const [sprints, setSprints] = useState<Sprint[]>([]);
  const [workspaceSprintStartDate, setWorkspaceSprintStartDate] = useState<Date | null>(null);
  const [sprintError, setSprintError] = useState<string | null>(null);
  const [showRejectDialog, setShowRejectDialog] = useState(false);
  const [rejectReason, setRejectReason] = useState('');
  // Cascade warning state for closing parent with incomplete children
  const [cascadeWarning, setCascadeWarning] = useState<{
    open: boolean;
    pendingState: string | null;
    incompleteChildren: IncompleteChild[];
  }>({ open: false, pendingState: null, incompleteChildren: [] });

  // Get current associations from issue - memoize to prevent infinite re-renders
  const belongsTo = useMemo(() => issue.belongs_to || [], [issue.belongs_to]);

  // Handle state change with cascade warning detection
  const handleStateChange = async (newState: string) => {
    try {
      await onUpdate({ state: newState });
    } catch (error) {
      if (isCascadeWarningError(error)) {
        setCascadeWarning({
          open: true,
          pendingState: newState,
          incompleteChildren: error.warning.incomplete_children,
        });
      } else {
        throw error;
      }
    }
  };

  // Confirm closing parent with incomplete children
  const handleCascadeConfirm = async () => {
    if (cascadeWarning.pendingState) {
      await onUpdate({
        state: cascadeWarning.pendingState,
        confirm_orphan_children: true,
      } as Partial<Issue> & { confirm_orphan_children: boolean });
    }
    setCascadeWarning({ open: false, pendingState: null, incompleteChildren: [] });
  };

  // Cancel cascade warning
  const handleCascadeCancel = () => {
    setCascadeWarning({ open: false, pendingState: null, incompleteChildren: [] });
  };

  // Fetch sprints when issue's program changes
  useEffect(() => {
    // Get program from belongs_to
    const programAssoc = belongsTo.find(bt => bt.type === 'program');
    const programId = programAssoc?.id;

    if (!programId) {
      setSprints([]);
      setWorkspaceSprintStartDate(null);
      return;
    }

    let cancelled = false;

    fetch(`${API_URL}/api/programs/${programId}/sprints`, { credentials: 'include' })
      .then(res => res.ok ? res.json() : { weeks: [], workspace_sprint_start_date: null })
      .then(data => {
        if (!cancelled) {
          setSprints(data.weeks || []);
          if (data.workspace_sprint_start_date) {
            setWorkspaceSprintStartDate(new Date(data.workspace_sprint_start_date));
          }
        }
      })
      .catch(() => {
        if (!cancelled) {
          setSprints([]);
          setWorkspaceSprintStartDate(null);
        }
      });

    return () => { cancelled = true; };
  }, [belongsTo]);

  // Add association via junction table API
  const handleAddAssociation = useCallback(async (relatedId: string, type: BelongsToType) => {
    const response = await apiPost(`/api/documents/${issue.id}/associations`, {
      related_id: relatedId,
      relationship_type: type,
    });
    if (!response.ok) {
      throw new Error('Failed to add association');
    }
    // Trigger refetch of issue data
    onAssociationChange?.();
  }, [issue.id, onAssociationChange]);

  // Remove association via junction table API
  const handleRemoveAssociation = useCallback(async (relatedId: string, type: BelongsToType) => {
    const response = await apiDelete(`/api/documents/${issue.id}/associations/${relatedId}?type=${type}`);
    if (!response.ok) {
      throw new Error('Failed to remove association');
    }
    // Trigger refetch of issue data
    onAssociationChange?.();
  }, [issue.id, onAssociationChange]);

  // Legacy program change handler (updates belongs_to via onUpdate)
  const handleProgramChange = async (programId: string | null) => {
    // Build new belongs_to array with updated program
    const newBelongsTo = belongsTo.filter(bt => bt.type !== 'program' && bt.type !== 'sprint');
    if (programId) {
      newBelongsTo.push({ id: programId, type: 'program' });
    }
    await onUpdate({ belongs_to: newBelongsTo } as Partial<Issue>);
  };

  // Legacy sprint change handler
  const handleSprintChange = async (sprintId: string | null) => {
    if (sprintId && !issue.estimate) {
      setSprintError('Please add an estimate before assigning to a week');
      return;
    }
    setSprintError(null);
    // Build new belongs_to array with updated sprint
    const newBelongsTo = belongsTo.filter(bt => bt.type !== 'sprint');
    if (sprintId) {
      newBelongsTo.push({ id: sprintId, type: 'sprint' });
    }
    await onUpdate({ belongs_to: newBelongsTo } as Partial<Issue>);
  };

  const handleReject = () => {
    if (rejectReason.trim() && onReject) {
      onReject(rejectReason.trim());
      setRejectReason('');
      setShowRejectDialog(false);
    }
  };

  // Get current program/sprint from belongs_to
  const currentProgramId = belongsTo.find(bt => bt.type === 'program')?.id ?? null;
  const currentSprintId = belongsTo.find(bt => bt.type === 'sprint')?.id ?? null;

  return (
    <div className="space-y-4 p-4">
      {/* Undo Conversion Banner */}
      {issue.converted_from_id && onUndoConversion && (
        <div className="mb-4 rounded-lg border border-blue-500/30 bg-blue-500/10 p-3">
          <p className="mb-2 text-sm text-blue-300">This issue was converted from a project.</p>
          <button
            onClick={onUndoConversion}
            disabled={isUndoing}
            className="w-full rounded bg-blue-600 px-3 py-1.5 text-sm font-medium text-white hover:bg-blue-700 disabled:opacity-50 transition-colors flex items-center justify-center gap-2"
          >
            {isUndoing ? (
              <>
                <svg className="w-4 h-4 animate-spin" viewBox="0 0 24 24" fill="none">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                </svg>
                Undoing...
              </>
            ) : (
              <>
                <svg className="w-4 h-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M7.707 3.293a1 1 0 010 1.414L5.414 7H11a7 7 0 017 7v2a1 1 0 11-2 0v-2a5 5 0 00-5-5H5.414l2.293 2.293a1 1 0 11-1.414 1.414l-4-4a1 1 0 010-1.414l4-4a1 1 0 011.414 0z" clipRule="evenodd" />
                </svg>
                Undo Conversion
              </>
            )}
          </button>
          <p className="mt-1 text-xs text-blue-300/70 text-center">Restore the original project</p>
        </div>
      )}

      {/* Triage Actions */}
      {issue.state === 'triage' && onAccept && onReject && (
        <div className="mb-4 rounded-lg border border-amber-500/30 bg-amber-500/10 p-3">
          <p className="mb-3 text-sm font-medium text-amber-300">Needs Triage</p>
          {!showRejectDialog ? (
            <div className="flex gap-2">
              <button
                onClick={onAccept}
                className="flex-1 rounded bg-green-600 px-3 py-1.5 text-sm font-medium text-white hover:bg-green-700 transition-colors"
              >
                Accept
              </button>
              <button
                onClick={() => setShowRejectDialog(true)}
                className="flex-1 rounded bg-red-600 px-3 py-1.5 text-sm font-medium text-white hover:bg-red-700 transition-colors"
              >
                Reject
              </button>
            </div>
          ) : (
            <div className="space-y-2">
              <textarea
                value={rejectReason}
                onChange={(e) => setRejectReason(e.target.value)}
                placeholder="Reason for rejection..."
                className="w-full rounded border border-border bg-border/50 px-2 py-1.5 text-sm text-foreground placeholder:text-muted focus:outline-none focus:ring-1 focus:ring-accent"
                rows={2}
              />
              <div className="flex gap-2">
                <button
                  onClick={() => { setShowRejectDialog(false); setRejectReason(''); }}
                  className="flex-1 rounded bg-border px-2 py-1 text-sm text-muted hover:text-foreground transition-colors"
                >
                  Cancel
                </button>
                <button
                  onClick={handleReject}
                  disabled={!rejectReason.trim()}
                  className="flex-1 rounded bg-red-600 px-2 py-1 text-sm font-medium text-white hover:bg-red-700 disabled:opacity-50 transition-colors"
                >
                  Reject
                </button>
              </div>
            </div>
          )}
        </div>
      )}

      <PropertyRow label="Status" highlighted={isHighlighted('state')}>
        <select
          value={issue.state}
          onChange={(e) => handleStateChange(e.target.value)}
          aria-label="Status"
          className={`w-full rounded px-2 py-1 text-sm text-foreground focus:outline-none focus:ring-1 focus:ring-accent ${
            isHighlighted('state') ? 'bg-amber-500/20 border border-amber-500' : 'bg-border'
          }`}
        >
          {STATES.map((s) => (
            <option key={s.value} value={s.value}>
              {s.label}
            </option>
          ))}
        </select>
      </PropertyRow>

      <PropertyRow label="Priority" highlighted={isHighlighted('priority')}>
        <select
          value={issue.priority}
          onChange={(e) => onUpdate({ priority: e.target.value })}
          aria-label="Priority"
          className={`w-full rounded px-2 py-1 text-sm text-foreground focus:outline-none focus:ring-1 focus:ring-accent ${
            isHighlighted('priority') ? 'bg-amber-500/20 border border-amber-500' : 'bg-border'
          }`}
        >
          {PRIORITIES.map((p) => (
            <option key={p.value} value={p.value}>
              {p.label}
            </option>
          ))}
        </select>
      </PropertyRow>

      <PropertyRow label="Estimate">
        <div className="flex items-center gap-2">
          <input
            type="number"
            step="0.5"
            min="0"
            placeholder="—"
            aria-label="Estimate in hours"
            value={issue.estimate ?? ''}
            onChange={(e) => {
              const value = e.target.value ? parseFloat(e.target.value) : null;
              onUpdate({ estimate: value });
              if (value) setSprintError(null);
            }}
            className="w-20 rounded bg-border px-2 py-1 text-sm text-foreground focus:outline-none focus:ring-1 focus:ring-accent"
          />
          <span className="text-xs text-muted">hours</span>
        </div>
      </PropertyRow>

      <PropertyRow label="Assignee">
        <Combobox
          options={(() => {
            const options = teamMembers.map((m) => ({ value: m.user_id, label: m.name }));
            // If current assignee is archived and not in the active team members list, add them
            if (issue.assignee_id && issue.assignee_archived && issue.assignee_name) {
              const exists = options.some(o => o.value === issue.assignee_id);
              if (!exists) {
                options.unshift({ value: issue.assignee_id, label: `${issue.assignee_name} (archived)` });
              }
            }
            return options;
          })()}
          value={issue.assignee_id}
          onChange={(value) => onUpdate({ assignee_id: value })}
          placeholder="Unassigned"
          clearLabel="Unassigned"
          searchPlaceholder="Search people..."
          emptyText="No people found"
          aria-label="Assignee"
        />
      </PropertyRow>

      {/* Projects - Multi-association chips */}
      <PropertyRow label="Projects">
        <MultiAssociationChips
          associations={belongsTo}
          options={projects.map(p => ({ id: p.id, name: p.title, color: p.color, href: `/documents/${p.id}` }))}
          type="project"
          onAdd={handleAddAssociation}
          onRemove={handleRemoveAssociation}
          placeholder={projects.length > 0 ? "Add project..." : "No projects yet"}
          aria-label="Projects"
        />
      </PropertyRow>

      {/* Programs - Multi-association chips */}
      <PropertyRow label="Programs">
        <MultiAssociationChips
          associations={belongsTo}
          options={programs.map(p => ({ id: p.id, name: p.name, color: p.color, href: `/programs/${p.id}` }))}
          type="program"
          onAdd={handleAddAssociation}
          onRemove={handleRemoveAssociation}
          placeholder="Add program..."
          aria-label="Programs"
        />
      </PropertyRow>

      {/* Week - still uses single-select since weeks depend on program selection */}
      {currentProgramId && (
        <PropertyRow label="Week">
          <Combobox
            options={sprints.map((s) => {
              let dateRange = '';
              if (workspaceSprintStartDate) {
                const { start, end } = computeSprintDates(s.sprint_number, workspaceSprintStartDate);
                dateRange = formatDateRange(start, end);
              }
              return { value: s.id, label: s.name, description: dateRange };
            })}
            value={currentSprintId}
            onChange={(value) => handleSprintChange(value)}
            placeholder="No Week"
            clearLabel="No Week"
            searchPlaceholder="Search weeks..."
            emptyText="No weeks found"
            aria-label="Week"
          />
          {sprintError && (
            <p className="mt-1 text-xs text-red-500">{sprintError}</p>
          )}
        </PropertyRow>
      )}

      <PropertyRow label="Source">
        <span className={`inline-flex items-center rounded px-2 py-0.5 text-xs font-medium whitespace-nowrap ${
          issue.source === 'external' ? 'bg-purple-500/20 text-purple-300' : 'bg-blue-500/20 text-blue-300'
        }`}>
          {issue.source === 'external' ? 'External' : 'Internal'}
        </span>
      </PropertyRow>

      {issue.state === 'cancelled' && issue.rejection_reason && (
        <PropertyRow label="Rejection Reason">
          <span className="text-sm text-red-300">{issue.rejection_reason}</span>
        </PropertyRow>
      )}

      {/* Document Conversion */}
      {onConvert && (
        <div className="pt-4 mt-4 border-t border-border">
          <button
            onClick={onConvert}
            disabled={isConverting}
            className="w-full rounded bg-accent/20 px-3 py-2 text-sm font-medium text-accent hover:bg-accent/30 disabled:opacity-50 transition-colors flex items-center justify-center gap-2"
          >
            {isConverting ? (
              <>
                <svg className="w-4 h-4 animate-spin" viewBox="0 0 24 24" fill="none">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                </svg>
                Converting...
              </>
            ) : (
              <>
                <svg className="w-4 h-4" viewBox="0 0 20 20" fill="currentColor">
                  <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-8.707l-3-3a1 1 0 00-1.414 1.414L10.586 9H7a1 1 0 100 2h3.586l-1.293 1.293a1 1 0 101.414 1.414l3-3a1 1 0 000-1.414z" clipRule="evenodd" />
                </svg>
                Promote to Project
              </>
            )}
          </button>
          <p className="mt-1 text-xs text-muted text-center">Convert this issue into a project</p>
        </div>
      )}

      {/* Cascade Warning Dialog */}
      <ConfirmDialog
        open={cascadeWarning.open}
        title="Incomplete Sub-Issues"
        description={`This issue has ${cascadeWarning.incompleteChildren.length} incomplete sub-issue(s). Closing it will remove their parent relationship, making them top-level issues.`}
        confirmLabel="Close Anyway"
        cancelLabel="Keep Open"
        variant="destructive"
        onConfirm={handleCascadeConfirm}
        onCancel={handleCascadeCancel}
      >
        <div className="max-h-32 overflow-y-auto">
          <ul className="space-y-1 text-sm">
            {cascadeWarning.incompleteChildren.map((child) => (
              <li key={child.id} className="flex items-center gap-2 text-muted">
                <span className="font-mono text-xs text-accent">#{child.ticket_number}</span>
                <span className="truncate">{child.title}</span>
                <span className="ml-auto rounded bg-border px-1.5 py-0.5 text-xs">
                  {child.state}
                </span>
              </li>
            ))}
          </ul>
        </div>
      </ConfirmDialog>
    </div>
  );
}

/**
 * ProjectContextSidebar - Sidebar for viewing documents in project context
 *
 * Shows a tree view of project-related documents when viewing weekly plans/retros
 * that belong to a project. Helps users understand the context and navigate
 * between related documents.
 */
import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';
import { apiGet } from '@/lib/api';
import { cn } from '@/lib/cn';

interface ProjectContextSidebarProps {
  projectId: string;
  activeDocumentId?: string;
}

interface ProjectData {
  id: string;
  title: string;
  color: string;
}

interface ProjectIssue {
  id: string;
  title: string;
  state: string;
  ticket_number?: number;
}

interface AllocationGridResponse {
  project: { id: string; title: string };
  people: Array<{
    id: string;
    name: string;
    weeks: Array<{
      week_number: number;
      plan?: { id: string; status: string };
      retro?: { id: string; status: string };
    }>;
  }>;
  weeks: number[];
}

// Icons
function ProjectIcon({ className }: { className?: string }) {
  return (
    <svg className={cn('h-4 w-4', className)} fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 17V7m0 10a2 2 0 01-2 2H5a2 2 0 01-2-2V7a2 2 0 012-2h2a2 2 0 012 2m0 10a2 2 0 002 2h2a2 2 0 002-2M9 7a2 2 0 012-2h2a2 2 0 012 2m0 10V7m0 10a2 2 0 002 2h2a2 2 0 002-2V7a2 2 0 00-2-2h-2a2 2 0 00-2 2" />
    </svg>
  );
}

function DocumentIcon({ className }: { className?: string }) {
  return (
    <svg className={cn('h-3.5 w-3.5', className)} fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" />
    </svg>
  );
}

function ChevronIcon({ expanded }: { expanded: boolean }) {
  return (
    <svg
      className={cn('h-3.5 w-3.5 text-muted transition-transform', expanded && 'rotate-90')}
      fill="none"
      stroke="currentColor"
      viewBox="0 0 24 24"
    >
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
    </svg>
  );
}

function IssueIcon({ className }: { className?: string }) {
  return (
    <svg className={cn('h-3.5 w-3.5', className)} fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
    </svg>
  );
}

function PersonIcon({ className }: { className?: string }) {
  return (
    <svg className={cn('h-3.5 w-3.5', className)} fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
    </svg>
  );
}

function CalendarIcon({ className }: { className?: string }) {
  return (
    <svg className={cn('h-3.5 w-3.5', className)} fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
    </svg>
  );
}

function RetroIcon({ className }: { className?: string }) {
  return (
    <svg className={cn('h-3.5 w-3.5', className)} fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 5l7 7-7 7" />
    </svg>
  );
}

// Status color mapping
const statusColors: Record<string, string> = {
  done: 'bg-green-500',
  due: 'bg-yellow-500',
  late: 'bg-red-500',
  future: 'bg-gray-400',
};

export function ProjectContextSidebar({ projectId, activeDocumentId }: ProjectContextSidebarProps) {
  const navigate = useNavigate();
  const [projectExpanded, setProjectExpanded] = useState(true);
  const [expandedPeople, setExpandedPeople] = useState<Set<string>>(new Set());
  const [showIssues, setShowIssues] = useState(false);

  // Fetch project details
  const { data: project, isLoading: projectLoading } = useQuery<ProjectData>({
    queryKey: ['document', projectId],
    queryFn: async () => {
      const res = await apiGet(`/api/documents/${projectId}`);
      if (!res.ok) throw new Error('Failed to fetch project');
      return res.json();
    },
    enabled: !!projectId,
  });

  // Fetch allocation grid data (includes weekly plans/retros)
  const { data: gridData, isLoading: gridLoading } = useQuery<AllocationGridResponse>({
    queryKey: ['project-allocation-grid', projectId],
    queryFn: async () => {
      const res = await apiGet(`/api/weekly-plans/project-allocation-grid/${projectId}`);
      if (!res.ok) throw new Error('Failed to fetch allocation grid');
      return res.json();
    },
    enabled: !!projectId,
  });

  // Fetch project issues
  const { data: issues = [], isLoading: issuesLoading } = useQuery<ProjectIssue[]>({
    queryKey: ['project-issues', projectId],
    queryFn: async () => {
      const res = await apiGet(`/api/issues?project_id=${projectId}`);
      if (!res.ok) throw new Error('Failed to fetch issues');
      return res.json();
    },
    enabled: !!projectId && showIssues,
  });

  const togglePerson = (personId: string) => {
    setExpandedPeople(prev => {
      const next = new Set(prev);
      if (next.has(personId)) {
        next.delete(personId);
      } else {
        next.add(personId);
      }
      return next;
    });
  };

  const isLoading = projectLoading || gridLoading;

  if (isLoading) {
    return (
      <div className="px-3 py-2 text-sm text-muted">
        Loading project context...
      </div>
    );
  }

  if (!project || !gridData) {
    return (
      <div className="px-3 py-2 text-sm text-muted">
        Project not found
      </div>
    );
  }

  const hasPeople = gridData.people && gridData.people.length > 0;

  return (
    <div className="space-y-1" data-testid="project-context-sidebar">
      {/* Project tree with expandable tabs */}
      <ul className="space-y-0.5 px-2 py-2" role="tree">
        {/* Project root node */}
        <li role="treeitem">
          <button
            onClick={() => setProjectExpanded(prev => !prev)}
            className="flex w-full items-center gap-2 rounded-md px-2 py-1.5 text-sm font-medium text-foreground hover:bg-border/30 transition-colors"
          >
            <ChevronIcon expanded={projectExpanded} />
            <span
              className="h-3 w-3 rounded-full flex-shrink-0"
              style={{ backgroundColor: project.color || '#6366f1' }}
            />
            <span className="truncate">{project.title || 'Untitled'}</span>
          </button>

          {/* Project tabs */}
          {projectExpanded && (
            <ul className="ml-4 space-y-0.5 mt-0.5" role="group">
              {/* Details tab */}
              <li role="treeitem">
                <Link
                  to={`/documents/${projectId}`}
                  className={cn(
                    'flex items-center gap-1.5 rounded-md px-2 py-1.5 text-sm transition-colors',
                    'text-muted hover:bg-border/30 hover:text-foreground'
                  )}
                >
                  <DocumentIcon className="text-muted" />
                  <span>Details</span>
                </Link>
              </li>

              {/* Weeks tab */}
              <li role="treeitem">
                <Link
                  to={`/documents/${projectId}/weeks`}
                  className={cn(
                    'flex items-center gap-1.5 rounded-md px-2 py-1.5 text-sm transition-colors',
                    'text-muted hover:bg-border/30 hover:text-foreground'
                  )}
                >
                  <CalendarIcon className="text-muted" />
                  <span>Weeks</span>
                </Link>
              </li>

              {/* Issues tab */}
              <li role="treeitem">
                <Link
                  to={`/documents/${projectId}/issues`}
                  className={cn(
                    'flex items-center gap-1.5 rounded-md px-2 py-1.5 text-sm transition-colors',
                    'text-muted hover:bg-border/30 hover:text-foreground'
                  )}
                >
                  <IssueIcon className="text-muted" />
                  <span>Issues</span>
                </Link>
              </li>

              {/* Retro tab */}
              <li role="treeitem">
                <Link
                  to={`/documents/${projectId}/retro`}
                  className={cn(
                    'flex items-center gap-1.5 rounded-md px-2 py-1.5 text-sm transition-colors',
                    'text-muted hover:bg-border/30 hover:text-foreground'
                  )}
                >
                  <RetroIcon className="text-muted" />
                  <span>Retro</span>
                </Link>
              </li>
            </ul>
          )}
        </li>
      </ul>

      {/* Separator */}
      <div className="border-t border-border mx-2" />

      {/* Weekly accountability section */}
      <div className="pt-1">
        <div className="flex items-center gap-1.5 px-3 py-1 text-xs font-medium text-muted uppercase tracking-wider">
          <DocumentIcon className="text-muted" />
          Weekly Docs
        </div>

        {!hasPeople ? (
          <div className="px-3 py-2 text-xs text-muted">
            No team members allocated
          </div>
        ) : (
          <ul className="space-y-0.5 px-2" role="tree">
            {gridData.people.map(person => {
              const isExpanded = expandedPeople.has(person.id);
              const hasWeeks = person.weeks && person.weeks.length > 0;

              return (
                <li key={person.id} role="treeitem">
                  {/* Person row */}
                  <button
                    onClick={() => togglePerson(person.id)}
                    className={cn(
                      'flex w-full items-center gap-1.5 rounded-md px-2 py-1.5 text-sm transition-colors text-left',
                      'text-muted hover:bg-border/30 hover:text-foreground'
                    )}
                  >
                    {hasWeeks && <ChevronIcon expanded={isExpanded} />}
                    {!hasWeeks && <PersonIcon className="text-muted" />}
                    <span className="truncate flex-1">{person.name}</span>
                    {hasWeeks && (
                      <span className="text-xs text-muted">
                        {person.weeks.length}w
                      </span>
                    )}
                  </button>

                  {/* Weeks for this person */}
                  {isExpanded && hasWeeks && (
                    <ul className="ml-4 space-y-0.5" role="group">
                      {person.weeks.map(week => (
                        <li key={week.week_number} className="space-y-0.5">
                          <div className="px-2 py-1 text-xs font-medium text-muted">
                            Week {week.week_number}
                          </div>

                          {/* Plan link */}
                          {week.plan && (
                            <Link
                              to={`/documents/${week.plan.id}`}
                              className={cn(
                                'flex items-center gap-1.5 rounded-md px-2 py-1 text-xs transition-colors ml-2',
                                activeDocumentId === week.plan.id
                                  ? 'bg-border/50 text-foreground'
                                  : 'text-muted hover:bg-border/30 hover:text-foreground'
                              )}
                            >
                              <span className={cn('h-2 w-2 rounded-full', statusColors[week.plan.status] || 'bg-gray-400')} />
                              <span>Plan</span>
                            </Link>
                          )}

                          {/* Retro link */}
                          {week.retro && (
                            <Link
                              to={`/documents/${week.retro.id}`}
                              className={cn(
                                'flex items-center gap-1.5 rounded-md px-2 py-1 text-xs transition-colors ml-2',
                                activeDocumentId === week.retro.id
                                  ? 'bg-border/50 text-foreground'
                                  : 'text-muted hover:bg-border/30 hover:text-foreground'
                              )}
                            >
                              <span className={cn('h-2 w-2 rounded-full', statusColors[week.retro.status] || 'bg-gray-400')} />
                              <span>Retro</span>
                            </Link>
                          )}
                        </li>
                      ))}
                    </ul>
                  )}
                </li>
              );
            })}
          </ul>
        )}
      </div>

      {/* Separator */}
      <div className="border-t border-border mx-2 my-2" />

      {/* Issues section (expandable) */}
      <div>
        <button
          onClick={() => setShowIssues(prev => !prev)}
          className="flex w-full items-center gap-1.5 px-3 py-1 text-xs font-medium text-muted uppercase tracking-wider hover:text-foreground transition-colors"
        >
          <ChevronIcon expanded={showIssues} />
          <IssueIcon className="text-muted" />
          Issues
        </button>

        {showIssues && (
          <ul className="space-y-0.5 px-2 mt-1">
            {issuesLoading ? (
              <li className="px-2 py-1 text-xs text-muted">Loading...</li>
            ) : issues.length === 0 ? (
              <li className="px-2 py-1 text-xs text-muted">No issues</li>
            ) : (
              issues.map(issue => (
                <li key={issue.id}>
                  <Link
                    to={`/documents/${issue.id}`}
                    className={cn(
                      'flex items-center gap-1.5 rounded-md px-2 py-1.5 text-xs transition-colors',
                      activeDocumentId === issue.id
                        ? 'bg-border/50 text-foreground'
                        : 'text-muted hover:bg-border/30 hover:text-foreground'
                    )}
                  >
                    <IssueIcon className="flex-shrink-0 text-muted" />
                    <span className="truncate">
                      {issue.ticket_number ? `#${issue.ticket_number} ` : ''}
                      {issue.title || 'Untitled'}
                    </span>
                  </Link>
                </li>
              ))
            )}
          </ul>
        )}
      </div>
    </div>
  );
}

/**
 * PropertiesPanel - Unified sidebar component that renders type-specific properties
 *
 * This component consolidates the 4 type-specific sidebars into a single entry point.
 * It adapts based on document_type while maintaining the same rendering patterns.
 */
import { useMemo, useCallback } from 'react';
import { useQuery } from '@tanstack/react-query';
import { WikiSidebar } from '@/components/sidebars/WikiSidebar';
import { IssueSidebar } from '@/components/sidebars/IssueSidebar';
import { ProjectSidebar } from '@/components/sidebars/ProjectSidebar';
import { WeekSidebar } from '@/components/sidebars/WeekSidebar';
import { ProgramSidebar } from '@/components/sidebars/ProgramSidebar';
import { ContentHistoryPanel } from '@/components/ContentHistoryPanel';
import { PlanQualityAssistant, RetroQualityAssistant } from '@/components/sidebars/QualityAssistant';
import { useWorkspace } from '@/contexts/WorkspaceContext';
import { useAuth } from '@/hooks/useAuth';
import { apiGet } from '@/lib/api';
import { cn } from '@/lib/cn';
import type { WeeklyReviewActionsState } from '@/hooks/useWeeklyReviewActions';
import type { Person } from '@/components/PersonCombobox';
import type { BelongsTo, ApprovalTracking } from '@ship/shared';

// Document types that have properties panels
export type PanelDocumentType = 'wiki' | 'issue' | 'project' | 'sprint' | 'program' | 'weekly_plan' | 'weekly_retro';

// Base document interface
interface BaseDocument {
  id: string;
  title: string;
  document_type: string;
  created_at?: string;
  updated_at?: string;
  created_by?: string | null;
  properties?: Record<string, unknown>;
}

// Wiki document properties
interface WikiDocument extends BaseDocument {
  document_type: 'wiki';
  parent_id?: string | null;
  visibility?: 'private' | 'workspace';
}

// Issue document properties
interface IssueDocument extends BaseDocument {
  document_type: 'issue';
  state: string;
  priority: string;
  estimate: number | null;
  assignee_id: string | null;
  assignee_name?: string | null;
  assignee_archived?: boolean;
  program_id: string | null;
  sprint_id: string | null;
  source?: 'internal' | 'external';
  rejection_reason?: string | null;
  converted_from_id?: string | null;
  belongs_to?: BelongsTo[];
}

// Project document properties
interface ProjectDocument extends BaseDocument {
  document_type: 'project';
  impact: number | null;
  confidence: number | null;
  ease: number | null;
  ice_score?: number | null;
  color: string;
  emoji: string | null;
  program_id: string | null;
  owner?: { id: string; name: string; email: string } | null;
  owner_id?: string | null;
  // RACI fields
  accountable_id?: string | null;
  consulted_ids?: string[];
  informed_ids?: string[];
  sprint_count?: number;
  issue_count?: number;
  converted_from_id?: string | null;
  // Approval tracking
  plan?: string | null;
  plan_approval?: ApprovalTracking | null;
  retro_approval?: ApprovalTracking | null;
  has_retro?: boolean;
}

// Sprint document properties
interface SprintDocument extends BaseDocument {
  document_type: 'sprint';
  status: 'planning' | 'active' | 'completed';
  program_id: string | null;
  program_name?: string;
  program_accountable_id?: string | null;
  owner_reports_to?: string | null;
  issue_count?: number;
  completed_count?: number;
  plan?: string;
  owner?: { id: string; name: string; email: string } | null;
  owner_id?: string | null;
  // Approval tracking
  plan_approval?: ApprovalTracking | null;
  review_approval?: ApprovalTracking | null;
  accountable_id?: string | null;
  has_review?: boolean;
}

// Program document properties
interface ProgramDocument extends BaseDocument {
  document_type: 'program';
  color?: string;
  emoji?: string | null;
  owner_id?: string | null;
  // RACI fields
  accountable_id?: string | null;
  consulted_ids?: string[];
  informed_ids?: string[];
}

// Weekly plan document properties
interface WeeklyPlanDocument extends BaseDocument {
  document_type: 'weekly_plan';
  properties?: {
    person_id?: string;
    project_id?: string;
    week_number?: number;
    submitted_at?: string | null;
  };
}

// Weekly retro document properties
interface WeeklyRetroDocument extends BaseDocument {
  document_type: 'weekly_retro';
  properties?: {
    person_id?: string;
    project_id?: string;
    week_number?: number;
    submitted_at?: string | null;
  };
}

// Union type for all documents
export type PanelDocument = WikiDocument | IssueDocument | ProjectDocument | SprintDocument | ProgramDocument | WeeklyPlanDocument | WeeklyRetroDocument;

// Props for wiki panel
interface WikiPanelProps {
  teamMembers: Person[];
  currentUserId?: string;
}

// Props for issue panel
interface IssuePanelProps {
  teamMembers: Array<{ id: string; user_id: string; name: string }>;
  programs: Array<{ id: string; name: string; color?: string }>;
  projects?: Array<{ id: string; title: string; color?: string }>;
  onConvert?: () => void;
  onUndoConversion?: () => void;
  onAccept?: () => Promise<void>;
  onReject?: (reason: string) => Promise<void>;
  isConverting?: boolean;
  isUndoing?: boolean;
  onAssociationChange?: () => void;
}

// Props for project panel
interface ProjectPanelProps {
  programs: Array<{ id: string; name: string; color: string; emoji?: string | null }>;
  people: Person[];
  onConvert?: () => void;
  onUndoConversion?: () => void;
  isConverting?: boolean;
  isUndoing?: boolean;
  /** Whether current user can approve (is accountable or workspace admin) */
  canApprove?: boolean;
  /** Map of user ID to name for displaying approver */
  userNames?: Record<string, string>;
  /** Callback when approval state changes */
  onApprovalUpdate?: () => void;
}

// Props for sprint panel
interface SprintPanelProps {
  people?: Array<{ id: string; user_id: string; name: string }>;
  existingSprints?: Array<{ owner?: { id: string; name: string; email: string } | null }>;
  /** Whether current user can approve (is accountable or workspace admin) */
  canApprove?: boolean;
  /** Map of user ID to name for displaying approver */
  userNames?: Record<string, string>;
  /** Callback when approval state changes */
  onApprovalUpdate?: () => void;
}

// Props for program panel
interface ProgramPanelProps {
  people: Person[];
}

// Combined props type that includes all panel-specific props
type PanelSpecificProps = WikiPanelProps | IssuePanelProps | ProjectPanelProps | SprintPanelProps | ProgramPanelProps;

interface PropertiesPanelProps {
  /** The document to render properties for */
  document: PanelDocument;
  /** Type-specific data required for rendering */
  panelProps: PanelSpecificProps;
  /** Handler for document updates */
  onUpdate: (updates: Partial<PanelDocument>) => Promise<void>;
  /** Fields to highlight as missing (e.g., after type conversion) */
  highlightedFields?: string[];
  /** Shared weekly review state used by sub-nav and sidebar */
  weeklyReviewState?: WeeklyReviewActionsState | null;
}

const EMPTY_WIKI_PROPS: WikiPanelProps = { teamMembers: [] };
const EMPTY_ISSUE_PROPS: IssuePanelProps = { teamMembers: [], programs: [] };
const EMPTY_PROJECT_PROPS: ProjectPanelProps = { programs: [], people: [] };
const EMPTY_SPRINT_PROPS: SprintPanelProps = {};
const EMPTY_PROGRAM_PROPS: ProgramPanelProps = { people: [] };

function isWikiPanelProps(props: PanelSpecificProps): props is WikiPanelProps {
  return 'teamMembers' in props && !('programs' in props);
}

function isIssuePanelProps(props: PanelSpecificProps): props is IssuePanelProps {
  return 'teamMembers' in props && 'programs' in props;
}

function isProjectPanelProps(props: PanelSpecificProps): props is ProjectPanelProps {
  return 'people' in props && 'programs' in props;
}

function isSprintPanelProps(props: PanelSpecificProps): props is SprintPanelProps {
  return 'existingSprints' in props || ('people' in props && !('programs' in props));
}

function isProgramPanelProps(props: PanelSpecificProps): props is ProgramPanelProps {
  return 'people' in props && !('programs' in props) && !('existingSprints' in props);
}

// OPM 5-level performance rating scale
const OPM_RATINGS = [
  { value: 5, label: 'Outstanding', color: 'text-green-500' },
  { value: 4, label: 'Exceeds Expectations', color: 'text-blue-500' },
  { value: 3, label: 'Fully Successful', color: 'text-muted' },
  { value: 2, label: 'Minimally Satisfactory', color: 'text-orange-500' },
  { value: 1, label: 'Unacceptable', color: 'text-red-500' },
] as const;

/**
 * WeeklyDocumentSidebar - Renders sidebar for weekly_plan/weekly_retro documents
 * with human-readable names instead of UUIDs.
 * In review mode (?review=true&sprintId=X), actions move to the sub-nav.
 */
function WeeklyDocumentSidebar({
  document,
  weeklyReviewState,
}: {
  document: WeeklyPlanDocument | WeeklyRetroDocument;
  weeklyReviewState?: WeeklyReviewActionsState | null;
}) {
  const docProperties = document.properties || {};
  const weekNumber = docProperties.week_number as number | undefined;
  const personId = docProperties.person_id as string | undefined;
  const projectId = docProperties.project_id as string | undefined;

  const isRetro = document.document_type === 'weekly_retro';
  const isReviewMode = weeklyReviewState?.isReviewMode ?? false;
  const effectiveSprintId = weeklyReviewState?.effectiveSprintId ?? null;
  const approvalState = weeklyReviewState?.approvalState ?? null;
  const approvedAt = weeklyReviewState?.approvedAt ?? null;
  const approvalComment = weeklyReviewState?.approvalComment ?? null;
  const requestChangesComment = weeklyReviewState?.requestChangesComment ?? null;
  const approverName = weeklyReviewState?.approverName ?? null;
  const currentRating = weeklyReviewState?.currentRating ?? null;

  const personName = weeklyReviewState?.personName || (personId ? `${personId.substring(0, 8)}...` : null);
  const projectName = weeklyReviewState?.projectName || (projectId ? `${projectId.substring(0, 8)}...` : null);

  function formatApprovalDate(dateStr: string): string {
    return weeklyReviewState?.formatApprovalDate(dateStr)
      ?? new Date(dateStr).toLocaleString('en-US', { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' });
  }

  return (
    <div className="space-y-4 p-4">
      {/* Header */}
      <div className="border-b border-border pb-3">
        <h3 className="text-sm font-medium text-foreground">
          {isRetro ? 'Weekly Retro' : 'Weekly Plan'}
        </h3>
        {weekNumber && (
          <p className="text-sm text-muted mt-1">Week {weekNumber}</p>
        )}
      </div>

      {isReviewMode && (
        <div className="rounded border border-border bg-border/20 px-2.5 py-2 text-xs text-muted">
          Use <span className="font-medium text-foreground">Submit Review</span> in the sub-nav to approve or request changes.
        </div>
      )}

      {/* Approval status (always shown) */}
      {effectiveSprintId && (
        <div className="border-b border-border pb-4">
          {isRetro ? (
            <div>
              <label className="text-xs font-medium text-muted mb-2 block">Performance Rating</label>
              {currentRating ? (
                <div className="mb-2">
                  <div className="flex items-center gap-2">
                    <span className={cn('text-sm font-bold', OPM_RATINGS.find(r => r.value === currentRating)?.color)}>
                      {currentRating}/5
                    </span>
                    <span className="text-xs text-muted">
                      {OPM_RATINGS.find(r => r.value === currentRating)?.label}
                    </span>
                  </div>
                  {approvedAt && (
                    <p className="text-[11px] text-muted mt-1">
                      Rated {formatApprovalDate(approvedAt)}
                      {approverName ? ` by ${approverName}` : ''}
                    </p>
                  )}
                </div>
              ) : (
                <p className="text-xs text-muted italic mb-2">Not yet rated</p>
              )}

              {approvalComment && (
                <div className="mb-3 rounded border border-border bg-border/20 px-2.5 py-2">
                  <p className="text-[11px] font-medium uppercase tracking-wide text-muted">Approval Note</p>
                  <p className="mt-1 text-xs text-foreground">{approvalComment}</p>
                </div>
              )}

              {requestChangesComment && (
                <div className="mb-3 rounded border border-orange-500/30 bg-orange-500/10 px-2.5 py-2">
                  <p className="text-[11px] font-medium uppercase tracking-wide text-orange-400">Changes Requested</p>
                  <p className="mt-1 text-xs text-orange-200">{requestChangesComment}</p>
                </div>
              )}
            </div>
          ) : (
            <div>
              <label className="text-xs font-medium text-muted mb-2 block">Plan Approval</label>
              <div className="mb-2">
                {approvalState === 'approved' ? (
                  <span className="inline-flex items-center gap-1 rounded bg-green-600/20 px-2 py-1 text-xs font-medium text-green-400">
                    <svg className="w-3 h-3" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M20 6L9 17l-5-5" /></svg>
                    Approved
                  </span>
                ) : approvalState === 'changed_since_approved' ? (
                  <span className="inline-flex items-center gap-1 rounded bg-orange-600/20 px-2 py-1 text-xs font-medium text-orange-400">
                    Changed since approved
                  </span>
                ) : approvalState === 'changes_requested' ? (
                  <span className="inline-flex items-center gap-1 rounded bg-orange-600/20 px-2 py-1 text-xs font-medium text-orange-400">
                    Changes requested
                  </span>
                ) : (
                  <p className="text-xs text-muted italic">Not yet approved</p>
                )}
              </div>

              {approvedAt && (
                <p className="text-[11px] text-muted mb-2">
                  {formatApprovalDate(approvedAt)}
                  {approverName ? ` by ${approverName}` : ''}
                </p>
              )}

              {approvalComment && (
                <div className="mb-3 rounded border border-border bg-border/20 px-2.5 py-2">
                  <p className="text-[11px] font-medium uppercase tracking-wide text-muted">Approval Note</p>
                  <p className="mt-1 text-xs text-foreground">{approvalComment}</p>
                </div>
              )}

              {requestChangesComment && (
                <div className="mb-3 rounded border border-orange-500/30 bg-orange-500/10 px-2.5 py-2">
                  <p className="text-[11px] font-medium uppercase tracking-wide text-orange-400">Changes Requested</p>
                  <p className="mt-1 text-xs text-orange-200">{requestChangesComment}</p>
                </div>
              )}
            </div>
          )}
        </div>
      )}

      {/* Person */}
      {personId && (
        <div>
          <label className="text-xs font-medium text-muted mb-1 block">Person</label>
          <p className="text-sm text-foreground">{personName}</p>
        </div>
      )}

      {/* Project */}
      {projectId && (
        <div>
          <label className="text-xs font-medium text-muted mb-1 block">Project</label>
          <a
            href={`/documents/${projectId}/weeks`}
            className="text-sm text-accent hover:underline"
          >
            {projectName}
          </a>
        </div>
      )}

      {/* AI Quality Assistant moved to PlanQualityBanner (rendered above editor content) */}

      {/* Content History Panel */}
      <ContentHistoryPanel
        documentId={document.id}
        documentType={document.document_type as 'weekly_plan' | 'weekly_retro'}
      />
    </div>
  );
}

/** Wrapper that fetches plan content for the retro quality assistant */
function RetroQualityAssistantWrapper({
  documentId,
  content,
  personId,
  weekNumber,
}: {
  documentId: string;
  content: Record<string, unknown>;
  personId?: string;
  weekNumber?: number;
}) {
  // Fetch the corresponding weekly plan for comparison
  const { data: planContent } = useQuery<Record<string, unknown> | null>({
    queryKey: ['weekly-plan-for-retro', personId, weekNumber],
    queryFn: async () => {
      if (!personId || !weekNumber) return null;
      const res = await apiGet(`/api/weekly-plans?person_id=${personId}&week_number=${weekNumber}`);
      if (!res.ok) return null;
      const plans = await res.json();
      if (plans.length > 0 && plans[0].content) return plans[0].content;
      return null;
    },
    enabled: !!personId && !!weekNumber,
    staleTime: 60 * 1000,
  });

  return (
    <RetroQualityAssistant
      documentId={documentId}
      content={content}
      planContent={planContent ?? null}
    />
  );
}

/**
 * PropertiesPanel - Unified component that renders the appropriate sidebar
 * based on document_type.
 *
 * Usage:
 * ```tsx
 * <PropertiesPanel
 *   document={myDocument}
 *   panelProps={typeSpecificProps}
 *   onUpdate={handleUpdate}
 * />
 * ```
 */
export function PropertiesPanel({
  document,
  panelProps,
  onUpdate,
  highlightedFields = [],
  weeklyReviewState = null,
}: PropertiesPanelProps) {
  const { isWorkspaceAdmin } = useWorkspace();
  const { user } = useAuth();

  // Compute canApprove: user is workspace admin OR is the accountable person
  // For sprints, approval uses program's accountable_id (program_accountable_id)
  // For projects, approval uses the project's accountable_id
  const canApprove = useMemo(() => {
    if (isWorkspaceAdmin) return true;
    if (!user?.id) return false;

    // Check document's accountable_id (used by projects)
    const docWithAccountable = document as { accountable_id?: string | null };
    if (docWithAccountable.accountable_id === user.id) return true;

    // For sprints, also check program_accountable_id (inherited from program)
    // and supervisor relationship (reports_to on the sprint owner's person document)
    if (document.document_type === 'sprint') {
      if (document.program_accountable_id === user.id) return true;
      if (document.owner_reports_to === user.id) return true;
    }

    return false;
  }, [isWorkspaceAdmin, user?.id, document]);

  // Build userNames from people in panelProps (for displaying approver names)
  const userNames = useMemo(() => {
    const names: Record<string, string> = {};
    // Try to get people from various panel props
    if ('people' in panelProps && panelProps.people) {
      panelProps.people.forEach(p => {
        if (p.user_id) names[p.user_id] = p.name;
        if (p.id) names[p.id] = p.name;
      });
    }
    return names;
  }, [panelProps]);

  // Callback for when approval state changes - trigger a refetch
  const handleApprovalUpdate = useCallback(() => {
    // The parent component should handle refreshing the document
    // For now, we rely on optimistic updates in the ApprovalButton
  }, []);

  const panel = useMemo(() => {
    switch (document.document_type) {
      case 'wiki': {
        const wikiProps = isWikiPanelProps(panelProps) ? panelProps : EMPTY_WIKI_PROPS;
        return (
          <WikiSidebar
            document={document}
            teamMembers={wikiProps.teamMembers || []}
            currentUserId={wikiProps.currentUserId}
            onUpdate={(updates) => onUpdate(updates)}
          />
        );
      }

      case 'issue': {
        const issueProps = isIssuePanelProps(panelProps) ? panelProps : EMPTY_ISSUE_PROPS;
        return (
          <IssueSidebar
            issue={document}
            teamMembers={issueProps.teamMembers || []}
            programs={issueProps.programs || []}
            projects={issueProps.projects || []}
            onUpdate={(updates) => onUpdate(updates)}
            onConvert={issueProps.onConvert}
            onUndoConversion={issueProps.onUndoConversion}
            onAccept={issueProps.onAccept}
            onReject={issueProps.onReject}
            isConverting={issueProps.isConverting}
            isUndoing={issueProps.isUndoing}
            highlightedFields={highlightedFields}
            onAssociationChange={issueProps.onAssociationChange}
          />
        );
      }

      case 'project': {
        const projectProps = isProjectPanelProps(panelProps) ? panelProps : EMPTY_PROJECT_PROPS;
        return (
          <ProjectSidebar
            project={document}
            programs={projectProps.programs || []}
            people={projectProps.people || []}
            onUpdate={(updates) => onUpdate(updates)}
            onConvert={projectProps.onConvert}
            onUndoConversion={projectProps.onUndoConversion}
            isConverting={projectProps.isConverting}
            isUndoing={projectProps.isUndoing}
            highlightedFields={highlightedFields}
            canApprove={canApprove}
            userNames={userNames}
            onApprovalUpdate={handleApprovalUpdate}
          />
        );
      }

      case 'sprint': {
        const sprintProps = isSprintPanelProps(panelProps) ? panelProps : EMPTY_SPRINT_PROPS;
        return (
          <WeekSidebar
            sprint={document}
            onUpdate={(updates) => onUpdate(updates)}
            highlightedFields={highlightedFields}
            people={sprintProps.people}
            existingSprints={sprintProps.existingSprints}
            canApprove={canApprove}
            userNames={userNames}
            onApprovalUpdate={handleApprovalUpdate}
          />
        );
      }

      case 'program': {
        const programProps = isProgramPanelProps(panelProps) ? panelProps : EMPTY_PROGRAM_PROPS;
        return (
          <ProgramSidebar
            program={document}
            people={programProps.people || []}
            onUpdate={(updates) => onUpdate(updates)}
            highlightedFields={highlightedFields}
          />
        );
      }

      case 'weekly_plan':
      case 'weekly_retro': {
        // Weekly plan and retro documents get a minimal sidebar with history panel
        // Names are fetched via WeeklyDocumentSidebar component
        return (
          <WeeklyDocumentSidebar
            document={document}
            weeklyReviewState={weeklyReviewState}
          />
        );
      }

      default:
        return null;
    }
  }, [document, panelProps, onUpdate, highlightedFields, canApprove, userNames, handleApprovalUpdate, weeklyReviewState]);

  return panel;
}

// Re-export types for convenience
export type {
  WikiDocument,
  IssueDocument,
  ProjectDocument,
  SprintDocument,
  ProgramDocument,
  WikiPanelProps,
  IssuePanelProps,
  ProjectPanelProps,
  SprintPanelProps,
  ProgramPanelProps,
};

/**
 * AI-powered quality assistant components for weekly plan and retro editors.
 *
 * PlanQualityAssistant: Shows approval likelihood meter, per-item feedback, and quality guide.
 * RetroQualityAssistant: Shows plan coverage, evidence prompts, and completeness meter.
 *
 * Both are ADVISORY ONLY — they do not block document submission.
 */

import { useState, useEffect, useRef, useCallback } from 'react';
import { cn } from '@/lib/cn';

// Use raw fetch for AI quality checks — these are non-critical background requests
// that must NOT trigger session expiration redirects (apiGet/apiPost do that on 401).
const API_URL = import.meta.env.VITE_API_URL ?? '';

let quietCsrfToken: string | null = null;

async function getQuietCsrfToken(): Promise<string | null> {
  if (quietCsrfToken) return quietCsrfToken;
  try {
    const res = await fetch(`${API_URL}/api/csrf-token`, { credentials: 'include' });
    if (!res.ok) return null;
    const data = await res.json();
    quietCsrfToken = data.token;
    return quietCsrfToken;
  } catch {
    return null;
  }
}

async function quietGet(endpoint: string): Promise<Response> {
  return fetch(`${API_URL}${endpoint}`, { credentials: 'include' });
}

async function quietPost(endpoint: string, body: object): Promise<Response> {
  const token = await getQuietCsrfToken();
  return fetch(`${API_URL}${endpoint}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      ...(token ? { 'X-CSRF-Token': token } : {}),
    },
    credentials: 'include',
    body: JSON.stringify(body),
  });
}

// ============ Shared Types ============

interface PlanItemAnalysis {
  text: string;
  score: number;
  feedback: string;
  issues: string[];
}

interface PlanAnalysisResult {
  overall_score: number;
  items: PlanItemAnalysis[];
  workload_assessment: 'light' | 'moderate' | 'heavy' | 'excessive';
  workload_feedback: string;
}

interface RetroItemAnalysis {
  plan_item: string;
  addressed: boolean;
  has_evidence: boolean;
  feedback: string;
}

interface RetroAnalysisResult {
  overall_score: number;
  plan_coverage: RetroItemAnalysis[];
  suggestions: string[];
}

type AnalysisError = { error: string };

function isError(result: unknown): result is AnalysisError {
  return !!result && typeof result === 'object' && 'error' in result;
}

// ============ Quality Meter ============

function QualityMeter({ score, label }: { score: number; label: string }) {
  const percentage = Math.round(score * 100);
  const color = percentage >= 70 ? 'bg-green-500' : percentage >= 40 ? 'bg-yellow-500' : 'bg-red-500';
  const textColor = percentage >= 70 ? 'text-green-500' : percentage >= 40 ? 'text-yellow-500' : 'text-red-500';

  return (
    <div>
      <div className="flex items-center justify-between mb-1">
        <span className="text-xs text-muted">{label}</span>
        <span className={cn('text-xs font-bold', textColor)}>{percentage}%</span>
      </div>
      <div className="w-full h-2 rounded-full bg-border overflow-hidden">
        <div
          className={cn('h-full rounded-full transition-all duration-500', color)}
          style={{ width: `${percentage}%` }}
        />
      </div>
    </div>
  );
}

// ============ Workload Badge ============

const WORKLOAD_CONFIG = {
  light: { label: 'Light', color: 'text-yellow-500 bg-yellow-500/10', desc: 'Consider adding more deliverables' },
  moderate: { label: 'Moderate', color: 'text-green-500 bg-green-500/10', desc: 'Good amount of work' },
  heavy: { label: 'Heavy', color: 'text-blue-500 bg-blue-500/10', desc: 'Ambitious but achievable' },
  excessive: { label: 'Excessive', color: 'text-red-500 bg-red-500/10', desc: 'May be unrealistic' },
};

function WorkloadBadge({ assessment }: { assessment: keyof typeof WORKLOAD_CONFIG }) {
  const config = WORKLOAD_CONFIG[assessment];
  return (
    <div className="flex items-center gap-2">
      <span className="text-xs text-muted">Workload:</span>
      <span className={cn('px-2 py-0.5 rounded text-xs font-medium', config.color)}>
        {config.label}
      </span>
    </div>
  );
}

// ============ Expandable Guide ============

function ExpandableGuide({ title, children }: { title: string; children: React.ReactNode }) {
  const [expanded, setExpanded] = useState(() => {
    try {
      return localStorage.getItem('ship_quality_guide_expanded') !== 'false';
    } catch { return true; }
  });

  const toggle = () => {
    const next = !expanded;
    setExpanded(next);
    try { localStorage.setItem('ship_quality_guide_expanded', String(next)); } catch { /* ignore */ }
  };

  return (
    <div className="border border-border rounded">
      <button onClick={toggle} className="w-full flex items-center justify-between px-3 py-2 text-xs font-medium text-muted hover:text-foreground">
        {title}
        <svg className={cn('w-3 h-3 transition-transform', expanded && 'rotate-180')} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
          <path d="M6 9l6 6 6-6" />
        </svg>
      </button>
      {expanded && <div className="px-3 pb-3 text-xs text-muted space-y-2">{children}</div>}
    </div>
  );
}

// ============ Plan Quality Assistant ============

export function PlanQualityAssistant({
  documentId,
}: {
  documentId: string;
  content: Record<string, unknown>;
}) {
  const [analysis, setAnalysis] = useState<PlanAnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [aiAvailable, setAiAvailable] = useState<boolean | null>(null);
  const lastContentRef = useRef<string>('');
  const pollRef = useRef<ReturnType<typeof setInterval>>();

  // Check AI availability on mount
  useEffect(() => {
    quietGet('/api/ai/status')
      .then(r => r.json())
      .then(data => setAiAvailable(data.available))
      .catch(() => setAiAvailable(false));
  }, []);

  // Analyze content by fetching latest from API
  const checkAndAnalyze = useCallback(async () => {
    if (!aiAvailable) return;

    try {
      // Fetch the latest saved content from the API
      const docRes = await quietGet(`/api/documents/${documentId}`);
      if (!docRes.ok) return;
      const doc = await docRes.json();
      const content = doc.content;
      if (!content) return;

      const contentStr = JSON.stringify(content);
      if (contentStr === lastContentRef.current) return;
      lastContentRef.current = contentStr;

      // Content changed — trigger analysis
      setLoading(true);
      const res = await quietPost('/api/ai/analyze-plan', { content });
      const data = await res.json();
      if (!isError(data)) {
        setAnalysis(data);
      }
    } catch { /* keep previous analysis */ }
    finally { setLoading(false); }
  }, [documentId, aiAvailable]);

  // Poll for content changes every 10 seconds
  useEffect(() => {
    if (!aiAvailable) return;

    // Initial check after 5 seconds
    const initialTimeout = setTimeout(checkAndAnalyze, 5000);

    // Then poll every 10 seconds
    pollRef.current = setInterval(checkAndAnalyze, 10000);

    return () => {
      clearTimeout(initialTimeout);
      if (pollRef.current) clearInterval(pollRef.current);
    };
  }, [aiAvailable, checkAndAnalyze]);

  // Don't render if AI is unavailable
  if (aiAvailable === false) return null;
  if (aiAvailable === null) return null; // Still checking

  return (
    <div className="space-y-3">
      <div className="flex items-center justify-between">
        <label className="text-xs font-medium text-muted">AI Quality Check</label>
        {loading && (
          <svg className="w-3 h-3 animate-spin text-muted" viewBox="0 0 24 24" fill="none">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
          </svg>
        )}
      </div>

      {analysis ? (
        <div className="space-y-3">
          <QualityMeter score={analysis.overall_score} label="Approval Likelihood" />
          <WorkloadBadge assessment={analysis.workload_assessment} />

          {/* Per-item feedback */}
          {analysis.items.length > 0 && (
            <div className="space-y-1.5">
              <span className="text-xs text-muted">Item Feedback</span>
              {analysis.items.map((item, i) => (
                <div key={i} className={cn(
                  'rounded border px-2 py-1.5 text-xs',
                  item.score >= 0.7 ? 'border-green-500/20 bg-green-500/5' :
                  item.score >= 0.4 ? 'border-yellow-500/20 bg-yellow-500/5' :
                  'border-red-500/20 bg-red-500/5'
                )}>
                  <p className="font-medium text-foreground truncate">{item.text}</p>
                  <p className="text-muted mt-0.5">{item.feedback}</p>
                </div>
              ))}
            </div>
          )}

          {analysis.workload_feedback && (
            <p className="text-xs text-muted italic">{analysis.workload_feedback}</p>
          )}
        </div>
      ) : !loading ? (
        <p className="text-xs text-muted italic">Write your plan items to get AI feedback.</p>
      ) : null}

      <ExpandableGuide title="Writing a Good Plan">
        <p>Each item should have a <strong className="text-foreground">clear, verifiable outcome</strong>.</p>
        <div className="space-y-1 mt-1">
          <p><span className="text-red-400">Bad:</span> "Coordinate with engineering"</p>
          <p><span className="text-green-400">Good:</span> "Deliver draft API spec to engineering lead"</p>
        </div>
        <div className="space-y-1">
          <p><span className="text-red-400">Bad:</span> "Investigate deployment options"</p>
          <p><span className="text-green-400">Good:</span> "Write comparison memo of 3 deployment options"</p>
        </div>
        <p className="mt-1">Aim for <strong className="text-foreground">3-5 significant deliverables</strong> per week.</p>
        <p className="text-muted mt-1 italic">This feedback is advisory — it does not block your submission.</p>
      </ExpandableGuide>
    </div>
  );
}

// ============ Retro Quality Assistant ============

export function RetroQualityAssistant({
  documentId,
  planContent,
}: {
  documentId: string;
  content: Record<string, unknown>;
  planContent: Record<string, unknown> | null;
}) {
  const [analysis, setAnalysis] = useState<RetroAnalysisResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [aiAvailable, setAiAvailable] = useState<boolean | null>(null);
  const lastContentRef = useRef<string>('');
  const pollRef = useRef<ReturnType<typeof setInterval>>();

  // Check AI availability on mount
  useEffect(() => {
    quietGet('/api/ai/status')
      .then(r => r.json())
      .then(data => setAiAvailable(data.available))
      .catch(() => setAiAvailable(false));
  }, []);

  // Analyze content by fetching latest from API
  const checkAndAnalyze = useCallback(async () => {
    if (!aiAvailable || !planContent) return;

    try {
      // Fetch the latest saved content from the API
      const docRes = await quietGet(`/api/documents/${documentId}`);
      if (!docRes.ok) return;
      const doc = await docRes.json();
      const content = doc.content;
      if (!content) return;

      const contentStr = JSON.stringify(content);
      if (contentStr === lastContentRef.current) return;
      lastContentRef.current = contentStr;

      // Content changed — trigger analysis
      setLoading(true);
      const res = await quietPost('/api/ai/analyze-retro', { retro_content: content, plan_content: planContent });
      const data = await res.json();
      if (!isError(data)) {
        setAnalysis(data);
      }
    } catch { /* keep previous analysis */ }
    finally { setLoading(false); }
  }, [documentId, aiAvailable, planContent]);

  // Poll for content changes every 10 seconds
  useEffect(() => {
    if (!aiAvailable || !planContent) return;

    const initialTimeout = setTimeout(checkAndAnalyze, 5000);
    pollRef.current = setInterval(checkAndAnalyze, 10000);

    return () => {
      clearTimeout(initialTimeout);
      if (pollRef.current) clearInterval(pollRef.current);
    };
  }, [aiAvailable, planContent, checkAndAnalyze]);

  // Don't render if AI is unavailable
  if (aiAvailable === false) return null;
  if (aiAvailable === null) return null;

  return (
    <div className="space-y-3">
      <div className="flex items-center justify-between">
        <label className="text-xs font-medium text-muted">AI Quality Check</label>
        {loading && (
          <svg className="w-3 h-3 animate-spin text-muted" viewBox="0 0 24 24" fill="none">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
          </svg>
        )}
      </div>

      {analysis ? (
        <div className="space-y-3">
          <QualityMeter score={analysis.overall_score} label="Retro Completeness" />

          {/* Plan coverage checklist */}
          {analysis.plan_coverage.length > 0 && (
            <div className="space-y-1.5">
              <span className="text-xs text-muted">Plan Coverage</span>
              {analysis.plan_coverage.map((item, i) => (
                <div key={i} className={cn(
                  'rounded border px-2 py-1.5 text-xs flex items-start gap-2',
                  item.addressed && item.has_evidence ? 'border-green-500/20 bg-green-500/5' :
                  item.addressed ? 'border-yellow-500/20 bg-yellow-500/5' :
                  'border-red-500/20 bg-red-500/5'
                )}>
                  {/* Status icon */}
                  <span className="mt-0.5 flex-shrink-0">
                    {item.addressed && item.has_evidence ? (
                      <svg className="w-3.5 h-3.5 text-green-500" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M20 6L9 17l-5-5" /></svg>
                    ) : item.addressed ? (
                      <svg className="w-3.5 h-3.5 text-yellow-500" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M12 9v2m0 4h.01" /><circle cx="12" cy="12" r="10" strokeWidth="2" /></svg>
                    ) : (
                      <svg className="w-3.5 h-3.5 text-red-500" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3"><path d="M18 6L6 18M6 6l12 12" /></svg>
                    )}
                  </span>
                  <div className="min-w-0">
                    <p className="font-medium text-foreground truncate">{item.plan_item}</p>
                    <p className="text-muted mt-0.5">{item.feedback}</p>
                  </div>
                </div>
              ))}
            </div>
          )}

          {/* Suggestions */}
          {analysis.suggestions.length > 0 && (
            <div className="space-y-1">
              <span className="text-xs text-muted">Suggestions</span>
              {analysis.suggestions.map((s, i) => (
                <p key={i} className="text-xs text-muted italic">• {s}</p>
              ))}
            </div>
          )}
        </div>
      ) : !loading ? (
        <p className="text-xs text-muted italic">
          {planContent ? 'Write your retro to get AI feedback.' : 'No plan found for comparison.'}
        </p>
      ) : null}

      <ExpandableGuide title="Writing a Good Retro">
        <p><strong className="text-foreground">Address each item from your plan:</strong></p>
        <ul className="list-disc pl-4 space-y-0.5">
          <li>Completed? Add evidence (link, screenshot, or the deliverable itself)</li>
          <li>Not completed? Explain what happened and why</li>
          <li>It's OK to not deliver everything — but always explain why</li>
        </ul>
        <p className="mt-1 italic">This feedback is advisory — it does not block your submission.</p>
      </ExpandableGuide>
    </div>
  );
}

