import { createContext, useContext, useState, useCallback, useRef } from 'react';
import { useNavigate } from 'react-router-dom';

export interface QueueItem {
  personId: string;
  personName: string;
  weekNumber: number;
  weekName: string;
  type: 'plan' | 'retro';
  sprintId: string;
  docId: string;
}

interface ReviewQueueState {
  queue: QueueItem[];
  currentIndex: number;
  active: boolean;
}

interface ReviewQueueContextValue {
  state: ReviewQueueState;
  start: (queue: QueueItem[]) => void;
  advance: () => void;
  skip: () => void;
  exit: () => void;
}

const ReviewQueueContext = createContext<ReviewQueueContextValue | null>(null);

export function ReviewQueueProvider({ children }: { children: React.ReactNode }) {
  const navigate = useNavigate();
  const [state, setState] = useState<ReviewQueueState>({
    queue: [],
    currentIndex: 0,
    active: false,
  });

  // Use a ref to avoid stale closures in setTimeout/callbacks
  const stateRef = useRef(state);
  stateRef.current = state;

  const navigateToItem = useCallback((item: QueueItem) => {
    navigate(`/documents/${item.docId}?review=true&sprintId=${item.sprintId}`);
  }, [navigate]);

  const start = useCallback((queue: QueueItem[]) => {
    if (queue.length === 0) return;
    setState({ queue, currentIndex: 0, active: true });
    navigateToItem(queue[0]!);
  }, [navigateToItem]);

  const advanceToNext = useCallback(() => {
    const s = stateRef.current;
    if (!s.active) return;
    const nextIndex = s.currentIndex + 1;
    if (nextIndex >= s.queue.length) {
      setState({ queue: [], currentIndex: 0, active: false });
      navigate('/team/reviews');
    } else {
      setState({ ...s, currentIndex: nextIndex });
      navigateToItem(s.queue[nextIndex]!);
    }
  }, [navigate, navigateToItem]);

  const advance = useCallback(() => {
    setTimeout(advanceToNext, 300);
  }, [advanceToNext]);

  const skip = useCallback(() => {
    advanceToNext();
  }, [advanceToNext]);

  const exit = useCallback(() => {
    setState({ queue: [], currentIndex: 0, active: false });
    navigate('/team/reviews');
  }, [navigate]);

  return (
    <ReviewQueueContext.Provider value={{ state, start, advance, skip, exit }}>
      {children}
    </ReviewQueueContext.Provider>
  );
}

export function useReviewQueue() {
  return useContext(ReviewQueueContext);
}

/**
 * Upload Context - Tracks active uploads for navigation warnings
 * Subscribes to the global upload tracker for real-time updates
 */
import { createContext, useContext, useEffect, ReactNode, useSyncExternalStore } from 'react';
import {
  getUploadCount,
  subscribeToUploads,
} from '@/services/uploadTracker';

interface UploadContextValue {
  uploadCount: number;
  isUploading: boolean;
}

const UploadContext = createContext<UploadContextValue | null>(null);

export function UploadProvider({ children }: { children: ReactNode }) {
  // Subscribe to global upload tracker using useSyncExternalStore
  const uploadCount = useSyncExternalStore(
    subscribeToUploads,
    getUploadCount,
    getUploadCount
  );

  const isUploading = uploadCount > 0;

  // Browser beforeunload warning
  useEffect(() => {
    if (!isUploading) return;

    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      e.preventDefault();
      // Modern browsers ignore custom messages but still show a generic warning
      e.returnValue = `You have ${uploadCount} upload(s) in progress. Leaving will cancel them.`;
      return e.returnValue;
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [isUploading, uploadCount]);

  return (
    <UploadContext.Provider
      value={{
        uploadCount,
        isUploading,
      }}
    >
      {children}
    </UploadContext.Provider>
  );
}

export function useUploads() {
  const context = useContext(UploadContext);
  if (!context) {
    throw new Error('useUploads must be used within an UploadProvider');
  }
  return context;
}

/**
 * Hook for checking upload status
 * Note: In-app SPA navigation blocking requires migrating to createBrowserRouter.
 * Currently we only block browser navigation via beforeunload.
 */
export function useUploadNavigationWarning() {
  const { isUploading, uploadCount } = useUploads();

  return {
    isBlocked: false, // Disabled until we migrate to data router
    uploadCount,
    proceed: () => {},
    reset: () => {},
  };
}

