import { useState, useEffect, useCallback, useRef } from 'react';
import { SESSION_TIMEOUT_MS, ABSOLUTE_SESSION_TIMEOUT_MS } from '@ship/shared';
import { apiPost } from '@/lib/api';

// Warning appears 60 seconds before timeout
const WARNING_THRESHOLD_MS = 60 * 1000;
// Absolute timeout warning appears 5 minutes before
const ABSOLUTE_WARNING_THRESHOLD_MS = 5 * 60 * 1000;
// Throttle activity events to once per 30 seconds
const ACTIVITY_THROTTLE_MS = 30 * 1000;

export type WarningType = 'inactivity' | 'absolute';

export interface SessionTimeoutState {
  showWarning: boolean;
  timeRemaining: number | null;
  warningType: WarningType | null;
  resetTimer: () => void;
  lastActivity: number;
}

interface SessionInfo {
  createdAt: string;
  expiresAt: string;
  lastActivity: string;
}

export function useSessionTimeout(onTimeout: () => void): SessionTimeoutState {
  const [showWarning, setShowWarning] = useState(false);
  const [timeRemaining, setTimeRemaining] = useState<number | null>(null);
  const [warningType, setWarningType] = useState<WarningType | null>(null);
  const [lastActivity, setLastActivity] = useState(() => Date.now());
  const [sessionCreatedAt, setSessionCreatedAt] = useState<number | null>(null);

  const lastActivityRef = useRef(lastActivity);
  const lastThrottledActivityRef = useRef(Date.now());
  const warningTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const countdownIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const absoluteWarningTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const onTimeoutRef = useRef(onTimeout);
  // Ref to break circular dependency between resetTimer and scheduleInactivityWarning
  const scheduleInactivityWarningRef = useRef<() => void>(() => {});
  // Guard to prevent duplicate extend-session API calls
  const extendingSessionRef = useRef(false);

  // Keep onTimeout ref updated
  useEffect(() => {
    onTimeoutRef.current = onTimeout;
  }, [onTimeout]);

  // Fetch session info on mount
  useEffect(() => {
    async function fetchSessionInfo() {
      try {
        const response = await fetch('/api/auth/session', {
          credentials: 'include',
        });
        if (response.ok) {
          const data = await response.json();
          if (data.success && data.data) {
            const info: SessionInfo = data.data;
            setSessionCreatedAt(new Date(info.createdAt).getTime());
          }
        }
      } catch {
        // Ignore errors - absolute timeout tracking won't work but inactivity still will
      }
    }
    fetchSessionInfo();
  }, []);

  // Clear all timers helper
  const clearAllTimers = useCallback(() => {
    if (warningTimerRef.current) {
      clearTimeout(warningTimerRef.current);
      warningTimerRef.current = null;
    }
    if (countdownIntervalRef.current) {
      clearInterval(countdownIntervalRef.current);
      countdownIntervalRef.current = null;
    }
    if (absoluteWarningTimerRef.current) {
      clearTimeout(absoluteWarningTimerRef.current);
      absoluteWarningTimerRef.current = null;
    }
  }, []);

  // Reset timer - dismisses warning, resets inactivity tracking, and schedules next warning
  // Also calls the extend-session API to extend the server-side session
  const resetTimer = useCallback(async () => {
    // Prevent duplicate API calls
    if (extendingSessionRef.current) {
      return;
    }
    extendingSessionRef.current = true;

    const now = Date.now();
    setLastActivity(now);
    lastActivityRef.current = now;
    setShowWarning(false);
    setTimeRemaining(null);
    setWarningType(null);
    clearAllTimers();
    // Schedule the next inactivity warning
    scheduleInactivityWarningRef.current();

    // Call extend-session API to extend server-side session
    try {
      const response = await apiPost('/api/auth/extend-session');
      if (!response.ok) {
        // API call failed - force logout
        console.error('Failed to extend session - forcing logout');
        onTimeoutRef.current();
      }
    } catch {
      // Network error - force logout
      console.error('Network error extending session - forcing logout');
      onTimeoutRef.current();
    } finally {
      extendingSessionRef.current = false;
    }
  }, [clearAllTimers]);

  // Schedule inactivity warning
  const scheduleInactivityWarning = useCallback(() => {
    if (warningTimerRef.current) {
      clearTimeout(warningTimerRef.current);
    }

    const timeUntilWarning = SESSION_TIMEOUT_MS - WARNING_THRESHOLD_MS;

    warningTimerRef.current = setTimeout(() => {
      // Check if we've had activity since scheduling
      const now = Date.now();
      const timeSinceActivity = now - lastActivityRef.current;

      if (timeSinceActivity >= timeUntilWarning) {
        // Show inactivity warning
        setShowWarning(true);
        setTimeRemaining(60);
        setWarningType('inactivity');

        // Start countdown
        countdownIntervalRef.current = setInterval(() => {
          setTimeRemaining((prev) => {
            if (prev === null || prev <= 1) {
              clearInterval(countdownIntervalRef.current!);
              countdownIntervalRef.current = null;
              onTimeoutRef.current();
              return 0;
            }
            return prev - 1;
          });
        }, 1000);
      } else {
        // Re-schedule based on actual last activity
        scheduleInactivityWarning();
      }
    }, timeUntilWarning);
  }, []);

  // Keep the ref updated for resetTimer to use
  scheduleInactivityWarningRef.current = scheduleInactivityWarning;

  // Schedule absolute timeout warning
  const scheduleAbsoluteWarning = useCallback(() => {
    if (!sessionCreatedAt) return;

    if (absoluteWarningTimerRef.current) {
      clearTimeout(absoluteWarningTimerRef.current);
    }

    const now = Date.now();
    const sessionAge = now - sessionCreatedAt;
    const timeUntilAbsoluteWarning = ABSOLUTE_SESSION_TIMEOUT_MS - ABSOLUTE_WARNING_THRESHOLD_MS - sessionAge;

    if (timeUntilAbsoluteWarning <= 0) {
      // Already past warning time - show immediately if not already showing inactivity warning
      if (!showWarning || warningType !== 'inactivity') {
        setShowWarning(true);
        setTimeRemaining(300); // 5 minutes
        setWarningType('absolute');

        // Start countdown for absolute timeout
        if (countdownIntervalRef.current) {
          clearInterval(countdownIntervalRef.current);
        }
        countdownIntervalRef.current = setInterval(() => {
          setTimeRemaining((prev) => {
            if (prev === null || prev <= 1) {
              clearInterval(countdownIntervalRef.current!);
              countdownIntervalRef.current = null;
              onTimeoutRef.current();
              return 0;
            }
            return prev - 1;
          });
        }, 1000);
      }
      return;
    }

    absoluteWarningTimerRef.current = setTimeout(() => {
      // Only show absolute warning if we're not already showing inactivity warning
      // Inactivity warning takes precedence
      if (!showWarning) {
        setShowWarning(true);
        setTimeRemaining(300); // 5 minutes
        setWarningType('absolute');

        // Start countdown
        countdownIntervalRef.current = setInterval(() => {
          setTimeRemaining((prev) => {
            if (prev === null || prev <= 1) {
              clearInterval(countdownIntervalRef.current!);
              countdownIntervalRef.current = null;
              onTimeoutRef.current();
              return 0;
            }
            return prev - 1;
          });
        }, 1000);
      }
    }, timeUntilAbsoluteWarning);
  }, [sessionCreatedAt, showWarning, warningType]);

  // Handle activity events (throttled)
  const handleActivity = useCallback(() => {
    const now = Date.now();

    // Throttle activity updates
    if (now - lastThrottledActivityRef.current < ACTIVITY_THROTTLE_MS) {
      return;
    }

    lastThrottledActivityRef.current = now;

    // If showing inactivity warning, dismiss it and reset timer
    // Note: resetTimer() now automatically schedules the next warning
    if (showWarning && warningType === 'inactivity') {
      resetTimer();
    } else if (!showWarning) {
      // Just update last activity
      setLastActivity(now);
      lastActivityRef.current = now;
    }
    // Don't reset for absolute warning - it can't be extended
  }, [showWarning, warningType, resetTimer]);

  // Set up activity listeners
  useEffect(() => {
    const events = ['mousedown', 'keydown', 'scroll', 'touchstart', 'mousemove'];

    events.forEach((event) => {
      document.addEventListener(event, handleActivity, { passive: true, capture: true });
    });

    return () => {
      events.forEach((event) => {
        document.removeEventListener(event, handleActivity, { capture: true });
      });
    };
  }, [handleActivity]);

  // Schedule warnings on mount and when dependencies change
  useEffect(() => {
    scheduleInactivityWarning();
    return () => {
      if (warningTimerRef.current) {
        clearTimeout(warningTimerRef.current);
      }
    };
  }, [scheduleInactivityWarning]);

  useEffect(() => {
    scheduleAbsoluteWarning();
    return () => {
      if (absoluteWarningTimerRef.current) {
        clearTimeout(absoluteWarningTimerRef.current);
      }
    };
  }, [scheduleAbsoluteWarning]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      clearAllTimers();
    };
  }, [clearAllTimers]);

  // Handle computer sleep/wake - check if we've jumped past timeout
  useEffect(() => {
    const checkForTimeJump = () => {
      const now = Date.now();
      const timeSinceActivity = now - lastActivityRef.current;

      // If we've jumped past the full timeout, trigger immediately
      if (timeSinceActivity >= SESSION_TIMEOUT_MS) {
        onTimeoutRef.current();
      }

      // Also check absolute timeout
      if (sessionCreatedAt) {
        const sessionAge = now - sessionCreatedAt;
        if (sessionAge >= ABSOLUTE_SESSION_TIMEOUT_MS) {
          onTimeoutRef.current();
        }
      }
    };

    // Check on visibility change (tab becomes visible after being hidden)
    const handleVisibilityChange = () => {
      if (document.visibilityState === 'visible') {
        checkForTimeJump();
      }
    };

    document.addEventListener('visibilitychange', handleVisibilityChange);

    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange);
    };
  }, [sessionCreatedAt]);

  return {
    showWarning,
    timeRemaining,
    warningType,
    resetTimer,
    lastActivity,
  };
}

import { useCallback, useEffect, useMemo, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { useSearchParams } from 'react-router-dom';
import { useReviewQueue } from '@/contexts/ReviewQueueContext';
import { apiGet, apiPost } from '@/lib/api';

export interface WeeklyReviewDocumentRef {
  id: string;
  document_type: 'weekly_plan' | 'weekly_retro';
  properties?: {
    person_id?: string;
    project_id?: string;
    week_number?: number;
  };
}

interface ApprovalDetails {
  state: string | null;
  approvedAt: string | null;
  comment: string | null;
  feedback: string | null;
  rating: number | null;
}

interface ApprovalData {
  state?: string;
  approved_by?: string;
  approved_at?: string;
  feedback?: string | null;
  comment?: string | null;
}

export interface WeeklyReviewActionsState {
  isReviewMode: boolean;
  isRetro: boolean;
  effectiveSprintId: string | null;
  weekNumber?: number;
  personId?: string;
  projectId?: string;
  personName: string | null;
  projectName: string | null;
  queueActive: boolean;
  queueIndex: number;
  queueLength: number;
  approvalState: string | null;
  approvedAt: string | null;
  approvalComment: string | null;
  requestChangesComment: string | null;
  approverName: string | null;
  currentRating: number | null;
  approving: boolean;
  skip: () => void;
  exit: () => void;
  approvePlan: (comment: string) => Promise<boolean>;
  approveRetro: (rating: number, comment: string) => Promise<boolean>;
  requestChanges: (feedback: string) => Promise<boolean>;
  formatApprovalDate: (dateStr: string) => string;
}

export function useWeeklyReviewActions(
  weeklyDocument: WeeklyReviewDocumentRef | null
): WeeklyReviewActionsState | null {
  const [searchParams] = useSearchParams();
  const sprintIdFromQuery = searchParams.get('sprintId');
  const isReviewMode = searchParams.get('review') === 'true';

  const reviewQueue = useReviewQueue();
  const queueActive = reviewQueue?.state.active ?? false;

  const isRetro = weeklyDocument?.document_type === 'weekly_retro';
  const docProperties = weeklyDocument?.properties ?? {};
  const weekNumber = docProperties.week_number;
  const personId = docProperties.person_id;
  const projectId = docProperties.project_id;

  const [approving, setApproving] = useState(false);
  const [localApprovalOverride, setLocalApprovalOverride] = useState<ApprovalDetails | null>(null);

  // Fetch person name
  const { data: personDoc } = useQuery<{ title: string }>({
    queryKey: ['document', personId],
    queryFn: async () => {
      const res = await apiGet(`/api/documents/${personId}`);
      if (!res.ok) throw new Error('Failed to fetch person');
      return res.json();
    },
    enabled: !!weeklyDocument && !!personId,
  });

  // Fetch project name
  const { data: projectDoc } = useQuery<{ title: string }>({
    queryKey: ['document', projectId],
    queryFn: async () => {
      const res = await apiGet(`/api/documents/${projectId}`);
      if (!res.ok) throw new Error('Failed to fetch project');
      return res.json();
    },
    enabled: !!weeklyDocument && !!projectId,
  });

  // Fetch sprint data with approval state + approver name in a single query
  const { data: sprintData } = useQuery<{ id: string; properties: Record<string, unknown>; approverName?: string }>({
    queryKey: ['sprint-approval-v2', sprintIdFromQuery || `lookup-${projectId}-${weekNumber}`, isRetro],
    queryFn: async () => {
      let sid = sprintIdFromQuery;
      if (!sid) {
        const lookupRes = await apiGet(`/api/weeks/lookup?project_id=${projectId}&sprint_number=${weekNumber}`);
        if (!lookupRes.ok) throw new Error('Sprint not found');
        const lookup = await lookupRes.json();
        sid = lookup.id as string;
      }

      const res = await apiGet(`/api/documents/${sid}`);
      if (!res.ok) throw new Error('Failed to fetch sprint');
      const data = await res.json();

      // Resolve approver name if there's an approval
      const props = (data.properties || {}) as Record<string, unknown>;
      const approval = (isRetro ? props.review_approval : props.plan_approval) as ApprovalData | undefined;
      if (approval?.approved_by) {
        const personRes = await fetch(
          `${import.meta.env.VITE_API_URL ?? ''}/api/weeks/lookup-person?user_id=${approval.approved_by}`,
          { credentials: 'include' }
        );
        if (personRes.ok) {
          const person = await personRes.json();
          data.approverName = person.title;
        }
      }
      return data;
    },
    enabled: !!weeklyDocument && (!!sprintIdFromQuery || (!!projectId && !!weekNumber)),
  });

  const effectiveSprintId = sprintData?.id || sprintIdFromQuery || null;

  // Clear local overrides when navigating between weekly docs
  useEffect(() => {
    setLocalApprovalOverride(null);
  }, [weeklyDocument?.id, effectiveSprintId]);

  // Derive approval state from sprint data (or local override after action)
  const sprintProps = (sprintData?.properties || {}) as Record<string, unknown>;
  const planApproval = (sprintProps.plan_approval as ApprovalData | null) ?? null;
  const reviewApproval = (sprintProps.review_approval as ApprovalData | null) ?? null;
  const reviewRating = (sprintProps.review_rating as { value?: number } | null) ?? null;
  const activeApproval = isRetro ? reviewApproval : planApproval;

  const approvalState = localApprovalOverride !== null
    ? localApprovalOverride.state
    : activeApproval?.state || null;
  const approvedAt = localApprovalOverride !== null
    ? localApprovalOverride.approvedAt
    : activeApproval?.approved_at || null;
  const approvalComment = localApprovalOverride !== null
    ? localApprovalOverride.comment
    : (activeApproval?.comment ?? null);
  const requestChangesComment = localApprovalOverride !== null
    ? localApprovalOverride.feedback
    : (activeApproval?.feedback ?? null);
  const approverName = sprintData?.approverName || null;
  const currentRating = localApprovalOverride !== null
    ? localApprovalOverride.rating
    : (reviewRating?.value || null);

  const personName = personDoc?.title || (personId ? `${personId.substring(0, 8)}...` : null);
  const projectName = projectDoc?.title || (projectId ? `${projectId.substring(0, 8)}...` : null);

  const formatApprovalDate = useCallback((dateStr: string) => {
    const d = new Date(dateStr);
    return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }) +
      ' at ' + d.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' });
  }, []);

  const approvePlan = useCallback(async (comment: string): Promise<boolean> => {
    if (!effectiveSprintId || approving) return false;

    setApproving(true);
    try {
      const res = await apiPost(`/api/weeks/${effectiveSprintId}/approve-plan`, {
        comment,
      });

      if (!res.ok) {
        console.error('Failed to approve plan:', res.status, await res.text().catch(() => ''));
        return false;
      }

      const data = await res.json().catch(() => ({}));
      const approval = data?.approval as ApprovalData | undefined;
      setLocalApprovalOverride({
        state: approval?.state ?? 'approved',
        approvedAt: approval?.approved_at ?? new Date().toISOString(),
        comment: approval?.comment ?? (comment.trim() || null),
        feedback: null,
        rating: currentRating,
      });

      if (queueActive) reviewQueue?.advance();
      return true;
    } catch (err) {
      console.error('Error approving plan:', err);
      return false;
    } finally {
      setApproving(false);
    }
  }, [approving, currentRating, effectiveSprintId, queueActive, reviewQueue]);

  const requestChanges = useCallback(async (feedbackInput: string): Promise<boolean> => {
    if (!effectiveSprintId || approving) return false;

    const feedback = feedbackInput.trim();
    if (!feedback) return false;

    setApproving(true);
    try {
      const endpoint = isRetro ? 'request-retro-changes' : 'request-plan-changes';
      const res = await apiPost(`/api/weeks/${effectiveSprintId}/${endpoint}`, { feedback });

      if (!res.ok) {
        console.error('Failed to request changes:', res.status, await res.text().catch(() => ''));
        return false;
      }

      const data = await res.json().catch(() => ({}));
      const approval = data?.approval as ApprovalData | undefined;
      setLocalApprovalOverride({
        state: approval?.state ?? 'changes_requested',
        approvedAt: approval?.approved_at ?? new Date().toISOString(),
        comment: null,
        feedback: approval?.feedback ?? feedback,
        rating: currentRating,
      });

      if (queueActive) reviewQueue?.advance();
      return true;
    } catch (err) {
      console.error('Error requesting changes:', err);
      return false;
    } finally {
      setApproving(false);
    }
  }, [approving, currentRating, effectiveSprintId, isRetro, queueActive, reviewQueue]);

  const approveRetro = useCallback(async (rating: number, comment: string): Promise<boolean> => {
    if (!effectiveSprintId || !rating || approving) return false;

    setApproving(true);
    try {
      const res = await apiPost(`/api/weeks/${effectiveSprintId}/approve-review`, {
        rating,
        comment,
      });

      if (!res.ok) {
        console.error('Failed to approve retro:', res.status, await res.text().catch(() => ''));
        return false;
      }

      const data = await res.json().catch(() => ({}));
      const approval = data?.approval as ApprovalData | undefined;
      const nextRating = (data?.review_rating as { value?: number } | null)?.value ?? rating;
      setLocalApprovalOverride({
        state: approval?.state ?? 'approved',
        approvedAt: approval?.approved_at ?? new Date().toISOString(),
        comment: approval?.comment ?? (comment.trim() || null),
        feedback: null,
        rating: nextRating,
      });

      if (queueActive) reviewQueue?.advance();
      return true;
    } catch (err) {
      console.error('Error approving retro:', err);
      return false;
    } finally {
      setApproving(false);
    }
  }, [approving, effectiveSprintId, queueActive, reviewQueue]);

  return useMemo(() => {
    if (!weeklyDocument) return null;

    return {
      isReviewMode,
      isRetro,
      effectiveSprintId,
      weekNumber,
      personId,
      projectId,
      personName,
      projectName,
      queueActive,
      queueIndex: reviewQueue?.state.currentIndex ?? 0,
      queueLength: reviewQueue?.state.queue.length ?? 0,
      approvalState,
      approvedAt,
      approvalComment,
      requestChangesComment,
      approverName,
      currentRating,
      approving,
      skip: () => reviewQueue?.skip(),
      exit: () => reviewQueue?.exit(),
      approvePlan,
      approveRetro,
      requestChanges,
      formatApprovalDate,
    } satisfies WeeklyReviewActionsState;
  }, [
    approvalComment,
    approvalState,
    approvePlan,
    approveRetro,
    approvedAt,
    approving,
    approverName,
    currentRating,
    effectiveSprintId,
    formatApprovalDate,
    isRetro,
    isReviewMode,
    personId,
    personName,
    projectId,
    projectName,
    queueActive,
    requestChanges,
    requestChangesComment,
    reviewQueue,
    weekNumber,
    weeklyDocument,
  ]);
}

import { describe, it, expect } from 'vitest';
import {
  getTabsForDocumentType,
  documentTypeHasTabs,
  resolveTabLabels,
  documentTabConfigs,
  type DocumentResponse,
} from './document-tabs';

/**
 * Tests for document tab configuration and URL-driven tab state.
 *
 * These tests ensure the tab system works correctly for deep linking:
 * - URLs like /documents/:id/issues should show the Issues tab
 * - Invalid tabs should be detectable for redirect handling
 * - Document types without tabs should return empty configs
 */

describe('getTabsForDocumentType', () => {
  it('returns tabs for project documents', () => {
    const tabs = getTabsForDocumentType('project');
    expect(tabs.length).toBeGreaterThan(0);
    expect(tabs.map(t => t.id)).toContain('details');
    expect(tabs.map(t => t.id)).toContain('issues');
    expect(tabs.map(t => t.id)).toContain('timeline');
    expect(tabs.map(t => t.id)).toContain('weeks');
  });

  it('returns tabs for program documents', () => {
    const tabs = getTabsForDocumentType('program');
    expect(tabs.length).toBeGreaterThan(0);
    expect(tabs.map(t => t.id)).toContain('overview');
    expect(tabs.map(t => t.id)).toContain('timeline');
    expect(tabs.map(t => t.id)).toContain('issues');
    expect(tabs.map(t => t.id)).toContain('projects');
    expect(tabs.map(t => t.id)).toContain('weeks');
  });

  it('returns empty array for wiki documents (no tabs)', () => {
    const tabs = getTabsForDocumentType('wiki');
    expect(tabs).toEqual([]);
  });

  it('returns empty array for issue documents (no tabs)', () => {
    const tabs = getTabsForDocumentType('issue');
    expect(tabs).toEqual([]);
  });

  it('returns tabs for sprint documents', () => {
    const tabs = getTabsForDocumentType('sprint');
    expect(tabs.map(t => t.id)).toEqual(['overview', 'plan', 'review', 'standups']);
  });

  it('returns empty array for unknown document types', () => {
    const tabs = getTabsForDocumentType('unknown-type');
    expect(tabs).toEqual([]);
  });
});

describe('documentTypeHasTabs', () => {
  it('returns true for project documents', () => {
    expect(documentTypeHasTabs('project')).toBe(true);
  });

  it('returns true for program documents', () => {
    expect(documentTypeHasTabs('program')).toBe(true);
  });

  it('returns false for wiki documents', () => {
    expect(documentTypeHasTabs('wiki')).toBe(false);
  });

  it('returns false for issue documents', () => {
    expect(documentTypeHasTabs('issue')).toBe(false);
  });

  it('returns true for sprint documents', () => {
    expect(documentTypeHasTabs('sprint')).toBe(true);
  });

  it('returns false for unknown document types', () => {
    expect(documentTypeHasTabs('unknown-type')).toBe(false);
  });
});

describe('tab ID validation for URL deep linking', () => {
  /**
   * These tests verify the pattern used in UnifiedDocumentPage
   * for validating URL tab parameters against the config.
   */

  it('validates project tab IDs correctly', () => {
    const tabs = getTabsForDocumentType('project');
    const validTabIds = tabs.map(t => t.id);

    // Valid tab IDs
    expect(validTabIds.includes('details')).toBe(true);
    expect(validTabIds.includes('issues')).toBe(true);
    expect(validTabIds.includes('timeline')).toBe(true);
    expect(validTabIds.includes('weeks')).toBe(true);
    expect(validTabIds.includes('retro')).toBe(true);

    // Invalid tab IDs (should trigger redirect in UnifiedDocumentPage)
    expect(validTabIds.includes('invalid')).toBe(false);
    expect(validTabIds.includes('overview')).toBe(false); // overview is for programs
    expect(validTabIds.includes('')).toBe(false);
  });

  it('validates program tab IDs correctly', () => {
    const tabs = getTabsForDocumentType('program');
    const validTabIds = tabs.map(t => t.id);

    // Valid tab IDs
    expect(validTabIds.includes('overview')).toBe(true);
    expect(validTabIds.includes('timeline')).toBe(true);
    expect(validTabIds.includes('issues')).toBe(true);
    expect(validTabIds.includes('projects')).toBe(true);
    expect(validTabIds.includes('weeks')).toBe(true);

    // Invalid tab IDs
    expect(validTabIds.includes('details')).toBe(false); // details is for projects
    expect(validTabIds.includes('retro')).toBe(false); // retro is for projects
  });

  it('returns first tab as default for URL without tab', () => {
    // This tests the pattern: tabConfig[0]?.id || ''
    const projectTabs = getTabsForDocumentType('project');
    expect(projectTabs[0]?.id).toBe('issues');

    const programTabs = getTabsForDocumentType('program');
    expect(programTabs[0]?.id).toBe('overview');

    // Documents without tabs should have empty first tab
    const wikiTabs = getTabsForDocumentType('wiki');
    expect(wikiTabs[0]?.id).toBeUndefined();
  });
});

describe('resolveTabLabels', () => {
  const mockDocument: DocumentResponse = {
    id: 'test-123',
    title: 'Test Document',
    document_type: 'project',
  };

  it('resolves static labels correctly', () => {
    const tabs = getTabsForDocumentType('project');
    const resolved = resolveTabLabels(tabs, mockDocument);

    const detailsTab = resolved.find(t => t.id === 'details');
    expect(detailsTab?.label).toBe('Details');

    const retroTab = resolved.find(t => t.id === 'retro');
    expect(retroTab?.label).toBe('Retro');

    const timelineTab = resolved.find(t => t.id === 'timeline');
    expect(timelineTab?.label).toBe('Timeline');
  });

  it('resolves dynamic labels with counts', () => {
    const tabs = getTabsForDocumentType('project');
    const resolved = resolveTabLabels(tabs, mockDocument, { issues: 5, weeks: 3 });

    const issuesTab = resolved.find(t => t.id === 'issues');
    expect(issuesTab?.label).toBe('Issues (5)');

    const weeksTab = resolved.find(t => t.id === 'weeks');
    expect(weeksTab?.label).toBe('Weeks');
  });

  it('resolves dynamic labels without counts', () => {
    const tabs = getTabsForDocumentType('project');
    const resolved = resolveTabLabels(tabs, mockDocument);

    const issuesTab = resolved.find(t => t.id === 'issues');
    expect(issuesTab?.label).toBe('Issues');

    const weeksTab = resolved.find(t => t.id === 'weeks');
    expect(weeksTab?.label).toBe('Weeks');
  });

  it('resolves dynamic labels with zero counts', () => {
    const tabs = getTabsForDocumentType('project');
    const resolved = resolveTabLabels(tabs, mockDocument, { issues: 0, weeks: 0 });

    // Zero should not show count (falsy check in label function)
    const issuesTab = resolved.find(t => t.id === 'issues');
    expect(issuesTab?.label).toBe('Issues');
  });
});

describe('documentTabConfigs structure', () => {
  it('has configs for expected document types', () => {
    expect(documentTabConfigs).toHaveProperty('project');
    expect(documentTabConfigs).toHaveProperty('program');
    expect(documentTabConfigs).toHaveProperty('sprint');
    expect(documentTabConfigs).toHaveProperty('issue');
    expect(documentTabConfigs).toHaveProperty('wiki');
  });

  it('each tab has required properties', () => {
    for (const [docType, tabs] of Object.entries(documentTabConfigs)) {
      for (const tab of tabs) {
        expect(tab).toHaveProperty('id');
        expect(tab).toHaveProperty('label');
        expect(tab).toHaveProperty('component');
        expect(typeof tab.id).toBe('string');
        expect(tab.id.length).toBeGreaterThan(0);
      }
    }
  });

  it('tab IDs are unique within each document type', () => {
    for (const [docType, tabs] of Object.entries(documentTabConfigs)) {
      const ids = tabs.map(t => t.id);
      const uniqueIds = new Set(ids);
      expect(uniqueIds.size).toBe(ids.length);
    }
  });
});

