import { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { useAuth } from '@/hooks/useAuth';
import { api } from '@/lib/api';

type InviteStatus = 'loading' | 'valid' | 'invalid' | 'expired' | 'accepted' | 'already_member' | 'error';

interface InviteInfo {
  workspaceName: string;
  invitedBy: string;
  role: 'admin' | 'member';
  email: string;
  userExists: boolean;
  alreadyMember?: boolean;
}

export function InviteAcceptPage() {
  const { token } = useParams<{ token: string }>();
  const navigate = useNavigate();
  const { user, loading: authLoading } = useAuth();
  const [status, setStatus] = useState<InviteStatus>('loading');
  const [inviteInfo, setInviteInfo] = useState<InviteInfo | null>(null);
  const [accepting, setAccepting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [name, setName] = useState('');
  const [password, setPassword] = useState('');

  useEffect(() => {
    if (!token) {
      setStatus('invalid');
      return;
    }

    validateInvite();
  }, [token]);

  async function validateInvite() {
    if (!token) return;

    const res = await api.invites.validate(token);
    if (res.success && res.data) {
      setInviteInfo(res.data);
      // Check if user is already a member - invite was auto-consumed
      if (res.data.alreadyMember) {
        setStatus('already_member');
      } else {
        setStatus('valid');
      }
    } else {
      const errorMsg = res.error?.message || '';
      if (errorMsg.includes('expired')) {
        setStatus('expired');
      } else if (errorMsg.includes('already accepted') || errorMsg.includes('already used')) {
        setStatus('accepted');
      } else {
        setStatus('invalid');
      }
      setError(errorMsg);
    }
  }

  async function handleAccept() {
    if (!token) return;

    setAccepting(true);
    setError(null);

    // For new users, pass name and password to create account
    const data = inviteInfo?.userExists === false
      ? { name: name || undefined, password }
      : undefined;
    const res = await api.invites.accept(token, data);
    if (res.success) {
      // Redirect to docs - user is now a member of the workspace
      navigate('/docs', { replace: true });
    } else {
      setError(res.error?.message || 'Failed to accept invite');
      setAccepting(false);
    }
  }

  if (authLoading || status === 'loading') {
    return (
      <div className="flex min-h-screen items-center justify-center bg-background">
        <div className="text-muted">Loading...</div>
      </div>
    );
  }

  // Invalid token
  if (status === 'invalid') {
    return (
      <div className="flex min-h-screen items-center justify-center bg-background">
        <div className="w-full max-w-md px-6">
          <div className="rounded-lg border border-border bg-surface p-8 text-center">
            <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-red-500/10">
              <ErrorIcon className="h-6 w-6 text-red-500" />
            </div>
            <h1 className="text-xl font-semibold text-foreground">Invalid Invite</h1>
            <p className="mt-2 text-sm text-muted">
              This invite link is not valid. It may have been revoked or the URL is incorrect.
            </p>
            <Link
              to="/login"
              className="mt-6 inline-block px-4 py-2 bg-accent text-white rounded-md hover:bg-accent/90 transition-colors"
            >
              Go to Login
            </Link>
          </div>
        </div>
      </div>
    );
  }

  // Expired token
  if (status === 'expired') {
    return (
      <div className="flex min-h-screen items-center justify-center bg-background">
        <div className="w-full max-w-md px-6">
          <div className="rounded-lg border border-border bg-surface p-8 text-center">
            <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-yellow-500/10">
              <ClockIcon className="h-6 w-6 text-yellow-500" />
            </div>
            <h1 className="text-xl font-semibold text-foreground">Invite Expired</h1>
            <p className="mt-2 text-sm text-muted">
              This invite link has expired. Please contact your workspace admin for a new invite.
            </p>
            <Link
              to="/login"
              className="mt-6 inline-block px-4 py-2 bg-accent text-white rounded-md hover:bg-accent/90 transition-colors"
            >
              Go to Login
            </Link>
          </div>
        </div>
      </div>
    );
  }

  // Already accepted
  if (status === 'accepted') {
    return (
      <div className="flex min-h-screen items-center justify-center bg-background">
        <div className="w-full max-w-md px-6">
          <div className="rounded-lg border border-border bg-surface p-8 text-center">
            <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-green-500/10">
              <CheckIcon className="h-6 w-6 text-green-500" />
            </div>
            <h1 className="text-xl font-semibold text-foreground">Already Accepted</h1>
            <p className="mt-2 text-sm text-muted">
              This invite has already been accepted.
            </p>
            <Link
              to="/docs"
              className="mt-6 inline-block px-4 py-2 bg-accent text-white rounded-md hover:bg-accent/90 transition-colors"
            >
              Go to Documents
            </Link>
          </div>
        </div>
      </div>
    );
  }

  // User is already a member of this workspace
  if (status === 'already_member') {
    return (
      <div className="flex min-h-screen items-center justify-center bg-background">
        <div className="w-full max-w-md px-6">
          <div className="rounded-lg border border-border bg-surface p-8 text-center">
            <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-green-500/10">
              <CheckIcon className="h-6 w-6 text-green-500" />
            </div>
            <h1 className="text-xl font-semibold text-foreground">Already a Member</h1>
            <p className="mt-2 text-sm text-muted">
              You're already a member of <span className="font-medium text-foreground">{inviteInfo?.workspaceName}</span>.
            </p>
            <Link
              to="/login"
              className="mt-6 inline-block px-4 py-2 bg-accent text-white rounded-md hover:bg-accent/90 transition-colors"
            >
              Log In
            </Link>
          </div>
        </div>
      </div>
    );
  }

  // Valid invite - show accept UI
  return (
    <div className="flex min-h-screen items-center justify-center bg-background">
      <div className="w-full max-w-md px-6">
        <div className="rounded-lg border border-border bg-surface p-8">
          <div className="text-center">
            <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-accent/10">
              <InviteIcon className="h-6 w-6 text-accent" />
            </div>
            <h1 className="text-xl font-semibold text-foreground">You're Invited!</h1>
            <p className="mt-2 text-sm text-muted">
              {inviteInfo?.invitedBy} has invited you to join
            </p>
            <p className="mt-1 text-lg font-medium text-foreground">
              {inviteInfo?.workspaceName}
            </p>
          </div>

          <div className="mt-6 rounded-md bg-border/30 p-4">
            <div className="flex justify-between text-sm">
              <span className="text-muted">Email</span>
              <span className="text-foreground">{inviteInfo?.email}</span>
            </div>
            <div className="mt-2 flex justify-between text-sm">
              <span className="text-muted">Role</span>
              <span className="text-foreground capitalize">{inviteInfo?.role}</span>
            </div>
          </div>

          {error && (
            <div className="mt-4 rounded-md bg-red-500/10 px-3 py-2 text-sm text-red-500">
              {error}
            </div>
          )}

          {/* Case 1: New user - show registration form */}
          {inviteInfo?.userExists === false && (
            <div className="mt-6 space-y-4">
              <p className="text-center text-sm text-muted">
                Create an account to accept this invite.
              </p>
              <div>
                <label htmlFor="name" className="sr-only">Name</label>
                <input
                  id="name"
                  type="text"
                  placeholder="Your name (optional)"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full rounded-md border border-border bg-background px-3 py-2 text-sm text-foreground placeholder:text-muted focus:border-accent focus:outline-none"
                />
              </div>
              <div>
                <label htmlFor="password" className="sr-only">Password</label>
                <input
                  id="password"
                  type="password"
                  placeholder="Create password (8+ characters)"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full rounded-md border border-border bg-background px-3 py-2 text-sm text-foreground placeholder:text-muted focus:border-accent focus:outline-none"
                />
              </div>
              <button
                onClick={handleAccept}
                disabled={accepting || password.length < 8}
                className="w-full px-4 py-2 bg-accent text-white rounded-md hover:bg-accent/90 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                {accepting ? 'Creating Account...' : 'Create Account & Accept'}
              </button>
            </div>
          )}

          {/* Case 2: Existing user but not logged in - show login button */}
          {inviteInfo?.userExists === true && !user && (
            <div className="mt-6 space-y-3">
              <p className="text-center text-sm text-muted">
                Please log in to accept this invite.
              </p>
              <Link
                to={`/login?redirect=/invite/${token}`}
                className="block w-full px-4 py-2 bg-accent text-white text-center rounded-md hover:bg-accent/90 transition-colors"
              >
                Log In to Accept
              </Link>
            </div>
          )}

          {/* Case 3: Logged in - show accept button */}
          {user && (
            <div className="mt-6 space-y-3">
              <button
                onClick={handleAccept}
                disabled={accepting}
                className="w-full px-4 py-2 bg-accent text-white rounded-md hover:bg-accent/90 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                {accepting ? 'Accepting...' : 'Accept Invite'}
              </button>
              <Link
                to="/docs"
                className="block w-full px-4 py-2 border border-border text-foreground text-center rounded-md hover:bg-border/30 transition-colors"
              >
                Decline
              </Link>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function ErrorIcon({ className }: { className?: string }) {
  return (
    <svg className={className} fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M6 18L18 6M6 6l12 12" />
    </svg>
  );
}

function ClockIcon({ className }: { className?: string }) {
  return (
    <svg className={className} fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
    </svg>
  );
}

function CheckIcon({ className }: { className?: string }) {
  return (
    <svg className={className} fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M5 13l4 4L19 7" />
    </svg>
  );
}

function InviteIcon({ className }: { className?: string }) {
  return (
    <svg className={className} fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M18 9v3m0 0v3m0-3h3m-3 0h-3m-2-5a4 4 0 11-8 0 4 4 0 018 0zM3 20a6 6 0 0112 0v1H3v-1z" />
    </svg>
  );
}

import { useState, useEffect, useMemo, type FormEvent } from 'react';
import { useNavigate, useLocation, useSearchParams } from 'react-router-dom';
import { useAuth } from '@/hooks/useAuth';
import { cn } from '@/lib/cn';
import { Icon } from '@/components/icons/uswds';

const API_URL = import.meta.env.VITE_API_URL ?? '';

// Validate that returnTo URL is same-origin (security measure)
function isValidReturnTo(url: string): boolean {
  try {
    // If it starts with /, it's a relative path - safe
    if (url.startsWith('/') && !url.startsWith('//')) {
      return true;
    }
    // Otherwise check if it's same origin
    const parsed = new URL(url, window.location.origin);
    return parsed.origin === window.location.origin;
  } catch {
    return false;
  }
}

export function LoginPage() {
  // Don't pre-fill in E2E tests (navigator.webdriver is true when controlled by Playwright)
  const isAutomated = typeof navigator !== 'undefined' && navigator.webdriver;
  const shouldPrefill = import.meta.env.DEV && !isAutomated;
  const [email, setEmail] = useState(shouldPrefill ? 'dev@ship.local' : '');
  const [password, setPassword] = useState(shouldPrefill ? 'admin123' : '');
  const [error, setError] = useState('');
  const [errorField, setErrorField] = useState<'email' | 'password' | 'general' | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isCheckingSetup, setIsCheckingSetup] = useState(true);
  const [isOnline, setIsOnline] = useState(navigator.onLine);
  const [caiaAvailable, setCaiaAvailable] = useState(false);
  const [isCaiaLoading, setIsCaiaLoading] = useState(false);

  // Subscribe to online/offline status changes using native browser events
  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  const { login } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [searchParams] = useSearchParams();

  // Check if session expired
  const sessionExpired = searchParams.get('expired') === 'true';

  // Check for error from OAuth callback (PIV auth failures)
  const urlError = searchParams.get('error');

  // Get returnTo URL with validation
  const returnTo = useMemo(() => {
    const returnToParam = searchParams.get('returnTo');
    if (returnToParam) {
      const decoded = decodeURIComponent(returnToParam);
      if (isValidReturnTo(decoded)) {
        return decoded;
      }
    }
    return null;
  }, [searchParams]);

  // Default redirect path from location state or returnTo param
  const from = returnTo || (location.state as { from?: { pathname: string } })?.from?.pathname || '/';

  // Check if setup is needed and if PIV auth is available
  useEffect(() => {
    async function checkSetup() {
      try {
        const res = await fetch(`${API_URL}/api/setup/status`, {
          credentials: 'include',
        });
        const data = await res.json();

        if (data.success && data.data.needsSetup) {
          navigate('/setup', { replace: true });
          return;
        }
      } catch (err) {
        // If we can't check, just show login
        console.error('Failed to check setup status:', err);
      }
      setIsCheckingSetup(false);
    }

    async function checkCaiaStatus() {
      try {
        const res = await fetch(`${API_URL}/api/auth/caia/status`, {
          credentials: 'include',
        });
        const data = await res.json();
        if (data.success && data.data.available) {
          setCaiaAvailable(true);
        }
      } catch (err) {
        // CAIA not available, that's fine
        console.debug('CAIA auth not available:', err);
      }
    }

    checkSetup();
    checkCaiaStatus();
  }, [navigate]);

  async function handleCaiaLogin() {
    setError('');
    setErrorField(null);
    setIsCaiaLoading(true);

    try {
      const res = await fetch(`${API_URL}/api/auth/caia/login`, {
        credentials: 'include',
      });
      const data = await res.json();

      if (data.success && data.data.authorizationUrl) {
        // Redirect to CAIA for PIV authentication
        window.location.href = data.data.authorizationUrl;
      } else {
        setError(data.error?.message || 'Failed to initiate CAIA login');
        setErrorField('general');
        setIsCaiaLoading(false);
      }
    } catch (err) {
      console.error('CAIA login error:', err);
      setError('Failed to connect to CAIA authentication service');
      setErrorField('general');
      setIsCaiaLoading(false);
    }
  }

  async function handleSubmit(e: FormEvent) {
    e.preventDefault();
    setError('');
    setErrorField(null);

    // Manual validation for accessibility (shows role="alert" error messages)
    if (!email.trim()) {
      setError('Email address is required');
      setErrorField('email');
      return;
    }
    if (!password) {
      setError('Password is required');
      setErrorField('password');
      return;
    }

    setIsLoading(true);

    const result = await login(email, password);

    if (result.success) {
      navigate(from, { replace: true });
    } else {
      setError(result.error || 'Login failed');
      setErrorField('email'); // Associate general login errors with email field
      setIsLoading(false);
    }
  }

  if (isCheckingSetup) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-background">
        <div className="text-muted">Loading...</div>
      </div>
    );
  }

  return (
    <main className="flex min-h-screen items-center justify-center bg-background px-4">
      <div className="w-full max-w-[360px]">
        {/* Logo / Brand */}
        <div className="mb-8 text-center">
          <img
            src="/icons/white/logo-128.png"
            alt="Ship"
            className="mx-auto h-16 w-16"
          />
          <h1 className="mt-4 text-2xl font-semibold text-foreground">Sign in to Ship</h1>
          <p className="mt-2 text-sm text-muted">Enter your credentials to continue</p>
        </div>

        {/* Login Form */}
        <form onSubmit={handleSubmit} noValidate className="space-y-4">
          {/* Offline message */}
          {!isOnline && (
            <div
              role="alert"
              className="rounded-md border border-yellow-500/20 bg-yellow-500/10 px-4 py-3 text-sm text-yellow-400"
            >
              You're currently offline. Please connect to the internet to sign in.
            </div>
          )}

          {/* Session expired message */}
          {sessionExpired && (
            <div
              role="alert"
              className="rounded-md border border-yellow-500/20 bg-yellow-500/10 px-4 py-3 text-sm text-yellow-400"
            >
              Your session expired due to inactivity. Please log in again.
            </div>
          )}

          {/* Error from URL (OAuth callback failures) */}
          {urlError && !error && (
            <div
              id="login-error"
              role="alert"
              className="rounded-md border border-red-500/20 bg-red-500/10 px-4 py-3 text-sm text-red-400"
            >
              {urlError}
            </div>
          )}

          {/* Error from form submission */}
          {error && (
            <div
              id="login-error"
              role="alert"
              className="rounded-md border border-red-500/20 bg-red-500/10 px-4 py-3 text-sm text-red-400"
            >
              {error}
            </div>
          )}

          <div>
            <label htmlFor="email" className="sr-only">
              Email address
            </label>
            <input
              id="email"
              name="email"
              type="email"
              autoComplete="email"
              autoFocus
              required
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Email address"
              aria-invalid={errorField === 'email' ? 'true' : undefined}
              aria-describedby={errorField === 'email' ? 'login-error' : undefined}
              className={cn(
                'w-full rounded-md border border-border bg-background px-4 py-2.5',
                'text-sm text-foreground placeholder:text-muted',
                'transition-colors focus:border-accent focus:outline-none'
              )}
            />
          </div>

          <div>
            <label htmlFor="password" className="sr-only">
              Password
            </label>
            <input
              id="password"
              name="password"
              type="password"
              autoComplete="current-password"
              required
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Password"
              aria-invalid={errorField === 'password' ? 'true' : undefined}
              aria-describedby={errorField === 'password' ? 'login-error' : undefined}
              className={cn(
                'w-full rounded-md border border-border bg-background px-4 py-2.5',
                'text-sm text-foreground placeholder:text-muted',
                'transition-colors focus:border-accent focus:outline-none'
              )}
            />
          </div>

          <button
            type="submit"
            disabled={isLoading}
            className={cn(
              'w-full rounded-md bg-accent px-4 py-2.5 text-sm font-medium text-white',
              'transition-colors hover:bg-accent-hover',
              'focus:outline-none focus:ring-2 focus:ring-accent focus:ring-offset-2 focus:ring-offset-background',
              'disabled:cursor-not-allowed disabled:opacity-50'
            )}
          >
            {isLoading ? 'Signing in...' : 'Sign in'}
          </button>
        </form>

        {/* PIV Authentication via CAIA */}
        {caiaAvailable && (
          <>
            <div className="relative my-6">
              <div className="absolute inset-0 flex items-center">
                <div className="w-full border-t border-border" />
              </div>
              <div className="relative flex justify-center text-xs">
                <span className="bg-background px-2 text-muted">or sign in with PIV</span>
              </div>
            </div>

            <button
              type="button"
              onClick={handleCaiaLogin}
              disabled={isCaiaLoading || !isOnline}
              className={cn(
                'w-full rounded-md border border-border bg-background px-4 py-2.5',
                'text-sm font-medium text-foreground',
                'transition-colors hover:bg-muted/50',
                'focus:outline-none focus:ring-2 focus:ring-accent focus:ring-offset-2 focus:ring-offset-background',
                'disabled:cursor-not-allowed disabled:opacity-50',
                'flex items-center justify-center gap-2'
              )}
            >
              <svg
                className="h-5 w-5"
                viewBox="0 0 24 24"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
              >
                <rect x="3" y="4" width="18" height="16" rx="2" />
                <rect x="7" y="8" width="3" height="3" rx="0.5" />
                <line x1="14" y1="9.5" x2="17" y2="9.5" />
                <line x1="7" y1="14" x2="17" y2="14" />
                <line x1="7" y1="17" x2="13" y2="17" />
              </svg>
              {isCaiaLoading ? 'Connecting...' : 'Sign in with PIV Card'}
            </button>
          </>
        )}

        {/* Dev credentials hint - only shown in development */}
        {import.meta.env.DEV && (
          <div className="mt-8 text-center text-xs text-muted">
            <p>Dev credentials:</p>
            <p className="mt-1 font-mono text-muted">
              dev@ship.local / admin123
            </p>
          </div>
        )}

        {/*
          USWDS Icon visual verification - different sizes and colors
          Used in E2E tests to verify icons are loading correctly 
        */}
        {import.meta.env.VITE_APP_ENV !== 'production' && (
          <div data-testid="uswds-icons" className="mt-6 border-t border-border pt-4 text-center text-xs text-muted">
            <p className="mb-2 text-muted">USWDS Icons:</p>
            <div className="flex items-center justify-center gap-3">
              <Icon name="check" className="h-3 w-3 text-green-500" title="Check (h-3)" />
              <Icon name="close" className="h-4 w-4 text-red-400" title="Close (h-4)" />
              <Icon name="warning" className="h-5 w-5 text-yellow-500" title="Warning (h-5)" />
              <Icon name="info" className="h-6 w-6 text-accent" title="Info (h-6)" />
            </div>
          </div>
        )}
      </div>
    </main>
  );
}

