import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import * as Dialog from '@radix-ui/react-dialog';
import { ProjectCombobox, Project } from '@/components/ProjectCombobox';
import { useAuth } from '@/hooks/useAuth';
import { cn } from '@/lib/cn';
import { apiPost, apiGet, apiDelete } from '@/lib/api';
import { formatDateRange } from '@/lib/date-utils';

interface User {
  personId: string; // Document ID - used for allocations (works for both pending and active)
  id: string | null; // User account ID - null for pending users
  name: string;
  email: string;
  isArchived?: boolean;
  isPending?: boolean;
  reportsTo?: string | null; // user_id of supervisor
}

interface Sprint {
  number: number;
  name: string;
  startDate: string;
  endDate: string;
  isCurrent: boolean;
}

interface Assignment {
  projectId: string | null;
  projectName: string | null;
  projectColor: string | null;
  programId: string | null;
  programName: string | null;
  emoji?: string | null;
  color: string | null;
}

interface TeamGridData {
  users: User[];
  weeks: Sprint[];
  currentSprintNumber: number;
}

const SPRINTS_PER_LOAD = 5;
const SCROLL_THRESHOLD = 200;

// Program group info for grouping users
interface ProgramGroup {
  programId: string | null;
  programName: string;
  emoji: string | null;
  color: string | null;
  users: User[];
}

export function TeamModePage() {
  const navigate = useNavigate();
  const { user } = useAuth();
  const [data, setData] = useState<TeamGridData | null>(null);
  const [projects, setProjects] = useState<Project[]>([]);
  const [assignments, setAssignments] = useState<Record<string, Record<number, Assignment>>>({});
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState<'left' | 'right' | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showArchived, setShowArchived] = useState(false);
  const [showPastWeeks, setShowPastWeeks] = useState(() => {
    try {
      return localStorage.getItem('ship:allocation-show-past-weeks') === 'true';
    } catch { return false; }
  });
  const [filterMode, setFilterMode] = useState<'my-team' | 'everyone' | null>(() => {
    try {
      const stored = localStorage.getItem('ship:allocation-filter-mode');
      if (stored === 'my-team' || stored === 'everyone') return stored;
    } catch { /* ignore */ }
    return null;
  });
  const [nameFilter, setNameFilter] = useState('');
  const [sprintRange, setSprintRange] = useState<{ min: number; max: number } | null>(null);
  const [collapsedPrograms, setCollapsedPrograms] = useState<Set<string>>(new Set());
  const [viewAsSprintNumber, setViewAsSprintNumber] = useState<number | null>(null);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const hasScrolledToCurrentRef = useRef(false);

  // Find the current sprint number
  const currentSprintNumber = data?.currentSprintNumber ?? null;

  // Filter weeks to hide past weeks when showPastWeeks is false
  const visibleWeeks = useMemo(() => {
    if (!data) return [];
    if (showPastWeeks || currentSprintNumber === null) return data.weeks;
    return data.weeks.filter(s => s.number >= currentSprintNumber);
  }, [data, showPastWeeks, currentSprintNumber]);

  // Smart default: if user has direct reports, default to "my-team"
  const hasDirectReports = useMemo(() => {
    if (!data || !user?.id) return false;
    return data.users.some(u => u.reportsTo === user.id);
  }, [data, user?.id]);

  // Set smart default when data first loads (only if no stored value)
  useEffect(() => {
    if (data && filterMode === null) {
      setFilterMode(hasDirectReports ? 'my-team' : 'everyone');
    }
  }, [data, filterMode, hasDirectReports]);

  // Persist filter mode and past-weeks visibility to localStorage
  useEffect(() => {
    if (filterMode !== null) {
      localStorage.setItem('ship:allocation-filter-mode', filterMode);
    }
  }, [filterMode]);

  useEffect(() => {
    localStorage.setItem('ship:allocation-show-past-weeks', String(showPastWeeks));
  }, [showPastWeeks]);

  // Filter users based on filter mode and name search
  const filteredUsers = useMemo(() => {
    if (!data) return [];
    let users = data.users;
    if (filterMode === 'my-team' && user?.id) {
      users = users.filter(u => u.reportsTo === user.id);
    }
    if (nameFilter.trim()) {
      const query = nameFilter.trim().toLowerCase();
      users = users.filter(u => u.name.toLowerCase().includes(query));
    }
    return users;
  }, [data, filterMode, user?.id, nameFilter]);

  // Group users by their assignment's program for the viewed sprint
  const groupingSprintNumber = viewAsSprintNumber ?? currentSprintNumber;

  const programGroups = useMemo((): ProgramGroup[] => {
    if (!data) return [];

    const groups: Map<string, ProgramGroup> = new Map();
    const UNASSIGNED_KEY = '__unassigned__';

    for (const user of filteredUsers) {
      const currentAssignment = groupingSprintNumber
        ? assignments[user.personId]?.[groupingSprintNumber]
        : null;

      const groupKey = currentAssignment?.programId || UNASSIGNED_KEY;

      if (!groups.has(groupKey)) {
        groups.set(groupKey, {
          programId: currentAssignment?.programId || null,
          programName: currentAssignment?.programName || 'Unassigned',
          emoji: currentAssignment?.emoji || null,
          color: currentAssignment?.color || null,
          users: [],
        });
      }

      groups.get(groupKey)!.users.push(user);
    }

    // Sort groups: alphabetically by name, with Unassigned last
    const sortedGroups = Array.from(groups.values()).sort((a, b) => {
      if (a.programId === null) return 1;
      if (b.programId === null) return -1;
      return a.programName.localeCompare(b.programName);
    });

    // Sort users within each group alphabetically
    for (const group of sortedGroups) {
      group.users.sort((a, b) => a.name.localeCompare(b.name));
    }

    return sortedGroups;
  }, [data, filteredUsers, assignments, groupingSprintNumber]);

  // Toggle program group collapse
  const toggleProgramCollapse = useCallback((programId: string | null) => {
    const key = programId || '__unassigned__';
    setCollapsedPrograms(prev => {
      const next = new Set(prev);
      if (next.has(key)) {
        next.delete(key);
      } else {
        next.add(key);
      }
      return next;
    });
  }, []);

  // Dialog states
  const [lastPersonDialog, setLastPersonDialog] = useState<{
    open: boolean;
    userId: string;
    sprintNumber: number;
    issuesOrphaned: Array<{ id: string; title: string }>;
    onConfirm: () => void;
  } | null>(null);
  const [operationLoading, setOperationLoading] = useState<string | null>(null);

  // Initial load
  useEffect(() => {
    Promise.all([
      fetchTeamGrid(undefined, undefined, showArchived),
      fetchProjects(),
      fetchAssignments(),
    ]).finally(() => setLoading(false));
  }, []);

  // Refetch when showArchived changes
  useEffect(() => {
    // Skip initial render
    if (loading) return;
    fetchTeamGrid(sprintRange?.min, sprintRange?.max, showArchived);
  }, [showArchived]);

  // Scroll to current sprint on initial load (only when past weeks are shown)
  useEffect(() => {
    if (!showPastWeeks) return; // No need to scroll when past weeks are hidden
    if (data && scrollContainerRef.current && !hasScrolledToCurrentRef.current) {
      const currentSprintIndex = data.weeks.findIndex(s => s.isCurrent);
      if (currentSprintIndex >= 0) {
        requestAnimationFrame(() => {
          if (scrollContainerRef.current) {
            const columnWidth = 180; // matches w-[180px] on sprint columns
            const scrollPosition = currentSprintIndex * columnWidth;
            scrollContainerRef.current.scrollLeft = scrollPosition;
            hasScrolledToCurrentRef.current = true;
          }
        });
      }
    }
  }, [data, showPastWeeks]);

  async function fetchTeamGrid(fromSprint?: number, toSprint?: number, includeArchived = false) {
    try {
      const params = new URLSearchParams();
      if (fromSprint !== undefined) params.set('fromSprint', String(fromSprint));
      if (toSprint !== undefined) params.set('toSprint', String(toSprint));
      if (includeArchived) params.set('includeArchived', 'true');

      const url = `/api/team/grid${params.toString() ? `?${params}` : ''}`;
      const res = await apiGet(url);
      if (!res.ok) throw new Error('Failed to fetch team grid');
      const json: TeamGridData = await res.json();

      if (json.weeks.length > 0) {
        setSprintRange({
          min: json.weeks[0].number,
          max: json.weeks[json.weeks.length - 1].number,
        });
      }

      setData(json);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown error');
    }
  }

  async function fetchProjects() {
    try {
      const res = await apiGet(`/api/team/projects`);
      if (res.ok) {
        const json = await res.json();
        setProjects(json);
      }
    } catch (err) {
      console.error('Failed to fetch projects:', err);
    }
  }

  async function fetchAssignments() {
    try {
      const res = await apiGet(`/api/team/assignments`);
      if (res.ok) {
        const json = await res.json();
        setAssignments(json);
      }
    } catch (err) {
      console.error('Failed to fetch assignments:', err);
    }
  }

  const handleAssign = async (personId: string, projectId: string, sprintNumber: number) => {
    const project = projects.find(p => p.id === projectId);
    if (!project) return;

    // Optimistic update - update UI immediately
    const previousAssignment = assignments[personId]?.[sprintNumber];
    setAssignments(prev => ({
      ...prev,
      [personId]: {
        ...prev[personId],
        [sprintNumber]: {
          projectId,
          projectName: project.title,
          projectColor: project.color ?? null,
          programId: project.programId,
          programName: project.programName,
          emoji: project.programEmoji ?? null,
          color: project.programColor ?? null,
        },
      },
    }));

    try {
      const res = await apiPost(`/api/team/assign`, { personId, projectId, sprintNumber });

      const json = await res.json();

      if (!res.ok) {
        // Rollback optimistic update
        setAssignments(prev => {
          const newAssignments = { ...prev };
          if (previousAssignment) {
            newAssignments[personId] = { ...newAssignments[personId], [sprintNumber]: previousAssignment };
          } else {
            const { [sprintNumber]: _, ...rest } = newAssignments[personId] || {};
            newAssignments[personId] = rest;
          }
          return newAssignments;
        });
        setError(json.error || 'Failed to assign');
        return;
      }
    } catch (err) {
      // Rollback optimistic update
      setAssignments(prev => {
        const newAssignments = { ...prev };
        if (previousAssignment) {
          newAssignments[personId] = { ...newAssignments[personId], [sprintNumber]: previousAssignment };
        } else {
          const { [sprintNumber]: _, ...rest } = newAssignments[personId] || {};
          newAssignments[personId] = rest;
        }
        return newAssignments;
      });
      setError('Failed to assign user');
    }
  };

  const handleUnassign = async (personId: string, sprintNumber: number, skipConfirmation = false) => {
    // Optimistic update - remove from UI immediately
    const previousAssignment = assignments[personId]?.[sprintNumber];
    setAssignments(prev => {
      const newAssignments = { ...prev };
      if (newAssignments[personId]) {
        const { [sprintNumber]: _, ...rest } = newAssignments[personId];
        newAssignments[personId] = rest;
      }
      return newAssignments;
    });

    try {
      const res = await apiDelete(`/api/team/assign`, { personId, sprintNumber });

      const json = await res.json();

      if (!res.ok) {
        // Rollback optimistic update
        if (previousAssignment) {
          setAssignments(prev => ({
            ...prev,
            [personId]: {
              ...prev[personId],
              [sprintNumber]: previousAssignment,
            },
          }));
        }
        setError(json.error || 'Failed to unassign');
        return;
      }

      // If there were orphaned issues, show them in a dialog (unless skipped)
      if (json.issuesOrphaned?.length > 0 && !skipConfirmation) {
        // Issues were already moved to backlog
      }
    } catch (err) {
      // Rollback optimistic update
      if (previousAssignment) {
        setAssignments(prev => ({
          ...prev,
          [personId]: {
            ...prev[personId],
            [sprintNumber]: previousAssignment,
          },
        }));
      }
      setError('Failed to unassign user');
    }
  };

  const handleCellChange = useCallback((
    personId: string,
    userName: string,
    sprintNumber: number,
    sprintName: string,
    newProjectId: string | null,
    currentAssignment: Assignment | null
  ) => {
    // Same project - no change
    if (newProjectId === currentAssignment?.projectId) {
      return;
    }

    // Clear assignment
    if (newProjectId === null && currentAssignment) {
      handleUnassign(personId, sprintNumber);
      return;
    }

    // New assignment or adding to existing - both just call handleAssign
    // (multiple people can now be assigned to same project/sprint)
    if (newProjectId) {
      handleAssign(personId, newProjectId, sprintNumber);
    }
  }, [projects]);

  // Fetch more sprints
  const fetchMoreSprints = useCallback(async (direction: 'left' | 'right') => {
    if (!data || !sprintRange || loadingMore) return;

    const fromSprint = direction === 'left'
      ? Math.max(1, sprintRange.min - SPRINTS_PER_LOAD)
      : sprintRange.max + 1;
    const toSprint = direction === 'left'
      ? sprintRange.min - 1
      : sprintRange.max + SPRINTS_PER_LOAD;

    if (direction === 'left' && sprintRange.min <= 1) return;

    setLoadingMore(direction);

    try {
      const params = new URLSearchParams({
        fromSprint: String(fromSprint),
        toSprint: String(toSprint),
      });
      if (showArchived) params.set('includeArchived', 'true');

      const res = await apiGet(`/api/team/grid?${params}`);
      if (!res.ok) throw new Error('Failed to fetch more sprints');
      const newData: TeamGridData = await res.json();

      const scrollContainer = scrollContainerRef.current;
      const prevScrollLeft = scrollContainer?.scrollLeft || 0;
      const prevScrollWidth = scrollContainer?.scrollWidth || 0;

      setData(prev => {
        if (!prev) return newData;
        const mergedSprints = direction === 'left'
          ? [...newData.weeks, ...prev.weeks]
          : [...prev.weeks, ...newData.weeks];
        return { ...prev, weeks: mergedSprints };
      });

      setSprintRange(prev => {
        if (!prev) return { min: fromSprint, max: toSprint };
        return {
          min: direction === 'left' ? fromSprint : prev.min,
          max: direction === 'right' ? toSprint : prev.max,
        };
      });

      if (direction === 'left' && scrollContainer) {
        requestAnimationFrame(() => {
          const newScrollWidth = scrollContainer.scrollWidth;
          const addedWidth = newScrollWidth - prevScrollWidth;
          scrollContainer.scrollLeft = prevScrollLeft + addedWidth;
        });
      }
    } catch (err) {
      console.error('Error loading more sprints:', err);
    } finally {
      setLoadingMore(null);
    }
  }, [data, sprintRange, loadingMore, showArchived]);

  const handleScroll = useCallback(() => {
    const container = scrollContainerRef.current;
    if (!container || loadingMore) return;

    const { scrollLeft, scrollWidth, clientWidth } = container;

    if (showPastWeeks && scrollLeft < SCROLL_THRESHOLD && sprintRange && sprintRange.min > 1) {
      fetchMoreSprints('left');
    }

    if (scrollWidth - scrollLeft - clientWidth < SCROLL_THRESHOLD) {
      fetchMoreSprints('right');
    }
  }, [fetchMoreSprints, loadingMore, sprintRange, showPastWeeks]);

  useEffect(() => {
    const container = scrollContainerRef.current;
    if (!container) return;

    container.addEventListener('scroll', handleScroll);
    return () => container.removeEventListener('scroll', handleScroll);
  }, [handleScroll]);

  // Escape key clears view-as mode
  useEffect(() => {
    if (viewAsSprintNumber === null) return;
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setViewAsSprintNumber(null);
    };
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [viewAsSprintNumber]);

  // Clear error after 3 seconds
  useEffect(() => {
    if (error) {
      const timer = setTimeout(() => setError(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [error]);

  if (loading) {
    return (
      <div className="flex h-full items-center justify-center">
        <div className="text-muted">Loading team grid...</div>
      </div>
    );
  }

  if (!data) {
    return (
      <div className="flex h-full items-center justify-center">
        <div className="text-red-500">{error || 'Failed to load data'}</div>
      </div>
    );
  }

  return (
    <div className="flex h-full flex-col">
      {/* Error toast */}
      {error && (
        <div className="absolute right-4 top-4 z-50 rounded-md bg-red-500/90 px-4 py-2 text-sm text-white shadow-lg">
          {error}
        </div>
      )}

      {/* Header */}
      <header className="flex h-10 items-center justify-between border-b border-border px-4">
        <div className="flex items-center gap-3">
          <h1 className="text-sm font-medium text-foreground">Allocation</h1>
          {hasDirectReports && (
            <div className="flex rounded-md border border-border text-xs">
              <button
                onClick={() => setFilterMode('my-team')}
                className={cn(
                  'px-2 py-0.5 transition-colors',
                  filterMode === 'my-team'
                    ? 'bg-accent text-white'
                    : 'text-muted hover:text-foreground'
                )}
              >
                My Team
              </button>
              <button
                onClick={() => setFilterMode('everyone')}
                className={cn(
                  'px-2 py-0.5 transition-colors',
                  filterMode === 'everyone'
                    ? 'bg-accent text-white'
                    : 'text-muted hover:text-foreground'
                )}
              >
                Everyone
              </button>
            </div>
          )}
          <div className="relative">
            <input
              type="text"
              value={nameFilter}
              onChange={(e) => setNameFilter(e.target.value)}
              placeholder="Filter by name..."
              className="h-6 w-36 rounded border border-border bg-transparent px-2 text-xs text-foreground placeholder:text-muted focus:border-accent focus:outline-none"
            />
            {nameFilter && (
              <button
                onClick={() => setNameFilter('')}
                className="absolute right-1 top-1/2 -translate-y-1/2 rounded p-0.5 text-muted hover:text-foreground"
              >
                <svg className="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            )}
          </div>
          {viewAsSprintNumber !== null && (
            <div className="flex items-center gap-1.5 rounded-md border border-accent/30 bg-accent/10 px-2 py-0.5 text-xs font-medium text-foreground">
              <span>Viewing as {data.weeks.find(w => w.number === viewAsSprintNumber)?.name ?? `Week ${viewAsSprintNumber}`}</span>
              <button
                onClick={() => setViewAsSprintNumber(null)}
                className="ml-0.5 rounded p-0.5 hover:bg-accent/20"
                title="Return to current week"
              >
                <svg className="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
          )}
        </div>
        <div className="flex items-center gap-4">
          <button
            onClick={() => setShowPastWeeks(prev => !prev)}
            className={cn(
              'flex items-center gap-1 rounded-md border border-border px-2 py-0.5 text-xs transition-colors',
              showPastWeeks
                ? 'bg-accent text-white border-accent'
                : 'text-muted hover:text-foreground hover:border-foreground/30'
            )}
          >
            <svg className="h-3 w-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
            </svg>
            {showPastWeeks ? 'Hide' : 'Show'} past weeks
          </button>
          <label className="flex items-center gap-1.5 cursor-pointer">
            <input
              type="checkbox"
              checked={showArchived}
              onChange={(e) => setShowArchived(e.target.checked)}
              className="h-3.5 w-3.5 rounded border-border text-accent focus:ring-accent/50"
            />
            <span className="text-xs text-muted">Show archived</span>
          </label>
          <span className="text-xs text-muted">
            {filteredUsers.length} team members &middot; {projects.length} projects
          </span>
        </div>
      </header>

      {/* Assignments Grid - Single scroll container with sticky person column */}
      <div
        ref={scrollContainerRef}
        className="flex-1 overflow-auto pb-20"
      >
          <div className="inline-flex min-w-full">
            {/* Sticky person column */}
            <div className="flex flex-col sticky left-0 z-20 bg-background border-r border-border">
              {/* Header cell */}
              <div className="flex h-10 w-[180px] items-center justify-center border-b border-border px-3 sticky top-0 z-30 bg-background">
                <span className="text-xs font-medium text-muted">Team Member</span>
              </div>

              {/* Program groups with users */}
              {programGroups.map((group) => {
                const groupKey = group.programId || '__unassigned__';
                const isCollapsed = collapsedPrograms.has(groupKey);

                return (
                  <div key={groupKey}>
                    {/* Program group header */}
                    <button
                      onClick={() => toggleProgramCollapse(group.programId)}
                      className="flex h-8 w-[180px] items-center gap-2 border-b border-border bg-border/30 px-3 hover:bg-border/50 transition-colors cursor-pointer"
                    >
                      <ChevronIcon
                        className={cn(
                          "h-3 w-3 text-muted transition-transform",
                          isCollapsed && "-rotate-90"
                        )}
                      />
                      {group.programId ? (
                        <span
                          className="shrink-0 rounded px-1.5 py-0.5 text-[10px] font-bold text-white"
                          style={{ backgroundColor: group.color || '#6b7280' }}
                        >
                          {group.emoji || group.programName[0]}
                        </span>
                      ) : (
                        <span className="shrink-0 rounded px-1.5 py-0.5 text-[10px] font-bold text-white bg-gray-500">
                          ?
                        </span>
                      )}
                      <span className="truncate text-xs font-medium text-foreground">
                        {isCollapsed ? `${group.programName} (${group.users.length})` : group.programName}
                      </span>
                      {!isCollapsed && (
                        <span className="ml-auto text-[10px] text-muted">
                          {group.users.length}
                        </span>
                      )}
                    </button>

                    {/* Users in this group */}
                    {!isCollapsed && group.users.map((user, idx) => (
                      <div
                        key={user.id ?? `pending-${idx}`}
                        className={cn(
                          "flex h-12 w-[180px] items-center border-b border-border px-3 bg-background",
                          user.isArchived && "opacity-50",
                          user.isPending && "opacity-70"
                        )}
                      >
                        <div className="flex items-center gap-2 overflow-hidden">
                          <div className={cn(
                            "flex h-6 w-6 flex-shrink-0 items-center justify-center rounded-full text-xs font-medium text-white",
                            user.isArchived ? "bg-gray-400" : user.isPending ? "bg-gray-400" : "bg-accent/80"
                          )}>
                            {user.name.charAt(0).toUpperCase()}
                          </div>
                          <span className={cn(
                            "truncate text-sm",
                            user.isArchived ? "text-muted" : user.isPending ? "text-muted italic" : "text-foreground"
                          )}>
                            {user.name}
                            {user.isArchived && <span className="ml-1 text-xs">(archived)</span>}
                            {user.isPending && <span className="ml-1 text-xs font-normal not-italic">(pending)</span>}
                          </span>
                        </div>
                      </div>
                    ))}
                  </div>
                );
              })}
            </div>

            {/* Sprint columns */}
            <div className="flex">
              {loadingMore === 'left' && (
                <div className="flex flex-col w-[60px]">
                  <div className="h-10 flex items-center justify-center border-b border-border sticky top-0 bg-background z-10">
                    <span className="text-xs text-muted animate-pulse">...</span>
                  </div>
                </div>
              )}

              {visibleWeeks.map((sprint) => {
                const isActiveViewAs = sprint.number === viewAsSprintNumber;
                const isDefaultCurrent = sprint.isCurrent && viewAsSprintNumber === null;
                const showViewAsButton = !isActiveViewAs && !isDefaultCurrent;

                return (
                <div key={sprint.number} className="flex flex-col">
                  {/* Sprint header */}
                  <div
                    className={cn(
                      'group flex h-10 w-[180px] flex-col items-center justify-center border-b border-r border-border px-2 sticky top-0 z-10 bg-background',
                      sprint.isCurrent && 'ring-1 ring-inset ring-accent/30',
                      isActiveViewAs && 'ring-2 ring-inset ring-accent/50 bg-accent/5'
                    )}
                  >
                    <span className={cn(
                      'text-xs font-medium text-foreground',
                      sprint.isCurrent && 'font-semibold'
                    )}>
                      {sprint.name}
                    </span>
                    <span className="text-[10px] text-muted">
                      {formatDateRange(sprint.startDate, sprint.endDate)}
                    </span>
                    {showViewAsButton && (
                      <button
                        onClick={() => setViewAsSprintNumber(sprint.number)}
                        title="View as current week"
                        className="absolute right-1 top-1/2 -translate-y-1/2 rounded p-0.5 text-muted opacity-0 transition-opacity hover:bg-border/50 hover:text-foreground group-hover:opacity-100"
                      >
                        <ViewAsIcon className="h-3.5 w-3.5" />
                      </button>
                    )}
                  </div>

                  {/* Sprint cells grouped by program */}
                  {programGroups.map((group) => {
                    const groupKey = group.programId || '__unassigned__';
                    const isCollapsed = collapsedPrograms.has(groupKey);

                    return (
                      <div key={groupKey}>
                        {/* Program header spacer row for this sprint column */}
                        <div
                          className={cn(
                            "h-8 w-[180px] border-b border-r border-border bg-border/30",
                            sprint.isCurrent && "bg-accent/5"
                          )}
                        />

                        {/* Cells for users in this group */}
                        {!isCollapsed && group.users.map((user) => {
                          const isPending = user.isPending || !user.id;
                          const assignment = assignments[user.personId]?.[sprint.number];
                          const previousWeekAssignment = assignments[user.personId]?.[sprint.number - 1];
                          const cellKey = `${user.personId}-${sprint.number}`;
                          const isLoading = operationLoading === cellKey;

                          return (
                            <SprintCell
                              key={cellKey}
                              assignment={assignment}
                              previousWeekAssignment={previousWeekAssignment}
                              projects={projects}
                              isCurrent={sprint.isCurrent}
                              loading={isLoading}
                              isPending={isPending}
                              onChange={(projectId) => {
                                handleCellChange(
                                  user.personId,
                                  user.name,
                                  sprint.number,
                                  sprint.name,
                                  projectId,
                                  assignment || null
                                );
                              }}
                              onNavigate={(projectId) => navigate(`/documents/${projectId}`)}
                            />
                          );
                        })}
                      </div>
                    );
                  })}
                </div>
                );
              })}

              {loadingMore === 'right' && (
                <div className="flex flex-col w-[60px]">
                  <div className="h-10 flex items-center justify-center border-b border-border sticky top-0 bg-background z-10">
                    <span className="text-xs text-muted animate-pulse">...</span>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

      {/* Last Person Dialog */}
      <Dialog.Root open={lastPersonDialog?.open || false} onOpenChange={(open: boolean) => !open && setLastPersonDialog(null)}>
        <Dialog.Portal>
          <Dialog.Overlay className="fixed inset-0 z-50 bg-black/50" />
          <Dialog.Content className="fixed left-1/2 top-1/2 z-50 w-full max-w-md -translate-x-1/2 -translate-y-1/2 rounded-lg border border-border bg-background p-6 shadow-xl">
            <Dialog.Title className="text-lg font-semibold text-foreground">
              Remove Last Assignee
            </Dialog.Title>
            <Dialog.Description className="mt-2 text-sm text-muted">
              This is the last person assigned to this sprint. Removing them will delete the sprint document.
            </Dialog.Description>

            {lastPersonDialog?.issuesOrphaned && lastPersonDialog.issuesOrphaned.length > 0 && (
              <div className="mt-4">
                <p className="text-sm font-medium text-foreground">
                  {lastPersonDialog.issuesOrphaned.length} issues will be moved to backlog:
                </p>
                <ul className="mt-2 max-h-[150px] overflow-auto rounded border border-border p-2">
                  {lastPersonDialog.issuesOrphaned.map((issue) => (
                    <li key={issue.id} className="text-sm text-muted truncate">
                      {issue.title}
                    </li>
                  ))}
                </ul>
              </div>
            )}

            <div className="mt-6 flex justify-end gap-3">
              <Dialog.Close asChild>
                <button className="rounded-md px-4 py-2 text-sm text-muted hover:bg-border">
                  Cancel
                </button>
              </Dialog.Close>
              <button
                onClick={() => {
                  lastPersonDialog?.onConfirm();
                  setLastPersonDialog(null);
                }}
                className="rounded-md bg-red-600 px-4 py-2 text-sm text-white hover:bg-red-700"
              >
                Remove & Delete Week
              </button>
            </div>
          </Dialog.Content>
        </Dialog.Portal>
      </Dialog.Root>
    </div>
  );
}

function SprintCell({
  assignment,
  previousWeekAssignment,
  projects,
  isCurrent,
  loading,
  isPending,
  onChange,
  onNavigate,
}: {
  assignment?: Assignment;
  previousWeekAssignment?: Assignment;
  projects: Project[];
  isCurrent: boolean;
  loading: boolean;
  isPending?: boolean;
  onChange: (projectId: string | null) => void;
  onNavigate: (projectId: string) => void;
}) {
  // Convert previous week assignment to Project format for the quick select
  const previousWeekProject: Project | null =
    previousWeekAssignment?.projectId && previousWeekAssignment?.projectName
      ? {
          id: previousWeekAssignment.projectId,
          title: previousWeekAssignment.projectName,
          color: previousWeekAssignment.projectColor,
          programId: previousWeekAssignment.programId,
          programName: previousWeekAssignment.programName,
          programEmoji: previousWeekAssignment.emoji,
          programColor: previousWeekAssignment.color,
        }
      : null;

  // isPending is only used for visual styling (dashed border), not for blocking assignment
  return (
    <div
      className={cn(
        'flex h-12 w-[180px] items-center justify-start border-b border-r border-border px-1',
        isCurrent && 'bg-accent/5',
        loading && 'animate-pulse',
        isPending && 'border-dashed'
      )}
    >
      <ProjectCombobox
        projects={projects}
        value={assignment?.projectId || null}
        onChange={onChange}
        onNavigate={onNavigate}
        disabled={loading}
        placeholder="+"
        previousWeekProject={previousWeekProject}
        triggerClassName={cn(
          'w-full h-full justify-start',
          !assignment && 'hover:bg-border/30'
        )}
      />
    </div>
  );
}

function ChevronIcon({ className }: { className?: string }) {
  return (
    <svg className={className} fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
    </svg>
  );
}

function ViewAsIcon({ className }: { className?: string }) {
  return (
    <svg className={className} fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
    </svg>
  );
}

import { useCallback, useMemo, useEffect, Suspense } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { UnifiedEditor } from '@/components/UnifiedEditor';
import type { UnifiedDocument, SidebarData } from '@/components/UnifiedEditor';
import { useAuth } from '@/hooks/useAuth';
import { useAssignableMembersQuery } from '@/hooks/useTeamMembersQuery';
import { useProgramsQuery } from '@/hooks/useProgramsQuery';
import { useProjectsQuery } from '@/hooks/useProjectsQuery';
import { useDocumentConversion } from '@/hooks/useDocumentConversion';
import { apiGet, apiPatch, apiDelete, apiPost } from '@/lib/api';
import { useToast } from '@/components/ui/Toast';
import { issueKeys } from '@/hooks/useIssuesQuery';
import { projectKeys, useProjectWeeksQuery } from '@/hooks/useProjectsQuery';
import { TabBar } from '@/components/ui/TabBar';
import { useCurrentDocument } from '@/contexts/CurrentDocumentContext';
import {
  getTabsForDocument,
  documentTypeHasTabs,
  resolveTabLabels,
  type DocumentResponse,
  type TabCounts,
} from '@/lib/document-tabs';

/**
 * UnifiedDocumentPage - Renders any document type via /documents/:id route
 *
 * This page fetches a document by ID regardless of type and renders it
 * using the UnifiedEditor component with the appropriate sidebar data.
 * Document types with tabs (projects, programs) get a tabbed interface.
 */
export function UnifiedDocumentPage() {
  const { id, '*': wildcardPath } = useParams<{ id: string; '*'?: string }>();
  const navigate = useNavigate();

  // Parse wildcard path into tab and nested path
  // Example: /documents/abc/sprints/xyz -> wildcardPath = "sprints/xyz" -> tab = "sprints", nestedPath = "xyz"
  const pathSegments = wildcardPath ? wildcardPath.split('/').filter(Boolean) : [];
  const urlTab = pathSegments[0] || undefined;
  const nestedPath = pathSegments.length > 1 ? pathSegments.slice(1).join('/') : undefined;
  const queryClient = useQueryClient();
  const { user } = useAuth();
  const { showToast } = useToast();
  const { setCurrentDocument, clearCurrentDocument } = useCurrentDocument();

  // Fetch the document by ID
  const { data: document, isLoading, error } = useQuery<DocumentResponse>({
    queryKey: ['document', id],
    queryFn: async () => {
      const response = await apiGet(`/api/documents/${id}`);
      if (!response.ok) {
        if (response.status === 404) {
          throw new Error('Document not found');
        }
        throw new Error('Failed to fetch document');
      }
      return response.json();
    },
    enabled: !!id,
    retry: false,
  });

  // Sync current document context for rail highlighting
  useEffect(() => {
    if (document && id) {
      const docType = document.document_type as 'wiki' | 'issue' | 'project' | 'program' | 'sprint' | 'person' | 'weekly_plan' | 'weekly_retro' | 'standup';
      // Extract projectId for weekly documents
      const projectId = (document.document_type === 'weekly_plan' || document.document_type === 'weekly_retro')
        ? (document.properties?.project_id as string | undefined) ?? null
        : null;
      setCurrentDocument(id, docType, projectId);
    }
    return () => {
      clearCurrentDocument();
    };
  }, [document, id, setCurrentDocument, clearCurrentDocument]);



  // Set default active tab when document loads (status-aware for sprints)
  const tabConfig = document ? getTabsForDocument(document) : [];
  const hasTabs = document ? documentTypeHasTabs(document.document_type) : false;

  // Derive activeTab from URL - if valid tab in URL, use it; otherwise default to first tab
  const activeTab = useMemo(() => {
    if (urlTab && tabConfig.some(t => t.id === urlTab)) {
      return urlTab;
    }
    return tabConfig[0]?.id || '';
  }, [urlTab, tabConfig]);

  // Redirect to clean URL if tab is invalid (prevents broken bookmarks and typos)
  useEffect(() => {
    if (!document || !id) return;

    // If URL has a tab but it's not valid for this document type, redirect to base URL
    const isValidTab = tabConfig.some(t => t.id === urlTab);
    if (urlTab && !isValidTab) {
      console.warn(`Invalid tab "${urlTab}" for document type "${document.document_type}", redirecting to base URL`);
      navigate(`/documents/${id}`, { replace: true });
    }
  }, [document, id, urlTab, tabConfig, navigate]);

  // Fetch team members for sidebar data
  const { data: teamMembersData = [] } = useAssignableMembersQuery();
  const teamMembers = useMemo(() => teamMembersData.map(m => ({
    id: m.id,
    user_id: m.user_id,
    name: m.name,
    email: m.email || '',
  })), [teamMembersData]);

  // Fetch programs for sidebar data
  const { data: programsData = [] } = useProgramsQuery();
  const programs = useMemo(() => programsData.map(p => ({
    id: p.id,
    name: p.name,
    color: p.color,
    emoji: p.emoji,
  })), [programsData]);

  // Fetch projects for issue sidebar (multi-association)
  const { data: projectsData = [] } = useProjectsQuery();
  const projects = useMemo(() => projectsData.map(p => ({
    id: p.id,
    title: p.title,
    color: p.color,
  })), [projectsData]);

  // Fetch counts for tabs (project weeks, etc.)
  const isProject = document?.document_type === 'project';
  const isProgram = document?.document_type === 'program';
  const { data: projectWeeks = [] } = useProjectWeeksQuery(isProject ? id : undefined);

  // Compute tab counts based on document type
  const tabCounts: TabCounts = useMemo(() => {
    if (isProject) {
      const issueCount = (document as { issue_count?: number })?.issue_count ?? 0;
      return {
        issues: issueCount,
        weeks: projectWeeks.length,
      };
    }
    if (isProgram) {
      // For programs, counts will be loaded by the tab components themselves
      return {};
    }
    return {};
  }, [document, isProject, isProgram, projectWeeks.length]);

  // Handler for when associations change (invalidate document query to refetch)
  const handleAssociationChange = useCallback(() => {
    queryClient.invalidateQueries({ queryKey: ['document', id] });
  }, [queryClient, id]);

  // Document conversion (issue <-> project)
  const { convert, isConverting } = useDocumentConversion({
    navigateAfterConvert: true,
  });

  // Conversion callbacks that use the current document
  const handleConvert = useCallback(() => {
    if (!document || !id) return;
    const sourceType = document.document_type as 'issue' | 'project';
    convert(id, sourceType, document.title);
  }, [convert, document, id]);

  const handleUndoConversion = useCallback(async () => {
    if (!document || !id) return;

    try {
      const res = await apiPost(`/api/documents/${id}/undo-conversion`, {});

      if (res.ok) {
        // Invalidate caches to refresh the UI
        await Promise.all([
          queryClient.invalidateQueries({ queryKey: issueKeys.lists() }),
          queryClient.invalidateQueries({ queryKey: projectKeys.lists() }),
          queryClient.invalidateQueries({ queryKey: ['document', id] }),
        ]);
        showToast('Conversion undone successfully', 'success');
      } else {
        const error = await res.json();
        showToast(error.error || 'Failed to undo conversion', 'error');
      }
    } catch (err) {
      showToast('Failed to undo conversion', 'error');
    }
  }, [document, id, queryClient, showToast]);

  // Handle document type change via DocumentTypeSelector
  const handleTypeChange = useCallback(async (newType: string) => {
    if (!document || !id) return;

    const currentType = document.document_type;

    // Only issue <-> project conversions are supported
    const isValidConversion =
      (currentType === 'issue' && newType === 'project') ||
      (currentType === 'project' && newType === 'issue');

    if (!isValidConversion) {
      showToast(`Converting ${currentType} to ${newType} is not supported`, 'error');
      return;
    }

    try {
      const res = await apiPost(`/api/documents/${id}/convert`, { target_type: newType });

      if (res.ok) {
        const data = await res.json();

        // Invalidate caches
        await Promise.all([
          queryClient.invalidateQueries({ queryKey: issueKeys.lists() }),
          queryClient.invalidateQueries({ queryKey: projectKeys.lists() }),
          queryClient.invalidateQueries({ queryKey: ['document', id] }),
        ]);

        // Navigate to the new document
        navigate(`/documents/${data.id}`, { replace: true });
      } else {
        const error = await res.json();
        showToast(error.error || 'Failed to convert document', 'error');
      }
    } catch (err) {
      showToast('Failed to convert document', 'error');
    }
  }, [document, id, navigate, queryClient, showToast]);

  // Handle WebSocket notification that document was converted
  const handleDocumentConverted = useCallback((newDocId: string) => {
    navigate(`/documents/${newDocId}`, { replace: true });
  }, [navigate]);

  // Update mutation with optimistic updates
  const updateMutation = useMutation({
    mutationFn: async ({ documentId, updates }: { documentId: string; updates: Partial<DocumentResponse> }) => {
      const response = await apiPatch(`/api/documents/${documentId}`, updates);
      if (!response.ok) {
        throw new Error('Failed to update document');
      }
      return response.json();
    },
    onMutate: async ({ documentId, updates }) => {
      // Cancel any outgoing refetches
      await queryClient.cancelQueries({ queryKey: ['document', documentId] });

      // Snapshot the previous value
      const previousDocument = queryClient.getQueryData<Record<string, unknown>>(['document', documentId]);

      // Optimistically update the document cache
      if (previousDocument) {
        queryClient.setQueryData(['document', documentId], { ...previousDocument, ...updates });
      }

      // Return context with the previous value for rollback
      return { previousDocument, documentId };
    },
    onError: (_err, _variables, context) => {
      // Rollback to the previous value on error
      if (context?.previousDocument && context?.documentId) {
        queryClient.setQueryData(['document', context.documentId], context.previousDocument);
      }
    },
    onSuccess: (_, { documentId }) => {
      queryClient.invalidateQueries({ queryKey: ['document', documentId] });
      // Also invalidate type-specific queries for list views
      if (document?.document_type) {
        queryClient.invalidateQueries({ queryKey: [document.document_type + 's', 'list'] });
        if (document.document_type === 'wiki') {
          queryClient.invalidateQueries({ queryKey: ['documents', 'wiki'] });
        }
      }
    },
  });

  // Delete mutation
  const deleteMutation = useMutation({
    mutationFn: async (documentId: string) => {
      const response = await apiDelete(`/api/documents/${documentId}`);
      if (!response.ok) {
        throw new Error('Failed to delete document');
      }
    },
    onSuccess: () => {
      navigate('/docs');
    },
  });

  // Handle update
  const handleUpdate = useCallback(async (updates: Partial<UnifiedDocument>) => {
    if (!id) return;
    await updateMutation.mutateAsync({ documentId: id, updates: updates as Partial<DocumentResponse> });
  }, [updateMutation, id]);

  // Handle delete
  const handleDelete = useCallback(async () => {
    if (!id) return;
    if (!window.confirm('Are you sure you want to delete this document?')) return;
    await deleteMutation.mutateAsync(id);
  }, [deleteMutation, id]);

  const isWeeklyDoc = document?.document_type === 'weekly_plan' || document?.document_type === 'weekly_retro';
  const isStandup = document?.document_type === 'standup';
  const hideBackButton = isWeeklyDoc || isStandup;

  // Resolve standup author name for title suffix
  const standupAuthorName = useMemo(() => {
    if (!isStandup) return undefined;
    const authorId = document?.properties?.author_id as string | undefined;
    if (!authorId) return undefined;
    return teamMembersData.find(m => m.user_id === authorId)?.name;
  }, [isStandup, document?.properties?.author_id, teamMembersData]);

  // Handle back navigation
  const handleBack = useCallback(() => {
    // Navigate to type-specific list or docs
    if (document?.document_type === 'issue') {
      navigate('/issues');
    } else if (document?.document_type === 'project') {
      navigate('/projects');
    } else if (document?.document_type === 'sprint') {
      navigate('/sprints');
    } else if (document?.document_type === 'program') {
      navigate('/programs');
    } else {
      navigate('/docs');
    }
  }, [document, navigate]);

  // Compute back label based on document type (just the noun - Editor adds "Back to")
  // Weekly plans/retros don't show a back button
  const backLabel = useMemo(() => {
    switch (document?.document_type) {
      case 'issue': return 'issues';
      case 'project': return 'projects';
      case 'sprint': return 'weeks';
      case 'program': return 'programs';
      default: return 'docs';
    }
  }, [document?.document_type]);

  // Build sidebar data based on document type
  const sidebarData: SidebarData = useMemo(() => {
    if (!document) return {};

    switch (document.document_type) {
      case 'wiki':
        return {
          teamMembers,
        };
      case 'issue':
        return {
          teamMembers,
          programs,
          projects,
          onAssociationChange: handleAssociationChange,
          onConvert: handleConvert,
          onUndoConversion: handleUndoConversion,
          isConverting,
          isUndoing: isConverting,
        };
      case 'project':
        return {
          programs,
          people: teamMembers,
          onConvert: handleConvert,
          onUndoConversion: handleUndoConversion,
          isConverting,
          isUndoing: isConverting,
        };
      case 'sprint':
        return {};
      default:
        return {};
    }
  }, [document, teamMembers, programs, projects, handleAssociationChange, handleConvert, handleUndoConversion, isConverting]);

  // Transform API response to UnifiedDocument format
  const unifiedDocument: UnifiedDocument | null = useMemo(() => {
    if (!document) return null;

    // Extract program_id from belongs_to array (via document_associations)
    const belongsTo = document.belongs_to as Array<{ id: string; type: string }> | undefined;
    const programIdFromBelongsTo = belongsTo?.find(b => b.type === 'program')?.id;
    const sprintIdFromBelongsTo = belongsTo?.find(b => b.type === 'sprint')?.id;

    return {
      id: document.id,
      title: document.title,
      document_type: document.document_type as UnifiedDocument['document_type'],
      created_at: document.created_at,
      updated_at: document.updated_at,
      created_by: document.created_by as string | undefined,
      properties: document.properties,
      // Spread flattened properties based on type
      ...(document.document_type === 'issue' && {
        state: (document.state as string) || 'backlog',
        priority: (document.priority as string) || 'medium',
        estimate: document.estimate as number | undefined,
        assignee_id: document.assignee_id as string | undefined,
        assignee_name: document.assignee_name as string | undefined,
        program_id: programIdFromBelongsTo,
        sprint_id: sprintIdFromBelongsTo,
        source: document.source as 'internal' | 'external' | undefined,
        converted_from_id: document.converted_from_id as string | undefined,
        display_id: (document.ticket_number as number) ? `#${document.ticket_number}` : undefined,
        belongs_to: document.belongs_to as Array<{
          id: string;
          type: 'program' | 'project' | 'sprint' | 'parent';
          title?: string;
          color?: string;
        }> | undefined,
      }),
      ...(document.document_type === 'project' && {
        impact: (document.impact as number | null) ?? null,
        confidence: (document.confidence as number | null) ?? null,
        ease: (document.ease as number | null) ?? null,
        color: (document.color as string) || '#3b82f6',
        emoji: null,
        program_id: programIdFromBelongsTo,
        owner: document.owner as { id: string; name: string; email: string } | null,
        owner_id: document.owner_id as string | undefined,
        // RACI fields
        accountable_id: document.accountable_id as string | undefined,
        consulted_ids: document.consulted_ids as string[] | undefined,
        informed_ids: document.informed_ids as string[] | undefined,
        converted_from_id: document.converted_from_id as string | undefined,
      }),
      ...(document.document_type === 'sprint' && {
        start_date: (document.start_date as string) || '',
        end_date: (document.end_date as string) || '',
        status: ((document.status as string) || 'planning') as 'planning' | 'active' | 'completed',
        program_id: programIdFromBelongsTo,
        plan: (document.plan as string) || '',
      }),
      ...(document.document_type === 'wiki' && {
        parent_id: document.parent_id as string | undefined,
        visibility: document.visibility as 'private' | 'workspace' | undefined,
      }),
    } as UnifiedDocument;
  }, [document]);

  // Loading state
  if (isLoading) {
    return (
      <div className="flex h-full items-center justify-center">
        <div className="text-muted">Loading...</div>
      </div>
    );
  }

  // Error state
  if (error || !document) {
    return (
      <div className="flex h-full flex-col items-center justify-center gap-4">
        <div className="text-muted">
          {error?.message || 'Document not found'}
        </div>
        <button
          onClick={() => navigate('/docs')}
          className="text-sm text-accent hover:underline"
        >
          Go to Documents
        </button>
      </div>
    );
  }

  if (!user || !unifiedDocument) {
    return null;
  }

  // Documents with tabs get a tabbed interface
  if (hasTabs && tabConfig.length > 0) {
    const tabs = resolveTabLabels(tabConfig, document, tabCounts);
    const currentTabConfig = tabConfig.find(t => t.id === activeTab) || tabConfig[0];
    const TabComponent = currentTabConfig?.component;

    return (
      <div className="flex h-full flex-col">
        {/* Tab bar */}
        <div className="border-b border-border px-4">
          <TabBar
            tabs={tabs}
            activeTab={activeTab || tabs[0]?.id}
            onTabChange={(tab) => {
              // Navigate to new URL - first tab gets clean URL, others get tab suffix
              if (tab === tabConfig[0]?.id) {
                navigate(`/documents/${id}`);
              } else {
                navigate(`/documents/${id}/${tab}`);
              }
            }}
          />
        </div>

        {/* Content area with lazy-loaded tab component */}
        <div className="flex-1 overflow-hidden">
          <Suspense
            fallback={
              <div className="flex h-full items-center justify-center">
                <div className="text-muted">Loading...</div>
              </div>
            }
          >
            {TabComponent && (
              <TabComponent documentId={id!} document={document} nestedPath={nestedPath} />
            )}
          </Suspense>
        </div>
      </div>
    );
  }

  // Non-tabbed documents render directly in editor
  return (
    <UnifiedEditor
      document={unifiedDocument}
      sidebarData={sidebarData}
      onUpdate={handleUpdate}
      onTypeChange={handleTypeChange}
      onDocumentConverted={handleDocumentConverted}
      onBack={hideBackButton ? undefined : handleBack}
      backLabel={hideBackButton ? undefined : backLabel}
      onDelete={handleDelete}
      showTypeSelector={true}
      titleSuffix={standupAuthorName}
    />
  );
}

import { useState, useEffect, useCallback } from 'react';
import { useSearchParams, Link } from 'react-router-dom';
import { useQueryClient } from '@tanstack/react-query';
import { useWorkspace } from '@/contexts/WorkspaceContext';
import { useAuth } from '@/hooks/useAuth';
import { api, WorkspaceMember, WorkspaceInvite, AuditLog, ApiToken, ApiTokenCreateResponse } from '@/lib/api';
import { archivedPersonsKey } from '@/contexts/ArchivedPersonsContext';
import { cn } from '@/lib/cn';

type Tab = 'members' | 'invites' | 'tokens' | 'audit';

const VALID_TABS: Tab[] = ['members', 'invites', 'tokens', 'audit'];

export function WorkspaceSettingsPage() {
  const { currentWorkspace, isWorkspaceAdmin } = useWorkspace();
  const { user } = useAuth();
  const queryClient = useQueryClient();
  const [searchParams, setSearchParams] = useSearchParams();

  // Derive active tab from URL query params
  const tabParam = searchParams.get('tab') as Tab | null;
  const activeTab: Tab = tabParam && VALID_TABS.includes(tabParam) ? tabParam : 'members';

  const handleTabChange = useCallback((tab: Tab) => {
    setSearchParams({ tab }, { replace: true });
  }, [setSearchParams]);
  const [members, setMembers] = useState<WorkspaceMember[]>([]);
  const [invites, setInvites] = useState<WorkspaceInvite[]>([]);
  const [apiTokens, setApiTokens] = useState<ApiToken[]>([]);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);
  const [loading, setLoading] = useState(true);
  const [inviteEmail, setInviteEmail] = useState('');
  const [inviteSubjectDn, setInviteSubjectDn] = useState('');
  const [showPivField, setShowPivField] = useState(false);
  const [inviteRole, setInviteRole] = useState<'admin' | 'member'>('member');
  const [inviting, setInviting] = useState(false);
  const [showArchived, setShowArchived] = useState(false);

  useEffect(() => {
    if (!currentWorkspace) return;
    loadData(showArchived);
  }, [currentWorkspace, showArchived]);

  async function loadData(includeArchived = false) {
    if (!currentWorkspace) return;
    setLoading(true);

    const [membersRes, invitesRes, tokensRes, logsRes] = await Promise.all([
      api.workspaces.getMembers(currentWorkspace.id, { includeArchived }),
      api.workspaces.getInvites(currentWorkspace.id),
      api.apiTokens.list(),
      api.workspaces.getAuditLogs(currentWorkspace.id, { limit: 50 }),
    ]);

    if (membersRes.success && membersRes.data) setMembers(membersRes.data.members);
    if (invitesRes.success && invitesRes.data) setInvites(invitesRes.data.invites);
    if (tokensRes.success && tokensRes.data) setApiTokens(tokensRes.data);
    if (logsRes.success && logsRes.data) setAuditLogs(logsRes.data.logs);
    setLoading(false);
  }

  async function handleInvite(e: React.FormEvent) {
    e.preventDefault();
    if (!currentWorkspace || !inviteEmail.trim()) return;

    setInviting(true);
    const res = await api.workspaces.createInvite(currentWorkspace.id, {
      email: inviteEmail.trim(),
      x509SubjectDn: inviteSubjectDn.trim() || undefined,
      role: inviteRole,
    });
    if (res.success && res.data) {
      const { invite } = res.data;
      setInvites(prev => [...prev, invite]);
      setInviteEmail('');
      setInviteSubjectDn('');
      setShowPivField(false);
    }
    setInviting(false);
  }

  async function handleRevokeInvite(inviteId: string) {
    if (!currentWorkspace) return;
    const res = await api.workspaces.revokeInvite(currentWorkspace.id, inviteId);
    if (res.success) {
      setInvites(prev => prev.filter(i => i.id !== inviteId));
    }
  }

  async function handleUpdateRole(userId: string, newRole: 'admin' | 'member') {
    if (!currentWorkspace) return;

    // Check if this is the last admin
    const admins = members.filter(m => m.role === 'admin');
    if (admins.length === 1 && admins[0].userId === userId && newRole === 'member') {
      alert('Cannot demote the last admin. Promote another member first.');
      return;
    }

    const res = await api.workspaces.updateMember(currentWorkspace.id, userId, { role: newRole });
    if (res.success) {
      setMembers(prev => prev.map(m => m.userId === userId ? { ...m, role: newRole } : m));
    }
  }

  async function handleArchiveMember(userId: string) {
    if (!currentWorkspace) return;

    // Check if this is the last admin
    const admins = members.filter(m => m.role === 'admin');
    const member = members.find(m => m.userId === userId);
    if (member?.role === 'admin' && admins.length === 1) {
      alert('Cannot archive the last admin. Promote another member first.');
      return;
    }

    if (!confirm(`Archive ${member?.name || 'this member'}? They will lose access immediately.`)) return;

    const res = await api.workspaces.removeMember(currentWorkspace.id, userId);
    if (res.success) {
      setMembers(prev => prev.filter(m => m.userId !== userId));
      // Invalidate archived persons cache so mentions update
      queryClient.invalidateQueries({ queryKey: archivedPersonsKey });
    }
  }

  async function handleRestoreMember(userId: string) {
    if (!currentWorkspace) return;

    const res = await api.workspaces.restoreMember(currentWorkspace.id, userId);
    if (res.success) {
      // Refresh the members list to get updated data
      loadData(showArchived);
      // Invalidate archived persons cache so mentions update
      queryClient.invalidateQueries({ queryKey: archivedPersonsKey });
    }
  }

  if (!currentWorkspace) {
    return (
      <div className="flex h-full items-center justify-center">
        <div className="text-muted">No workspace selected</div>
      </div>
    );
  }

  if (!isWorkspaceAdmin) {
    return (
      <div className="flex h-full flex-col items-center justify-center gap-4">
        <h1 className="text-xl font-medium text-foreground">Workspace Settings</h1>
        <p className="text-muted">You don't have permission to manage this workspace.</p>
      </div>
    );
  }

  return (
    <div className="flex h-full flex-col">
      {/* Header */}
      <header className="flex h-14 items-center justify-between border-b border-border px-6">
        <h1 className="text-lg font-semibold text-foreground">
          Workspace Settings: {currentWorkspace.name}
        </h1>
      </header>

      {/* Tabs */}
      <div className="border-b border-border">
        <nav className="flex px-6">
          <TabButton active={activeTab === 'members'} onClick={() => handleTabChange('members')}>
            Members
          </TabButton>
          <TabButton active={activeTab === 'invites'} onClick={() => handleTabChange('invites')}>
            Pending Invites
          </TabButton>
          <TabButton active={activeTab === 'tokens'} onClick={() => handleTabChange('tokens')}>
            API Tokens
          </TabButton>
          <TabButton active={activeTab === 'audit'} onClick={() => handleTabChange('audit')}>
            Audit Logs
          </TabButton>
          <Link
            to="/settings/conversions"
            className={cn(
              'px-4 py-3 text-sm font-medium border-b-2 border-transparent',
              'text-muted hover:text-foreground hover:border-border/50 transition-colors'
            )}
          >
            Conversions
          </Link>
        </nav>
      </div>

      {/* Content */}
      <main className="flex-1 overflow-auto p-6 pb-20">
        {loading ? (
          <div className="flex items-center justify-center h-32">
            <div className="text-muted">Loading...</div>
          </div>
        ) : (
          <>
            {activeTab === 'members' && (
              <MembersTab
                members={members}
                currentUserId={user?.id}
                showArchived={showArchived}
                onShowArchivedChange={setShowArchived}
                onUpdateRole={handleUpdateRole}
                onArchiveMember={handleArchiveMember}
                onRestoreMember={handleRestoreMember}
              />
            )}
            {activeTab === 'invites' && (
              <InvitesTab
                invites={invites}
                inviteEmail={inviteEmail}
                setInviteEmail={setInviteEmail}
                inviteSubjectDn={inviteSubjectDn}
                setInviteSubjectDn={setInviteSubjectDn}
                showPivField={showPivField}
                setShowPivField={setShowPivField}
                inviteRole={inviteRole}
                setInviteRole={setInviteRole}
                inviting={inviting}
                onInvite={handleInvite}
                onRevoke={handleRevokeInvite}
              />
            )}
            {activeTab === 'tokens' && (
              <ApiTokensTab
                tokens={apiTokens}
                onTokenCreated={(token) => setApiTokens(prev => [token, ...prev])}
                onTokenRevoked={(tokenId) => setApiTokens(prev => prev.filter(t => t.id !== tokenId))}
              />
            )}
            {activeTab === 'audit' && (
              <AuditTab auditLogs={auditLogs} />
            )}
          </>
        )}
      </main>
    </div>
  );
}

function TabButton({ active, onClick, children }: { active: boolean; onClick: () => void; children: React.ReactNode }) {
  return (
    <button
      onClick={onClick}
      className={cn(
        'px-4 py-3 text-sm font-medium border-b-2 transition-colors',
        active
          ? 'border-accent text-foreground'
          : 'border-transparent text-muted hover:text-foreground'
      )}
    >
      {children}
    </button>
  );
}

function MembersTab({
  members,
  currentUserId,
  showArchived,
  onShowArchivedChange,
  onUpdateRole,
  onArchiveMember,
  onRestoreMember,
}: {
  members: WorkspaceMember[];
  currentUserId?: string;
  showArchived: boolean;
  onShowArchivedChange: (show: boolean) => void;
  onUpdateRole: (userId: string, role: 'admin' | 'member') => void;
  onArchiveMember: (userId: string) => void;
  onRestoreMember: (userId: string) => void;
}) {
  const activeMembers = members.filter(m => !m.isArchived);
  const adminCount = activeMembers.filter(m => m.role === 'admin').length;

  return (
    <div className="space-y-4">
      {/* Show archived toggle */}
      <div className="flex justify-end">
        <label className="flex items-center gap-1.5 cursor-pointer">
          <input
            type="checkbox"
            checked={showArchived}
            onChange={(e) => onShowArchivedChange(e.target.checked)}
            className="h-3.5 w-3.5 rounded border-border text-accent focus:ring-accent/50"
          />
          <span className="text-xs text-muted">Show archived</span>
        </label>
      </div>

      <div className="border border-border rounded-lg overflow-hidden">
        <table className="w-full">
          <thead className="bg-border/30">
            <tr>
              <th className="px-4 py-3 text-left text-sm font-medium text-muted">Name</th>
              <th className="px-4 py-3 text-left text-sm font-medium text-muted">Email</th>
              <th className="px-4 py-3 text-left text-sm font-medium text-muted">Role</th>
              <th className="px-4 py-3 text-left text-sm font-medium text-muted">Joined</th>
              <th className="px-4 py-3 text-right text-sm font-medium text-muted">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-border">
            {members.map((member) => {
              const isArchived = member.isArchived;
              const isLastAdmin = member.role === 'admin' && adminCount === 1;
              const isSelf = member.userId === currentUserId;

              return (
                <tr key={member.id} className={cn(isArchived && "opacity-50")}>
                  <td className={cn("px-4 py-3 text-sm font-medium", isArchived ? "text-muted" : "text-foreground")}>
                    {member.name}
                    {isArchived && <span className="ml-1 text-xs font-normal">(archived)</span>}
                    {isSelf && !isArchived && <span className="ml-2 text-muted">(you)</span>}
                  </td>
                  <td className="px-4 py-3 text-sm text-muted">{member.email}</td>
                  <td className="px-4 py-3 text-sm">
                    {isArchived ? (
                      <span className="text-muted">-</span>
                    ) : (
                      <select
                        value={member.role || 'member'}
                        onChange={(e) => onUpdateRole(member.userId, e.target.value as 'admin' | 'member')}
                        disabled={isLastAdmin}
                        className={cn(
                          'px-2 py-1 rounded text-sm bg-background border border-border',
                          isLastAdmin && 'opacity-50 cursor-not-allowed'
                        )}
                        title={isLastAdmin ? 'Workspace must have at least one admin' : undefined}
                      >
                        <option value="admin">Admin</option>
                        <option value="member">Member</option>
                      </select>
                    )}
                  </td>
                  <td className="px-4 py-3 text-sm text-muted">
                    {member.joinedAt ? new Date(member.joinedAt).toLocaleDateString() : '-'}
                  </td>
                  <td className="px-4 py-3 text-right">
                    {isArchived ? (
                      <button
                        onClick={() => onRestoreMember(member.userId)}
                        className="text-sm text-accent hover:text-accent/80 transition-colors"
                      >
                        Restore
                      </button>
                    ) : (
                      !isSelf && !isLastAdmin && (
                        <button
                          onClick={() => onArchiveMember(member.userId)}
                          className="text-sm text-red-500 hover:text-red-400 transition-colors"
                        >
                          Archive
                        </button>
                      )
                    )}
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function InvitesTab({
  invites,
  inviteEmail,
  setInviteEmail,
  inviteSubjectDn,
  setInviteSubjectDn,
  showPivField,
  setShowPivField,
  inviteRole,
  setInviteRole,
  inviting,
  onInvite,
  onRevoke,
}: {
  invites: WorkspaceInvite[];
  inviteEmail: string;
  setInviteEmail: (v: string) => void;
  inviteSubjectDn: string;
  setInviteSubjectDn: (v: string) => void;
  showPivField: boolean;
  setShowPivField: (v: boolean) => void;
  inviteRole: 'admin' | 'member';
  setInviteRole: (v: 'admin' | 'member') => void;
  inviting: boolean;
  onInvite: (e: React.FormEvent) => void;
  onRevoke: (id: string) => void;
}) {
  const [copiedId, setCopiedId] = useState<string | null>(null);

  function handleCopyLink(invite: WorkspaceInvite) {
    const url = `${window.location.origin}/invite/${invite.token}`;
    navigator.clipboard.writeText(url);
    setCopiedId(invite.id);
    setTimeout(() => setCopiedId(null), 2000);
  }

  return (
    <div className="space-y-6">
      {/* Invite form */}
      <form onSubmit={onInvite} className="space-y-3">
        <div className="flex gap-3">
          <input
            type="email"
            value={inviteEmail}
            onChange={(e) => setInviteEmail(e.target.value)}
            placeholder="Email address"
            className="flex-1 max-w-md px-3 py-2 bg-background border border-border rounded-md text-foreground placeholder:text-muted focus:outline-none focus:ring-2 focus:ring-accent"
            required
          />
          <select
            value={inviteRole}
            onChange={(e) => setInviteRole(e.target.value as 'admin' | 'member')}
            className="px-3 py-2 bg-background border border-border rounded-md text-foreground"
          >
            <option value="member">Member</option>
            <option value="admin">Admin</option>
          </select>
          <button
            type="submit"
            disabled={inviting || !inviteEmail.trim()}
            className="px-4 py-2 bg-accent text-white rounded-md hover:bg-accent/90 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            {inviting ? 'Inviting...' : 'Send Invite'}
          </button>
        </div>

        {/* PIV Subject DN field (collapsible) */}
        <div>
          <button
            type="button"
            onClick={() => setShowPivField(!showPivField)}
            className="text-xs text-muted hover:text-foreground transition-colors"
          >
            {showPivField ? '- Hide PIV options' : '+ Add PIV certificate identity'}
          </button>
          {showPivField && (
            <div className="mt-2">
              <input
                type="text"
                value={inviteSubjectDn}
                onChange={(e) => setInviteSubjectDn(e.target.value)}
                placeholder="X.509 Subject DN (e.g., CN=LASTNAME.FIRSTNAME.MIDDLE.1234567890)"
                className="w-full max-w-lg px-3 py-2 bg-background border border-border rounded-md text-foreground placeholder:text-muted focus:outline-none focus:ring-2 focus:ring-accent font-mono text-sm"
              />
              <p className="mt-1 text-xs text-muted">
                Optional: For PIV users whose certificate may not contain an email address.
                The certificate Subject DN will be matched during PIV login.
              </p>
            </div>
          )}
        </div>
      </form>

      {/* Pending invites */}
      {invites.length === 0 ? (
        <div className="text-muted text-sm">No pending invites</div>
      ) : (
        <div className="border border-border rounded-lg overflow-hidden">
          <table className="w-full">
            <thead className="bg-border/30">
              <tr>
                <th className="px-4 py-3 text-left text-sm font-medium text-muted">Email</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-muted">PIV Identity</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-muted">Role</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-muted">Expires</th>
                <th className="px-4 py-3 text-right text-sm font-medium text-muted">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-border">
              {invites.map((invite) => (
                <tr key={invite.id}>
                  <td className="px-4 py-3 text-sm text-foreground">{invite.email}</td>
                  <td className="px-4 py-3 text-sm text-muted">
                    {invite.x509SubjectDn ? (
                      <span className="font-mono text-xs">{invite.x509SubjectDn}</span>
                    ) : (
                      <span className="text-muted/50">-</span>
                    )}
                  </td>
                  <td className="px-4 py-3 text-sm text-muted capitalize">{invite.role}</td>
                  <td className="px-4 py-3 text-sm text-muted">
                    {new Date(invite.expiresAt).toLocaleDateString()}
                  </td>
                  <td className="px-4 py-3 text-right space-x-3">
                    <button
                      onClick={() => handleCopyLink(invite)}
                      className={cn(
                        "text-sm transition-colors",
                        copiedId === invite.id
                          ? "text-green-500"
                          : "text-accent hover:text-accent/80"
                      )}
                    >
                      {copiedId === invite.id ? 'Copied!' : 'Copy Link'}
                    </button>
                    <button
                      onClick={() => onRevoke(invite.id)}
                      className="text-sm text-red-500 hover:text-red-400 transition-colors"
                    >
                      Revoke
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

function ApiTokensTab({
  tokens,
  onTokenCreated,
  onTokenRevoked,
}: {
  tokens: ApiToken[];
  onTokenCreated: (token: ApiToken) => void;
  onTokenRevoked: (tokenId: string) => void;
}) {
  const [tokenName, setTokenName] = useState('');
  const [expiresInDays, setExpiresInDays] = useState<string>('90');
  const [creating, setCreating] = useState(false);
  const [newToken, setNewToken] = useState<ApiTokenCreateResponse | null>(null);
  const [copied, setCopied] = useState(false);

  async function handleCreate(e: React.FormEvent) {
    e.preventDefault();
    if (!tokenName.trim()) return;

    setCreating(true);
    const res = await api.apiTokens.create({
      name: tokenName.trim(),
      expires_in_days: expiresInDays ? parseInt(expiresInDays, 10) : undefined,
    });
    if (res.success && res.data) {
      setNewToken(res.data);
      onTokenCreated(res.data);
      setTokenName('');
    }
    setCreating(false);
  }

  async function handleRevoke(tokenId: string) {
    if (!confirm('Are you sure you want to revoke this token? This cannot be undone.')) return;

    const res = await api.apiTokens.revoke(tokenId);
    if (res.success) {
      onTokenRevoked(tokenId);
    }
  }

  function handleCopy() {
    if (!newToken) return;
    navigator.clipboard.writeText(newToken.token);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  }

  function handleDismissToken() {
    setNewToken(null);
    setCopied(false);
  }

  return (
    <div className="space-y-6">
      {/* Create token form */}
      <div className="space-y-4">
        <div>
          <h3 className="text-sm font-medium text-foreground mb-1">Generate API Token</h3>
          <p className="text-xs text-muted">
            API tokens allow external tools like Claude Code to access Ship on your behalf.
          </p>
        </div>

        <form onSubmit={handleCreate} className="flex gap-3 items-end">
          <div className="flex-1 max-w-xs">
            <label className="block text-xs text-muted mb-1">Token Name</label>
            <input
              type="text"
              value={tokenName}
              onChange={(e) => setTokenName(e.target.value)}
              placeholder="e.g., Claude Code"
              className="w-full px-3 py-2 bg-background border border-border rounded-md text-foreground placeholder:text-muted focus:outline-none focus:ring-2 focus:ring-accent"
              required
            />
          </div>
          <div className="w-32">
            <label className="block text-xs text-muted mb-1">Expires</label>
            <select
              value={expiresInDays}
              onChange={(e) => setExpiresInDays(e.target.value)}
              className="w-full px-3 py-2 bg-background border border-border rounded-md text-foreground"
            >
              <option value="30">30 days</option>
              <option value="90">90 days</option>
              <option value="365">1 year</option>
              <option value="">Never</option>
            </select>
          </div>
          <button
            type="submit"
            disabled={creating || !tokenName.trim()}
            className="px-4 py-2 bg-accent text-white rounded-md hover:bg-accent/90 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            {creating ? 'Creating...' : 'Generate Token'}
          </button>
        </form>
      </div>

      {/* New token display (shown only once after creation) */}
      {newToken && (
        <div className="p-4 bg-yellow-500/10 border border-yellow-500/30 rounded-lg space-y-3">
          <div className="flex items-start gap-2">
            <span className="text-yellow-500 text-lg">!</span>
            <div>
              <p className="text-sm font-medium text-foreground">Copy your new API token</p>
              <p className="text-xs text-muted mt-1">
                This is the only time this token will be shown. Save it somewhere secure.
              </p>
            </div>
          </div>
          <div className="flex gap-2">
            <code className="flex-1 px-3 py-2 bg-background border border-border rounded-md text-sm font-mono text-foreground overflow-x-auto">
              {newToken.token}
            </code>
            <button
              onClick={handleCopy}
              className={cn(
                "px-3 py-2 rounded-md text-sm transition-colors",
                copied
                  ? "bg-green-500/20 text-green-500"
                  : "bg-border/50 text-foreground hover:bg-border"
              )}
            >
              {copied ? 'Copied!' : 'Copy'}
            </button>
          </div>
          <button
            onClick={handleDismissToken}
            className="text-xs text-muted hover:text-foreground transition-colors"
          >
            I've saved the token, dismiss this
          </button>
        </div>
      )}

      {/* Token list */}
      {tokens.length === 0 ? (
        <div className="text-muted text-sm">No API tokens yet</div>
      ) : (
        <div className="border border-border rounded-lg overflow-hidden">
          <table className="w-full">
            <thead className="bg-border/30">
              <tr>
                <th className="px-4 py-3 text-left text-sm font-medium text-muted">Name</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-muted">Prefix</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-muted">Status</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-muted">Last Used</th>
                <th className="px-4 py-3 text-left text-sm font-medium text-muted">Expires</th>
                <th className="px-4 py-3 text-right text-sm font-medium text-muted">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-border">
              {tokens.map((token) => (
                <tr key={token.id} className={token.is_active ? '' : 'opacity-50'}>
                  <td className="px-4 py-3 text-sm text-foreground font-medium">{token.name}</td>
                  <td className="px-4 py-3 text-sm text-muted font-mono">{token.token_prefix}...</td>
                  <td className="px-4 py-3 text-sm">
                    {token.is_active ? (
                      <span className="text-green-500">Active</span>
                    ) : token.revoked_at ? (
                      <span className="text-red-500">Revoked</span>
                    ) : (
                      <span className="text-yellow-500">Expired</span>
                    )}
                  </td>
                  <td className="px-4 py-3 text-sm text-muted">
                    {token.last_used_at
                      ? new Date(token.last_used_at).toLocaleDateString()
                      : 'Never'}
                  </td>
                  <td className="px-4 py-3 text-sm text-muted">
                    {token.expires_at
                      ? new Date(token.expires_at).toLocaleDateString()
                      : 'Never'}
                  </td>
                  <td className="px-4 py-3 text-right">
                    {token.is_active && (
                      <button
                        onClick={() => handleRevoke(token.id)}
                        className="text-sm text-red-500 hover:text-red-400 transition-colors"
                      >
                        Revoke
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

function AuditTab({ auditLogs }: { auditLogs: AuditLog[] }) {
  return (
    <div className="border border-border rounded-lg overflow-hidden">
      <table className="w-full">
        <thead className="bg-border/30">
          <tr>
            <th className="px-4 py-3 text-left text-sm font-medium text-muted">Time</th>
            <th className="px-4 py-3 text-left text-sm font-medium text-muted">Actor</th>
            <th className="px-4 py-3 text-left text-sm font-medium text-muted">Action</th>
            <th className="px-4 py-3 text-left text-sm font-medium text-muted">Resource</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-border">
          {auditLogs.map((log) => (
            <tr key={log.id}>
              <td className="px-4 py-3 text-sm text-muted whitespace-nowrap">
                {new Date(log.createdAt).toLocaleString()}
              </td>
              <td className="px-4 py-3 text-sm text-foreground">
                {log.actorName || log.actorEmail}
              </td>
              <td className="px-4 py-3 text-sm text-muted">{log.action}</td>
              <td className="px-4 py-3 text-sm text-muted">
                {log.resourceType ? `${log.resourceType}:${log.resourceId?.slice(0, 8)}...` : '-'}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

/**
 * File upload service for images and attachments.
 * Handles upload flow: get presigned URL -> upload to storage -> confirm -> return CDN URL
 */

// In development, Vite proxy handles /api routes (see vite.config.ts)
// In production, use VITE_API_URL or relative URLs
const API_BASE = import.meta.env.VITE_API_URL ?? '';

// File size limits
export const MAX_FILE_SIZE = 1073741824; // 1GB in bytes
export const MAX_FILE_SIZE_DISPLAY = '1GB';

interface UploadResult {
  fileId: string;
  cdnUrl: string;
}

interface UploadProgress {
  fileId: string;
  progress: number; // 0-100
  status: 'pending' | 'uploading' | 'confirming' | 'complete' | 'error';
  error?: string;
}

type ProgressCallback = (progress: UploadProgress) => void;

/**
 * Get CSRF token for API requests
 */
async function getCsrfToken(): Promise<string> {
  const res = await fetch(`${API_BASE}/api/csrf-token`, { credentials: 'include' });
  if (!res.ok) throw new Error('Failed to get CSRF token');
  const { token } = await res.json();
  return token;
}

/**
 * Upload a file to the server
 * @param file - The file to upload
 * @param onProgress - Optional callback for progress updates
 * @param signal - Optional AbortSignal for cancelling the upload
 * @returns The CDN URL of the uploaded file
 */
export async function uploadFile(
  file: File,
  onProgress?: ProgressCallback,
  signal?: AbortSignal
): Promise<UploadResult> {
  // Check if already aborted
  if (signal?.aborted) {
    throw new DOMException('Upload cancelled', 'AbortError');
  }

  const csrfToken = await getCsrfToken();

  const progress: UploadProgress = {
    fileId: '',
    progress: 0,
    status: 'pending',
  };

  const updateProgress = (updates: Partial<UploadProgress>) => {
    Object.assign(progress, updates);
    onProgress?.({ ...progress });
  };

  try {
    // Step 1: Request upload URL
    updateProgress({ status: 'pending', progress: 10 });

    // Use effective MIME type (fallback to extension-based detection if browser returns empty)
    const effectiveMimeType = file.type || getMimeTypeFromExtension(file.name) || 'application/octet-stream';

    const uploadReqRes = await fetch(`${API_BASE}/api/files/upload`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-csrf-token': csrfToken,
      },
      credentials: 'include',
      body: JSON.stringify({
        filename: file.name,
        mimeType: effectiveMimeType,
        sizeBytes: file.size,
      }),
      signal,
    });

    if (!uploadReqRes.ok) {
      const error = await uploadReqRes.json();
      throw new Error(error.error || 'Failed to create upload request');
    }

    const { fileId, uploadUrl, s3Key } = await uploadReqRes.json();
    updateProgress({ fileId, progress: 20 });

    // Step 2: Upload file data
    updateProgress({ status: 'uploading', progress: 30 });

    // Check if this is a local upload URL or S3 presigned URL
    const isLocalUpload = uploadUrl.startsWith('/api/files/');
    const fullUploadUrl = isLocalUpload ? `${API_BASE}${uploadUrl}` : uploadUrl;

    const fileBuffer = await file.arrayBuffer();

    if (isLocalUpload) {
      // Local development: upload to our API
      const uploadRes = await fetch(fullUploadUrl, {
        method: 'POST',
        headers: {
          'x-csrf-token': csrfToken,
          'Content-Type': effectiveMimeType,
        },
        credentials: 'include',
        body: fileBuffer,
        signal,
      });

      if (!uploadRes.ok) {
        const error = await uploadRes.json();
        throw new Error(error.error || 'Failed to upload file');
      }

      updateProgress({ progress: 90 });

      // For local uploads, the local-upload endpoint already sets status to 'uploaded'
      // Just get the file metadata to return the CDN URL
      const fileRes = await fetch(`${API_BASE}/api/files/${fileId}`, {
        credentials: 'include',
        signal,
      });

      if (!fileRes.ok) {
        throw new Error('Failed to get file metadata');
      }

      const fileData = await fileRes.json();
      updateProgress({ status: 'complete', progress: 100 });

      return {
        fileId,
        cdnUrl: fileData.cdn_url,
      };
    } else {
      // Production: upload directly to S3
      const uploadRes = await fetch(fullUploadUrl, {
        method: 'PUT',
        headers: {
          'Content-Type': effectiveMimeType,
        },
        body: fileBuffer,
        signal,
      });

      if (!uploadRes.ok) {
        throw new Error('Failed to upload to S3');
      }

      updateProgress({ status: 'confirming', progress: 80 });

      // Step 3: Confirm upload
      const confirmRes = await fetch(`${API_BASE}/api/files/${fileId}/confirm`, {
        method: 'POST',
        headers: {
          'x-csrf-token': csrfToken,
        },
        credentials: 'include',
        signal,
      });

      if (!confirmRes.ok) {
        const error = await confirmRes.json();
        throw new Error(error.error || 'Failed to confirm upload');
      }

      const { cdnUrl } = await confirmRes.json();
      updateProgress({ status: 'complete', progress: 100 });

      return { fileId, cdnUrl };
    }
  } catch (error) {
    updateProgress({
      status: 'error',
      error: error instanceof Error ? error.message : 'Upload failed',
    });
    throw error;
  }
}

/**
 * Upload a file from a data URL (e.g., from clipboard paste)
 */
export async function uploadDataUrl(
  dataUrl: string,
  filename: string,
  onProgress?: ProgressCallback
): Promise<UploadResult> {
  // Convert data URL to File
  const res = await fetch(dataUrl);
  const blob = await res.blob();
  const file = new File([blob], filename, { type: blob.type });

  return uploadFile(file, onProgress);
}

/**
 * Blocked file extensions for security (executables and scripts)
 * We allow ANY file type EXCEPT these dangerous extensions.
 * Check by extension, not MIME type (MIME types are unreliable and can be spoofed).
 */
const BLOCKED_EXTENSIONS = new Set([
  // Windows executables
  '.exe', '.bat', '.cmd', '.com', '.msi', '.scr', '.pif',
  // Windows scripts
  '.vbs', '.vbe', '.js', '.jse', '.ws', '.wsf', '.wsc', '.wsh',
  // Windows system files
  '.dll', '.sys', '.drv', '.cpl', '.ocx',
  // Windows shortcuts and config
  '.lnk', '.inf', '.reg', '.msc',
  // macOS executables
  '.app', '.dmg', '.pkg',
  // Linux executables and packages
  '.sh', '.bash', '.deb', '.rpm', '.run',
  // Cross-platform
  '.jar', '.ps1', '.psm1', '.psd1',
]);

/**
 * Map file extensions to MIME types for fallback detection
 * Browsers sometimes return empty MIME type for Office files (especially on macOS)
 */
const EXTENSION_TO_MIME: Record<string, string> = {
  // Images
  '.jpg': 'image/jpeg',
  '.jpeg': 'image/jpeg',
  '.png': 'image/png',
  '.gif': 'image/gif',
  '.webp': 'image/webp',
  '.svg': 'image/svg+xml',
  // Documents
  '.pdf': 'application/pdf',
  '.doc': 'application/msword',
  '.docx': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  '.xls': 'application/vnd.ms-excel',
  '.xlsx': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
  '.ppt': 'application/vnd.ms-powerpoint',
  '.pptx': 'application/vnd.openxmlformats-officedocument.presentationml.presentation',
  // Text
  '.txt': 'text/plain',
  '.csv': 'text/csv',
  '.md': 'text/markdown',
  // Archives
  '.zip': 'application/zip',
};

/**
 * Get MIME type from filename extension as fallback
 */
export function getMimeTypeFromExtension(filename: string): string | null {
  const ext = filename.toLowerCase().slice(filename.lastIndexOf('.'));
  return EXTENSION_TO_MIME[ext] || null;
}

/**
 * Check if a file type is allowed for upload
 * Uses blocklist approach: allow ANY file EXCEPT dangerous executables.
 * Checks by extension (not MIME type) since MIME types can be spoofed.
 */
export function isAllowedFileType(mimeType: string, filename?: string): boolean {
  // If no filename provided, allow (can't check extension)
  if (!filename) {
    return true;
  }

  // Extract extension from filename
  const ext = filename.toLowerCase().slice(filename.lastIndexOf('.'));

  // Block dangerous file types
  if (BLOCKED_EXTENSIONS.has(ext)) {
    return false;
  }

  // Allow everything else
  return true;
}

/**
 * Check if a file is an image
 */
export function isImageFile(mimeType: string): boolean {
  return mimeType.startsWith('image/');
}
